const e=[{id:"finance-0001",location:"finance",arc:"finance-t0-a0",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["reserves","forex","imf"],prompt:'The Governor lays the reserves chart on your desk — a line sliding toward three months of imports. "We have been counting money we do not have as reserves. The real number is worse, and the IMF will see through the trick at the next review."',left:{id:"a",label:"Keep publishing the flattering number.",tooltip:"Confidence is a currency too.",reveal:"The headline reserves look calm; importers and rating agencies quietly stop believing you, and the black-market dollar climbs.",effects:{FI:3,GL:-13,EN:-6}},right:{id:"b",label:"Publish the true, lower figure.",tooltip:"A lie in the books is a run waiting to happen.",reveal:"The honesty stings the markets for a week, then steadies them. The IMF, reassured by candour, eases the next tranche.",effects:{FI:-10,GL:8,MI:-6}}},{id:"finance-0002",location:"finance",arc:"finance-t0-a0",stage:1,speaker:"Central Bank Governor",portrait:"official",tags:["reserves","forex","imf"],prompt:"To defend the taka you have been burning reserves to hold the peg. The Governor says you can either let the currency float and watch prices leap, or keep bleeding dollars to defend a number you cannot hold.",left:{id:"a",label:"Float the taka.",tooltip:"Better a fair price than an empty vault.",reveal:"The taka drops; exporters and remitters cheer while every imported good — fuel, food, medicine — jumps overnight. The streets feel it instantly.",effects:{FI:6,GL:5,EN:-18}},right:{id:"b",label:"Keep defending the peg.",tooltip:"A cliff-edge devaluation would break the poor.",reveal:"You hold the line a while longer at the cost of the vault. The reserves thin toward the danger mark and the market sniffs the weakness.",effects:{FI:-16,EN:5,GL:-6}}},{id:"finance-0003",location:"finance",arc:"finance-t0-a0",stage:2,speaker:"Central Bank Governor",portrait:"official",tags:["reserves","forex","imf"],prompt:"Reserves hit the red line. The IMF will release an emergency tranche — but only if you cut energy subsidies the same week. Your advisors warn that the price shock could put people on the streets within days.",left:{id:"a",label:"Take the tranche, cut the subsidies.",tooltip:"Solvency now, anger managed later.",reveal:"Dollars refill the vault as fuel and power prices spike. The crisis on the balance sheet becomes a crisis in the bazaars.",effects:{FI:10,GL:6,EN:-18,MI:-6}},right:{id:"b",label:"Refuse the conditions, seek bilateral loans.",tooltip:"I will not detonate prices on a foreign schedule.",reveal:"You borrow from friendly capitals instead — costlier, with strings of their own. The subsidy holds; the debt stack grows more dangerous.",effects:{FI:3,GL:-6,EN:5,RE:-6}}},{id:"finance-0004",location:"finance",arc:"finance-t0-a1",stage:0,speaker:"Bank Reform Commissioner",portrait:"official",tags:["banks","default-loans","cronies"],prompt:`The Commissioner names the rot: a handful of business families have looted the banks through ever-rolled 'rescheduled' loans, and several of them fund your campaigns. "Classify the bad loans honestly and the banks look insolvent. Hide them and they rot from inside."`,left:{id:"a",label:"Keep rescheduling the cronies' loans.",tooltip:"These men keep the party funded.",reveal:"The books stay pretty and the donors stay loyal. The hole grows in the dark, and one bank's collapse could pull down the rest.",effects:{FI:5,FA:3,GL:-13,EN:-6}},right:{id:"b",label:"Force honest classification and recovery.",tooltip:"A looted bank is a tax on every saver.",reveal:"You name the defaulters and freeze their rolling. The donors revolt and the books look grim — but depositors, and the IMF, exhale.",effects:{FI:-13,GL:8,MI:-6,FA:-10}}},{id:"finance-0005",location:"finance",arc:"finance-t0-a1",stage:1,speaker:"Bank Reform Commissioner",portrait:"official",tags:["banks","default-loans","cronies"],prompt:"Your honest-classification drive has cornered the country's biggest loan defaulter — who happens to own three TV channels and a slice of your party's purse. He offers a deal: a partial repayment and his media's undying loyalty, if you call off the rest.",left:{id:"a",label:"Take the partial deal and the loyalty.",tooltip:"Half a recovery and a friendly press is no small thing.",reveal:"He repays a fraction and his channels glow for you. Every other defaulter learns the price of getting caught is merely negotiable.",effects:{FI:3,FA:5,GL:-10,MI:3}},right:{id:"b",label:"Pursue full recovery, channels be damned.",tooltip:"The law cannot have a discount for the loud.",reveal:"You break him publicly. His networks turn on you nightly — but the message lands that the era of free money is over.",effects:{FI:6,GL:5,FA:-13,MI:-10}}},{id:"finance-0006",location:"finance",arc:"finance-t0-a2",stage:0,speaker:"Expatriate Welfare Secretary",portrait:"official",tags:["remittances","hundi","diaspora"],prompt:"Migrant workers are sending their money home through the illegal hundi network instead of the banks, because hundi gives a better rate and asks no questions. Billions of dollars bypass the reserves entirely. The Secretary wants a 2.5% cash incentive to lure them back.",left:{id:"a",label:"Pay the incentive on legal remittances.",tooltip:"Buy the dollars back into the system.",reveal:"Formal inflows jump and the reserves breathe — at a real fiscal cost, and with smugglers adapting their margins fast.",effects:{FI:6,EN:3,GL:3}},right:{id:"b",label:"Crack down on hundi operators instead.",tooltip:"Punish the channel, not subsidise the rival.",reveal:"Raids disrupt the networks briefly. The operators reroute through crypto and gold; workers, harassed, trust the banks even less.",effects:{FI:-6,MI:5,GL:-6}}},{id:"finance-0007",location:"finance",arc:"finance-t0-a3",stage:0,speaker:"Garment Buyers' Consortium",portrait:"official",tags:["rmg","exports","wages"],prompt:"The Western buyers' consortium that takes most of your garments delivers an ultimatum dressed as concern: raise the minimum wage and improve safety, or they shift orders to cheaper rivals. Your factory owners say a wage hike will close mills.",left:{id:"a",label:"Mandate the wage rise the buyers want.",tooltip:"Cheap labour is a race we lose anyway.",reveal:"Wages rise; the buyers stay and the workers quiet. Marginal factories shutter, and the owners — your donors — are furious.",effects:{GL:6,EN:6,FI:-13,FA:-6}},right:{id:"b",label:"Protect the owners, keep wages flat.",tooltip:"Mills closed help no worker at all.",reveal:"The owners are grateful and the lines keep running. Some buyers quietly diversify away, and the wage protests build.",effects:{FI:6,FA:5,EN:-16,GL:-10}}},{id:"finance-0008",location:"finance",arc:"finance-t0-a4",stage:0,speaker:"Megaproject Coordinator",portrait:"official",tags:["debt","infrastructure","china"],prompt:"The grand projects — bridges, rail, power plants — are monuments and millstones both. A coordinator warns that the foreign loans behind them balloon next year, and one lender wants port-equity collateral if you cannot pay on time.",left:{id:"a",label:"Offer port equity to roll the debt.",tooltip:"Keep the cranes turning at any cost.",reveal:"The repayment is rescheduled and construction continues. A strategic port is now partly mortgaged to a foreign creditor.",effects:{FI:5,RE:-10,GL:-13,MI:-6}},right:{id:"b",label:"Pause new projects and prioritise repayment.",tooltip:"No more monuments we cannot afford.",reveal:"You freeze the ribbon-cuttings to service the debt. The optics dull and contractors grumble, but the balance sheet stops bleeding.",effects:{FI:6,GL:3,EN:-6,FA:-6}}},{id:"finance-0009",location:"finance",arc:"finance-t0-a5",stage:0,speaker:"Financial Intelligence Chief",portrait:"official",tags:["laundering","capital-flight","elite"],prompt:'The FIU chief shows you the outflows: the same elite that complains about the dollar shortage is quietly wiring fortunes into second homes abroad. "They starve the reserves they then blame you for. I can name them — many are friends."',left:{id:"a",label:"Bury the report to protect the names.",tooltip:"These are the people who hold the regime up.",reveal:"The list disappears and the friends stay close. The reserves keep leaking out the back door you chose not to lock.",effects:{FI:-10,FA:5,GL:-10}},right:{id:"b",label:"Publish it and freeze the worst offenders.",tooltip:"Patriotism that flees with the money is none.",reveal:"You name and freeze. The elite is enraged and the courts will be slow — but capital flight stutters and the public roars approval.",effects:{FI:6,EN:5,GL:5,FA:-13}}},{id:"finance-0010",location:"finance",arc:"finance-t0-a6",stage:0,speaker:"Trade & Prices Adviser",portrait:"people",tags:["inflation","subsidies","food"],prompt:"Rice, oil, and onions have outrun wages and the kitchen is now a political battlefield. The adviser offers two levers: open emergency duty-free imports that hammer the budget, or hold the line and tell people to tighten belts they have already cinched.",left:{id:"a",label:"Flood the market with duty-free imports.",tooltip:"An empty plate topples governments faster than deficits.",reveal:"Prices ease at the bazaar and tempers cool. The deficit widens and local farmers, undercut, send their own anger upward.",effects:{EN:8,FI:-13,RE:-6}},right:{id:"b",label:"Hold firm and protect domestic farmers.",tooltip:"Cheap imports today, dead farms tomorrow.",reveal:"The farmers keep their margins and the budget holds. Urban households seethe as the kitchen stays expensive.",effects:{FI:5,RE:3,EN:-16,FA:-6}}},{id:"finance-0011",location:"finance",arc:"finance-t0-a7",stage:0,speaker:"Sovereign Ratings Analyst",portrait:"ambassador",tags:["rating","markets","confidence"],prompt:"A ratings agency is poised to downgrade you to junk, which would spike borrowing costs across the board. The analyst hints the decision could 'go either way' with the right gestures — fiscal transparency, or a quietly arranged hospitality.",left:{id:"a",label:"Arrange the quiet hospitality.",tooltip:"A friendly rating is cheaper than a downgrade.",reveal:"The downgrade is shelved this cycle. The fix is fragile and faintly corrupt; the next analyst may not be so amenable.",effects:{FI:5,GL:-10,EN:-6}},right:{id:"b",label:"Open the books and take the rating you earn.",tooltip:"I will not bribe my way out of arithmetic.",reveal:"You bare the fiscal accounts honestly. The downgrade may come, but investors who reward candour begin, cautiously, to return.",effects:{FI:-10,GL:6,MI:-3}}},{id:"finance-0012",location:"finance",arc:"finance-t0-a8",stage:0,speaker:"NBR Chairman",portrait:"official",tags:["tax","nbr","informal"],prompt:"Barely 2% of the country files taxes; the chairman wants an aggressive drive to widen the net into the vast informal economy. The shopkeepers and traders who fund half your local committees are already calling.",left:{id:"a",label:"Push the tax-net drive hard.",tooltip:"A state cannot run on 2% of its people.",reveal:"Revenue creeps up and the IMF nods — while market associations declare a shutter-down strike against you.",effects:{FI:10,GL:5,EN:-13,FA:-6}},right:{id:"b",label:"Go gently, spare the traders.",tooltip:"Do not squeeze the people who keep me standing.",reveal:"The committees stay loyal and the books stay thin. The tax-to-GDP ratio remains among the lowest on earth.",effects:{FA:6,FI:-13,GL:-10}}},{id:"finance-0013",location:"finance",arc:"finance-t0-a9",stage:0,speaker:"Budget Adviser",portrait:"official",tags:["black-money","whitening","budget"],prompt:"The adviser proposes the familiar budget clause: let undisclosed 'black money' be whitened by paying a flat low tax, no questions asked. It would pull billions into the formal economy — and reward exactly the people who hid it.",left:{id:"a",label:"Keep the whitening window open.",tooltip:"Better the money home than abroad.",reveal:"Hidden fortunes surface and the deficit eases. Honest taxpayers fume that crime pays a lower rate than they do.",effects:{FI:10,EN:-13,GL:-10}},right:{id:"b",label:"Scrap the whitening scheme.",tooltip:"I will not legislate a discount for thieves.",reveal:"You close the loophole on principle. The flagged billions stay offshore, and the budget must find them elsewhere.",effects:{GL:5,EN:5,FI:-16}}},{id:"finance-0014",location:"finance",arc:"finance-t0-a10",stage:0,speaker:"Stock Exchange Chair",portrait:"official",tags:["dse","market","retail"],prompt:"The share index is in free-fall and small investors are burning effigies outside the exchange. The chair wants you to impose an artificial 'floor price' freezing shares from falling further.",left:{id:"a",label:"Impose the floor price.",tooltip:"Stop the bleeding on the screens.",reveal:"The index steadies on paper; trading dries up as no one will buy a price that cannot fall. Foreign funds flee the frozen market.",effects:{EN:5,FI:-10,GL:-13}},right:{id:"b",label:"Let the market clear and fund investor education.",tooltip:"A propped market is a trap with a delay.",reveal:"The index overshoots down, then finds a real bottom. The pain is sharp and the recovery, when it comes, is trusted.",effects:{GL:5,FI:3,EN:-13}}},{id:"finance-0015",location:"finance",arc:"finance-t0-a10",stage:1,speaker:"Stock Exchange Chair",portrait:"official",tags:["dse","market","retail"],prompt:"With the market cratered, a tycoon offers to 'rescue' it by buying en masse — if you hand his group a state bank and a telecom licence in return.",left:{id:"a",label:"Take the tycoon's rescue.",tooltip:"A white knight asks his price.",reveal:"Shares rally on his buying spree. You have sold public assets to paper over a market panic, and he now owns a piece of the state.",effects:{FI:6,EN:3,GL:-13,FA:3}},right:{id:"b",label:"Refuse and let a real recovery take its time.",tooltip:"I will not ransom the bourse to one man.",reveal:"The market mends slowly without a saviour. The tycoon turns his media against you for the snub.",effects:{GL:5,FI:-10,MI:-6}}},{id:"finance-0016",location:"finance",arc:"finance-t0-a11",stage:0,speaker:"Debt Management Chief",portrait:"official",tags:["eurobond","debt","markets"],prompt:"Reserves are tight and the chief proposes a debut dollar Eurobond — quick foreign cash, but at a punishing coupon that locks in high interest for a decade if the markets smell desperation.",left:{id:"a",label:"Issue the Eurobond now.",tooltip:"Cash today is worth the coupon.",reveal:"Dollars arrive and the reserves breathe. The expensive interest bill compounds quietly for ten years.",effects:{FI:8,GL:3,EN:-6}},right:{id:"b",label:"Wait for calmer markets and cut imports instead.",tooltip:"I will not borrow dear out of panic.",reveal:"You squeeze import demand to hold the line. It bites at home now, but spares the country a decade of costly debt.",effects:{FI:-6,EN:-10,GL:3}}},{id:"finance-0017",location:"finance",arc:"finance-t0-a12",stage:0,speaker:"Agriculture Secretary",portrait:"official",tags:["subsidy","fertiliser","farmers"],prompt:"Global fertiliser prices have tripled. The secretary warns that without a fat subsidy the next harvest fails — but the subsidy alone would blow a hole in the budget the IMF is watching.",left:{id:"a",label:"Fund the full fertiliser subsidy.",tooltip:"A failed harvest is a famine and a fall.",reveal:"The fields stay green and the farmers bless you. The deficit balloons and the IMF frowns at the next review.",effects:{EN:8,RE:3,FI:-16}},right:{id:"b",label:"Trim the subsidy to satisfy the lenders.",tooltip:"The books must balance somewhere.",reveal:"You please the creditors and thin the subsidy. Input costs hit the villages, and rural anger ferments.",effects:{FI:6,GL:3,EN:-16,FA:-6}}},{id:"finance-0018",location:"finance",arc:"finance-t0-a13",stage:0,speaker:"Pension Authority Head",portrait:"official",tags:["pension","welfare","funding"],prompt:"Your flagship universal pension scheme is wildly popular — and quietly unfunded past the first few years. The head asks whether to keep enrolling millions on a promise the treasury cannot yet keep.",left:{id:"a",label:"Keep enrolling — worry about funding later.",tooltip:"The promise wins this decade's votes.",reveal:"Millions sign up to applause. You have built a magnificent liability your successors will curse.",effects:{EN:8,FA:3,FI:-13}},right:{id:"b",label:"Slow enrolment until it is actuarially sound.",tooltip:"A pension that bounces is a betrayal.",reveal:"You cap the scheme to make it real. The rollout looks timid, but the cheque will clear when it comes due.",effects:{FI:5,GL:3,EN:-13}}},{id:"finance-0019",location:"finance",arc:"finance-t0-a14",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["banks","merger","weak-banks"],prompt:"Five insolvent banks are walking corpses, kept alive by liquidity from the central bank. The governor wants to force-merge them into stronger ones — wiping out politically-connected directors.",left:{id:"a",label:"Force the mergers through.",tooltip:"Let the dead banks be buried.",reveal:"The rot is consolidated and capped. The ousted directors — several are donors — swear vengeance.",effects:{FI:8,GL:5,FA:-13}},right:{id:"b",label:"Keep them on life support a while longer.",tooltip:"Not before the election, not these names.",reveal:"The zombies shuffle on, draining liquidity. The reckoning is postponed and made larger.",effects:{FA:5,FI:-13,GL:-6}}},{id:"finance-0020",location:"finance",arc:"finance-t0-a15",stage:0,speaker:"Mobile Finance Regulator",portrait:"official",tags:["mfs","bkash","fintech"],prompt:"Mobile money moves the wages of the whole working class now, and the dominant operator wants to raise cash-out fees. The poorest pay those fees; the operator employs thousands and lobbies hard.",left:{id:"a",label:"Cap the cash-out fees.",tooltip:"The garment girl should keep her wage.",reveal:"The fee cap eases millions of small lives. The operator threatens to cut rural agents in protest.",effects:{EN:8,FA:3,FI:-10}},right:{id:"b",label:"Let the operator set its fees.",tooltip:"A profitable rail keeps expanding.",reveal:"The network grows and invests; the daily skim off the poor grows with it.",effects:{FI:5,GL:3,EN:-13}}},{id:"finance-0021",location:"finance",arc:"finance-t0-a16",stage:0,speaker:"Customs Intelligence Chief",portrait:"shadow",tags:["misinvoicing","laundering","trade"],prompt:"The chief lays out how billions leave the country through fake import invoices — over-paying foreign 'suppliers' who are really the importers' own offshore shells. The biggest offenders dine with your ministers.",left:{id:"a",label:"Order a real crackdown on misinvoicing.",tooltip:"Plug the hole in the hull.",reveal:"Customs tightens and capital flight slows. Powerful importers, exposed, fund your rivals overnight.",effects:{FI:8,GL:5,FA:-13}},right:{id:"b",label:"Let the audit quietly stall.",tooltip:"Some hulls are best left unexamined.",reveal:"The trade continues and the friends stay close. The reserves keep leaking out the side the cameras never see.",effects:{FA:5,FI:-10,GL:-10}}},{id:"finance-0022",location:"finance",arc:"finance-t0-a17",stage:0,speaker:"Fuel Pricing Board",portrait:"official",tags:["fuel","bpc","subsidy"],prompt:"The state oil company bleeds crores a day selling diesel below cost. The board wants an automatic price-adjustment formula — fuel prices that rise with the world market, untouched by your hand.",left:{id:"a",label:"Adopt the automatic formula.",tooltip:"Take the politics out of the pump.",reveal:"The oil company stops bleeding; fuel jumps with every global tick, and transport strikes follow each rise.",effects:{FI:8,GL:5,EN:-16}},right:{id:"b",label:"Keep prices fixed and eat the loss.",tooltip:"Cheap diesel keeps the country moving.",reveal:"Buses and irrigation pumps run cheap. The subsidy drains the budget and distorts every market it touches.",effects:{EN:6,FI:-16,RE:-6}}},{id:"finance-0023",location:"finance",arc:"finance-t0-a18",stage:0,speaker:"Treasury Economist",portrait:"official",tags:["currency","dual-rate","taka"],prompt:"A grey gap has opened between the official taka rate and the street rate, breeding arbitrage and a black market. The economist says you must unify the rates — a one-time devaluation that will sting everyone at once.",left:{id:"a",label:"Unify the rate, take the devaluation.",tooltip:"One honest price beats two dishonest ones.",reveal:"The black market shrinks and exporters cheer; every imported good leaps in price the same morning.",effects:{FI:6,GL:5,EN:-16}},right:{id:"b",label:"Hold the official rate and ration dollars.",tooltip:"A sudden devaluation would break the poor.",reveal:"You keep the headline rate and dole out scarce dollars by favour — a system that breeds its own corruption.",effects:{FI:-10,EN:3,GL:-10}}},{id:"finance-0024",location:"finance",arc:"finance-t0-a19",stage:0,speaker:"Foreign Loans Director",portrait:"official",tags:["china","debt","geopolitics"],prompt:"Beijing offers soft loans for a glittering ring road, far cheaper than the markets. The opposition is already chanting 'debt trap', and the West is watching whose money paves your capital.",left:{id:"a",label:"Take the Chinese loan.",tooltip:"Cheap concrete is cheap concrete.",reveal:"The ring road rises on easy terms. The 'debt-trap' headlines and Western coolness are the price of the bargain.",effects:{FI:8,RE:5,GL:-13}},right:{id:"b",label:"Decline and tender it to the markets.",tooltip:"I will not mortgage the capital to one capital.",reveal:"You pay more for diversified financing and Western goodwill. The project crawls; the books strain.",effects:{GL:5,FI:-13,RE:-6}}},{id:"finance-0025",location:"finance",arc:"finance-t0-a20",stage:0,speaker:"Pay Commission Head",portrait:"official",tags:["wages","civil-service","budget"],prompt:"Two million civil servants want a new pay scale, and they staff every office you rely on. A generous raise wins a loyal bureaucracy; it also locks in a wage bill that eats the development budget.",left:{id:"a",label:"Grant the generous pay rise.",tooltip:"A happy bureaucracy is a working one.",reveal:"The files move and the clerks smile. The recurring wage bill devours the money meant for bridges and clinics.",effects:{MI:5,FA:3,FI:-16,EN:-6}},right:{id:"b",label:"Offer a modest, affordable raise.",tooltip:"The state cannot be a charity for itself.",reveal:"You protect the development budget. A sullen civil service slow-walks everything for a season.",effects:{FI:6,EN:3,MI:-10}}},{id:"finance-0026",location:"finance",arc:"finance-t0-a21",stage:0,speaker:"Export Promotion Chief",portrait:"official",tags:["rmg","incentive","exports"],prompt:"Exporters get a cash incentive on every dollar of garments shipped — a subsidy the IMF calls a distortion and wants gone. The factory owners say cutting it now hands the orders to Vietnam.",left:{id:"a",label:"Keep the export cash incentive.",tooltip:"Do not gift our orders to Hanoi.",reveal:"The looms keep their edge and the dollars keep coming. The IMF marks another unmet condition against you.",effects:{FI:5,GL:-10,EN:3,FA:3}},right:{id:"b",label:"Phase out the incentive as promised.",tooltip:"A crutch carried too long becomes a cast.",reveal:"You please the lenders and prod exporters to compete on merit. Margins thin; some marginal factories fold.",effects:{GL:6,FI:-10,EN:-10}}},{id:"finance-0027",location:"finance",arc:"finance-t0-a22",stage:0,speaker:"Deficit Financing Officer",portrait:"official",tags:["printing","inflation","central-bank"],prompt:"Short of cash before the budget, an officer suggests the oldest trick: have the central bank simply print money to cover the gap. It is invisible today and inflationary tomorrow.",left:{id:"a",label:"Print to cover the deficit.",tooltip:"No one feels it this quarter.",reveal:"The gap is filled with fresh notes. Inflation stirs in the months ahead, a tax no one voted for.",effects:{FI:6,EN:-16,GL:-6}},right:{id:"b",label:"Refuse and borrow honestly instead.",tooltip:"I will not pay tomorrow's prices for today's gap.",reveal:"You raise the money through bonds, dearer but cleaner. The deficit is honest and the taka steadier.",effects:{GL:5,FI:-6,EN:3}}},{id:"finance-0028",location:"finance",arc:"finance-t0-a23",stage:0,speaker:"e-Commerce Victims' Delegation",portrait:"people",tags:["scam","ecommerce","refunds"],prompt:"A glittering online marketplace took advance payments for goods it never had and collapsed, taking the savings of a hundred thousand families. They camp outside your office demanding their money back.",left:{id:"a",label:"Order a state-backed refund fund.",tooltip:"The state failed to police it; the state pays.",reveal:"Families recover a fraction of their savings. The treasury absorbs a scam it did not commit, and others ask why they were not bailed out too.",effects:{EN:8,FA:3,FI:-16}},right:{id:"b",label:"Pursue the founders, but no public refund.",tooltip:"I will jail the thieves, not reward the gamble.",reveal:"You freeze assets and prosecute. The recovered crumbs disappoint the crowd, but the precedent of no-bailout holds.",effects:{GL:3,FI:3,EN:-13}}},{id:"finance-0029",location:"finance",arc:"finance-t0-a24",stage:0,speaker:"Revenue Reform Adviser",portrait:"official",tags:["wealth-tax","surcharge","elite"],prompt:"The adviser proposes a stiff surcharge on the largest fortunes — popular with the street, loathed by the class that funds campaigns and owns the newspapers.",left:{id:"a",label:"Impose the wealth surcharge.",tooltip:"Those with the most can give the most.",reveal:"Public revenue and approval both rise. The moneyed class opens its war chest against you and its front pages turn cold.",effects:{FI:8,EN:6,FA:-13}},right:{id:"b",label:"Shelve it to keep the donors close.",tooltip:"I cannot fight the people who fund me.",reveal:"The fortunes stay untaxed and the donors stay sweet. The street notes whose interests the budget serves.",effects:{FA:5,FI:-10,EN:-10}}},{id:"finance-0030",location:"finance",arc:"finance-t0-a25",stage:0,speaker:"Import Policy Officer",portrait:"official",tags:["lc","luxury","reserves"],prompt:"To defend the reserves, an officer wants to choke letters of credit for 'luxury' imports — cars, cosmetics, fruit. It saves dollars and irritates exactly the affluent who notice empty shelves.",left:{id:"a",label:"Restrict the luxury LCs.",tooltip:"Dollars are for medicine, not Mercedes.",reveal:"Reserves stop bleeding on baubles. The affluent grumble about scarcity, and some smuggling reroutes the trade.",effects:{FI:6,GL:3,EN:-6,FA:-6}},right:{id:"b",label:"Keep imports open to avoid the optics of scarcity.",tooltip:"Empty shelves photograph badly.",reveal:"The shops stay stocked and the rich content. The reserves keep draining on things the country need not buy.",effects:{FA:3,FI:-13,GL:-6}}},{id:"finance-0031",location:"finance",arc:"finance-t0-a26",stage:0,speaker:"Loan Classification Board",portrait:"official",tags:["rescheduling","defaulters","banks"],prompt:"The board can relax the loan-rescheduling rules so habitual defaulters look 'regular' again with a token down-payment. It flatters the banks' books and rewards the very borrowers who never pay.",left:{id:"a",label:"Relax the rules, flatter the books.",tooltip:"A pretty balance sheet calms the market.",reveal:"Default ratios drop on paper overnight. The rot deepens in the dark, and the honest borrower wonders why he bothers.",effects:{FI:5,GL:-10,FA:3}},right:{id:"b",label:"Tighten classification to the real number.",tooltip:"Call a bad loan a bad loan.",reveal:"The true scale of default is finally visible. It looks ugly and frightens markets briefly — but the cleanup can begin.",effects:{GL:5,FI:-10,EN:3,FA:-6}}},{id:"finance-0032",location:"finance",arc:"finance-t0-a27",stage:0,speaker:"Privatisation Commissioner",portrait:"official",tags:["privatisation","jute","state-firms"],prompt:"The state jute and textile mills lose money every single year, yet they employ tens of thousands and carry the romance of the founding economy. The commissioner wants them sold or shut.",left:{id:"a",label:"Shut and sell the loss-making mills.",tooltip:"Nostalgia is not a business plan.",reveal:"The hemorrhage stops and buyers move in. Thousands of mill workers and their unions march on your gate.",effects:{FI:8,GL:3,EN:-16,MI:-6}},right:{id:"b",label:"Keep the mills open with state money.",tooltip:"These looms built the nation.",reveal:"The jobs and the heritage survive on subsidy. The losses recur, year after year, a line item that never dies.",effects:{EN:5,FA:3,FI:-16}}},{id:"finance-0033",location:"finance",arc:"finance-t0-a28",stage:0,speaker:"National Savings Director",portrait:"official",tags:["sanchayapatra","savings","rates"],prompt:"Government savings certificates pay pensioners and widows a generous fixed return — and cost the treasury dearly as everyone piles in. The director wants to cut the rate.",left:{id:"a",label:"Cut the savings-certificate rate.",tooltip:"The treasury cannot subsidise every saver.",reveal:"The interest bill eases. Pensioners and widows who counted on that return feel the floor drop, and say so loudly.",effects:{FI:8,GL:3,EN:-13}},right:{id:"b",label:"Protect the small savers' rate.",tooltip:"The widow's certificate is sacred.",reveal:"You shield the small savers and eat the cost. The high-rollers exploit the same window, and the bill grows.",effects:{EN:6,FA:3,FI:-16}}},{id:"finance-0034",location:"finance",arc:"finance-t0-a29",stage:0,speaker:"Special Economic Zone Director",portrait:"official",tags:["sez","tax-holiday","investment"],prompt:"A foreign consortium will build a vast economic zone and bring jobs — if you grant a fifteen-year tax holiday so generous the project pays almost nothing into the treasury for a generation.",left:{id:"a",label:"Grant the long tax holiday.",tooltip:"Jobs now, taxes eventually.",reveal:"The cranes arrive and employment rises. The treasury forgoes a fortune for fifteen years to win the ribbon-cutting.",effects:{EN:6,FI:-10,GL:5,RE:3}},right:{id:"b",label:"Negotiate a shorter, fairer holiday.",tooltip:"I will host investment, not subsidise it forever.",reveal:"You drive a harder bargain. The consortium hesitates and shrinks the project — but the state keeps a slice of the upside.",effects:{FI:5,GL:-6,EN:-6}}},{id:"finance-0035",location:"finance",arc:"finance-t0-a30",stage:0,speaker:"Anti-Tobacco Coalition",portrait:"people",tags:["tobacco","tax","health"],prompt:"Doctors want tobacco taxed steeply to curb a public-health disaster; the tobacco giants are among your largest taxpayers and employ a vast leaf-growing belt that votes.",left:{id:"a",label:"Tax tobacco hard.",tooltip:"A cigarette tax is a life saved and a taka earned.",reveal:"Revenue and public health both rise. The tobacco lobby and its farming districts turn sharply against you.",effects:{FI:6,EN:6,FA:-10}},right:{id:"b",label:"Keep tobacco taxes low.",tooltip:"Do not gut a top taxpayer and a voting belt.",reveal:"The companies stay sweet and the leaf districts loyal. The wards fill with the slow harvest of that bargain.",effects:{FI:3,FA:3,EN:-16}}},{id:"finance-0036",location:"finance",arc:"finance-t0-a31",stage:0,speaker:"Land Registration Reformer",portrait:"official",tags:["real-estate","black-money","registration"],prompt:"Property is bought at a fraction of its true value on paper, hiding black money and starving the treasury of registration tax. Digitising and revaluing it would expose a lot of powerful people.",left:{id:"a",label:"Digitise and revalue property.",tooltip:"Drag the land market into the light.",reveal:"Registration revenue surges and a laundering channel narrows. Builders and land barons — and their political patrons — howl.",effects:{FI:8,EN:3,GL:3,FA:-13}},right:{id:"b",label:"Leave the registers as they are.",tooltip:"Some ledgers are best left yellowed.",reveal:"The cosy undervaluation continues. Black money keeps flowing into bricks while the treasury watches it pass.",effects:{FA:5,FI:-13,GL:-6}}},{id:"finance-0037",location:"finance",arc:"finance-t0-a32",stage:0,speaker:"Hajj Management Director",portrait:"cleric",tags:["hajj","pilgrims","cost"],prompt:"Airfares and Saudi fees have pushed the pilgrimage beyond ordinary families. The director asks whether to subsidise Hajj from the budget — pious and popular, or a costly precedent the secularists will attack.",left:{id:"a",label:"Subsidise the pilgrimage.",tooltip:"Let the faithful afford the journey.",reveal:"Grateful pilgrims bless your name from Mecca. The treasury and the secular press both wince at the bill.",effects:{FA:5,EN:5,FI:-13,GL:-6}},right:{id:"b",label:"Keep Hajj unsubsidised but cut the agents' fees.",tooltip:"Faith should not be a fiscal line.",reveal:"You squeeze the middlemen instead of the budget. The devout are mildly disappointed; the books stay clean.",effects:{FI:5,GL:3,EN:-6,FA:-6}}},{id:"finance-0038",location:"finance",arc:"finance-t0-a33",stage:0,speaker:"Climate Fund Auditor",portrait:"official",tags:["climate","fund","graft"],prompt:"The donor-funded climate adaptation pot — embankments, shelters, resilient seed — has leaked badly into the pockets of local officials. A hard audit would recover money and embarrass your own party men.",left:{id:"a",label:"Order the hard audit and claw the money back.",tooltip:"Stolen flood money is blood money.",reveal:"Recovered crores return to the embankments. The implicated party officials become loud, wounded enemies.",effects:{EN:6,GL:6,FI:3,FA:-13}},right:{id:"b",label:"Bury the audit to protect the party.",tooltip:"Do not hand the donors a scandal.",reveal:"The leak stays hidden and the party intact. The embankments stay thin, and the next flood collects the difference.",effects:{FA:5,EN:-16,GL:-10}}},{id:"finance-0039",location:"finance",arc:"finance-t0-a34",stage:0,speaker:"Sovereign Fund Proponent",portrait:"official",tags:["reserves","sovereign-fund","investment"],prompt:"An adviser wants to carve a sovereign wealth fund out of the foreign reserves to invest in big domestic projects. Bold — but every dollar parked in concrete is a dollar not defending the taka in a crisis.",left:{id:"a",label:"Launch the sovereign fund from reserves.",tooltip:"Idle reserves should build the country.",reveal:"Grand projects get cheap money and momentum. The reserve buffer thins, and a future shock will find less cushion.",effects:{RE:5,EN:5,FI:-10,GL:-6}},right:{id:"b",label:"Keep the reserves as a war chest.",tooltip:"Reserves are the wall against the storm.",reveal:"You guard the buffer and pass on the projects. Critics call it timid; the next currency scare proves it wise.",effects:{FI:6,GL:3,EN:-6}}},{id:"finance-0040",location:"finance",arc:"finance-t0-a35",stage:0,speaker:"VAT Online Director",portrait:"official",tags:["vat","digitisation","compliance"],prompt:"Electronic VAT machines would capture billions that retailers currently pocket — but every shopkeeper sees a spy in the till, and they are a million-strong voting bloc.",left:{id:"a",label:"Mandate the electronic VAT machines.",tooltip:"An honest till funds an honest state.",reveal:"Consumption-tax revenue climbs steadily. A million shopkeepers grumble about the machine watching every sale.",effects:{FI:8,GL:3,EN:-6,FA:-6}},right:{id:"b",label:"Keep VAT collection manual and negotiable.",tooltip:"Do not put a meter on every shop counter.",reveal:"The shopkeepers stay content and the leakage continues. The treasury collects a fraction of what it is owed.",effects:{FA:5,FI:-13,GL:-6}}},{id:"finance-0041",location:"finance",arc:"finance-t0-a36",stage:0,speaker:"Garment Buyers' Auditor",portrait:"ambassador",tags:["rmg","compliance","wages"],prompt:"After a competitor's scandal, Western buyers demand audited proof that your factories pay the legal wage and the promised bonuses. Real compliance costs the owners; faking it risks the whole export market.",left:{id:"a",label:"Enforce real wage compliance.",tooltip:"The market is worth more than the margin.",reveal:"Buyers are reassured and orders hold; the workers are paid in full. Factory owners — your donors — bristle at the cost.",effects:{GL:6,EN:6,FI:-10,FA:-6}},right:{id:"b",label:"Help the owners present a compliant face.",tooltip:"Protect the owners who keep the lines running.",reveal:"The audit is smoothed over and margins protected. One leaked payslip could bring the whole edifice down.",effects:{FI:5,FA:3,GL:-13,EN:-10}}},{id:"finance-0042",location:"finance",arc:"finance-t0-a37",stage:0,speaker:"Revenue Board Chairman",portrait:"fixer",tags:["black-money","tax","whitening"],prompt:"A budget clause would let undisclosed 'black money' be legalised by paying a flat low tax, no questions asked — luring billions back into the formal economy and the property market. The chairman calls it pragmatic; honest taxpayers call it a reward for the crooked.",left:{id:"a",label:"Offer the no-questions whitening scheme.",tooltip:"Better the black money working here than hiding abroad.",reveal:"The clause passes and laundered crores flood into property and banks. The reserves and the books improve, and every honest taxpayer learns that cheating, in the end, is rewarded.",effects:{FI:8,FA:2,EN:-13,GL:-10}},right:{id:"b",label:"Refuse to legalise undisclosed wealth.",tooltip:"A state that pardons theft for a fee invites more theft.",reveal:"You kill the whitening clause. The hidden money stays hidden or flees abroad, and the budget is thinner for it, but the tax system keeps a shred of fairness and credibility.",effects:{GL:5,EN:5,FI:-13}}},{id:"finance-0043",location:"finance",arc:"finance-t0-a38",stage:0,speaker:"Securities Regulator",portrait:"official",tags:["stock-market","crash","retail"],prompt:"The bourse has crashed after a manipulated bubble, wiping out hundreds of thousands of small investors lured in by insiders who cashed out at the top. The regulator can mount a costly retail bailout and prosecute the manipulators, or let the market clear and the losers learn.",left:{id:"a",label:"Bail out small investors, prosecute manipulators.",tooltip:"A market that eats its small fish breeds no trust.",reveal:"You cushion the retail losses and go after the big manipulators. The bailout is costly and the syndicates fight back, but the small investor sees the state will not abandon them to the wolves.",effects:{EN:6,GL:3,FI:-13,FA:-6}},right:{id:"b",label:"Let the market clear on its own.",tooltip:"A gambler who loses cannot bill the state.",reveal:"You let the crash run its course. The treasury is spared, the manipulators keep their gains, and a generation of small savers swears off the market that fleeced them.",effects:{FI:3,EN:-13,GL:-3}}},{id:"finance-0044",location:"finance",arc:"finance-t0-a39",stage:0,speaker:"Privatisation Commission Chief",portrait:"official",tags:["soe","privatisation","jobs"],prompt:"Dozens of state enterprises — mills, factories, a national airline — bleed subsidy every year, kept alive for the jobs and the patronage. The chief can privatise or shut the worst, stemming the losses, or keep them on life support to protect the workers and the votes.",left:{id:"a",label:"Privatise or shut the loss-makers.",tooltip:"A factory that only makes losses makes nothing.",reveal:"You sell or close the bleeding enterprises and stem the subsidy. The freed budget is real, but tens of thousands of workers lose their jobs and turn their fury on you.",effects:{FI:6,GL:3,EN:-13}},right:{id:"b",label:"Keep the enterprises on life support.",tooltip:"A wage lost is a household sunk.",reveal:"You keep the loss-makers running for the workers and the patronage. The jobs and the votes are safe, and the subsidy keeps draining money that schools and clinics will never see.",effects:{EN:5,FA:3,FI:-13}}},{id:"finance-0045",location:"finance",arc:"finance-t0-a40",stage:0,speaker:"Pension Authority Director",portrait:"people",tags:["pension","welfare","future"],prompt:"A national pension scheme would give the vast informal workforce security in old age — a transformative legacy — but it demands either contributions the poor can barely make or a vast permanent subsidy the budget can barely bear. The director needs your design.",left:{id:"a",label:"Launch a generously subsidised pension.",tooltip:"An old age without dignity is a society's shame.",reveal:"You build a pension reaching even the poorest with heavy state top-ups. The fiscal burden is enormous and permanent, but a generation of the elderly is lifted out of destitution.",effects:{EN:10,GL:3,FI:-16}},right:{id:"b",label:"Build a lean contributory pension.",tooltip:"A promise I cannot fund is a betrayal deferred.",reveal:"You launch a modest, mainly contribution-based scheme. It is fiscally sound but reaches the poorest thinly, and the informal workers who most need it can least afford to join.",effects:{FI:3,EN:3,GL:2}}},{id:"finance-0046",location:"finance",arc:"finance-t0-a41",stage:0,speaker:"IMF Programme Negotiator",portrait:"ambassador",tags:["imf","subsidy","austerity"],prompt:"The next IMF tranche hinges on slashing fuel and electricity subsidies — a move that steadies the budget and detonates the cost of living for everyone. The negotiator says the money is vital; the street says the price rises are unbearable.",left:{id:"a",label:"Cut the subsidies for the IMF tranche.",tooltip:"The fund's money keeps the lights on at all.",reveal:"You slash the subsidies and unlock the tranche. The reserves and the lenders are reassured, and the price of transport, food, and power detonates in every household.",effects:{FI:6,GL:5,EN:-18}},right:{id:"b",label:"Protect the subsidies, risk the tranche.",tooltip:"I will not buy a loan with my people's hunger.",reveal:"You shield the subsidies and the IMF talks stall. The street is spared the shock, but the reserves keep bleeding and the lifeline you turned down may not be offered twice.",effects:{EN:6,FI:-13,GL:-6}}},{id:"finance-0047",location:"finance",arc:"finance-t0-a42",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["currency","float","devaluation"],prompt:"The taka is propped up at an artificial rate the reserves can no longer defend, feeding a black market. The governor urges letting it float to its real value — ending the drain, but spiking import prices and inflation overnight — or burning more reserves to hold the peg.",left:{id:"a",label:"Let the taka float to its real value.",tooltip:"A currency defended past its worth bankrupts the defender.",reveal:"You float the taka and the black-market premium vanishes. Import prices and inflation jump painfully, but the ruinous reserve drain stops and the market finds honest footing.",effects:{FI:5,GL:3,EN:-13}},right:{id:"b",label:"Burn reserves to hold the peg.",tooltip:"A falling taka is a falling government.",reveal:"You keep defending the rate. The official price holds and the public is spared the shock for now, but the reserves drain toward empty and the black market thrives in the gap.",effects:{EN:3,FI:-13,GL:-3}}},{id:"finance-0048",location:"finance",arc:"finance-t0-a43",stage:0,speaker:"Banking Division Secretary",portrait:"official",tags:["banks","merger","npl"],prompt:"Several banks are insolvent, hollowed out by insider looting and bad loans, and one is days from collapse. The secretary can force mergers into healthier banks — protecting depositors but rewarding the looters — or let a bank fail and shock the system into discipline.",left:{id:"a",label:"Force mergers to protect depositors.",tooltip:"A bank run is a fire that spreads.",reveal:"You merge the zombie banks into stronger ones and depositors are saved. The looters who gutted them walk away clean, and the healthy banks inherit a mountain of toxic debt.",effects:{FI:3,EN:2,GL:-3,FA:-3}},right:{id:"b",label:"Let an insolvent bank fail.",tooltip:"A bank that is never allowed to die never learns to live.",reveal:"You let one rotten bank collapse. Depositors panic and the system shudders, but for once the looters lose their bank, and every other board suddenly takes risk seriously.",effects:{GL:3,FI:-10,EN:-6}}},{id:"finance-0049",location:"finance",arc:"finance-t0-a44",stage:0,speaker:"Banking Division Secretary",portrait:"fixer",tags:["loans","defaulters","favours"],prompt:"The biggest loan defaulters — industrialists with party ties — want their bad loans rescheduled on absurdly soft terms again, kicking the reckoning down the road. The secretary says it props up the banks' books on paper; it also lets the willful defaulters off the hook forever.",left:{id:"a",label:"Grant the soft rescheduling again.",tooltip:"A defaulter's empire employs thousands; do not topple it.",reveal:"You let the big defaulters reschedule on featherbed terms. The banks' books look healthier on paper, the connected tycoons stay afloat, and the rot in the banking system deepens out of sight.",effects:{FI:3,FA:3,EN:-10,GL:-10}},right:{id:"b",label:"Force repayment or seizure.",tooltip:"A willful defaulter is a thief with a balance sheet.",reveal:"You refuse the rescheduling and move to recover or seize. The tycoons rage and call in their political chips, but billions in dead loans start, painfully, to come back.",effects:{GL:5,FI:3,EN:3,FA:-10}}},{id:"finance-0050",location:"finance",arc:"finance-t0-a45",stage:0,speaker:"Debt Management Director",portrait:"ambassador",tags:["eurobond","debt","markets"],prompt:"You can raise a large sum fast by issuing a sovereign bond on the international markets — no IMF conditions, no neighbourly strings — but at a steep interest rate that mortgages future budgets, and exposes you to the mercy of global bond traders.",left:{id:"a",label:"Issue the international bond.",tooltip:"Market money comes with no master attached.",reveal:"The bond raises the cash quickly and string-free. The high coupon settles onto future budgets, and your fortunes are now hostage to the moods of distant bond markets.",effects:{FI:5,GL:2,RE:2}},right:{id:"b",label:"Avoid the costly market borrowing.",tooltip:"A bond at usurer's rates is a trap with a ribbon.",reveal:"You skip the expensive bond and live within tighter means. The development plans shrink and the cash crunch bites, but you do not mortgage the next decade to the markets.",effects:{GL:2,FI:-6,EN:-3}}},{id:"finance-0051",location:"finance",arc:"finance-t0-a46",stage:0,speaker:"Trading Corporation Chief",portrait:"shadow",tags:["inflation","syndicate","food"],prompt:"A cartel of wholesalers is hoarding rice, onions, and oil to spike prices at will, squeezing every household — and several cartel bosses are party financiers. The chief can break the syndicate with raids and state imports, or protect the donors and let prices ride.",left:{id:"a",label:"Break the price syndicate.",tooltip:"A cartel that taxes every plate must be smashed.",reveal:"You raid the hoarders and flood the market with state imports. Prices ease and the public exhales, but the cartel bosses — your financiers — turn on you with their wallets shut.",effects:{EN:8,FI:-6,FA:-10}},right:{id:"b",label:"Protect the donors, let prices ride.",tooltip:"The men who fund the party are not lightly raided.",reveal:"You spare the syndicate and the hoarding continues. The financiers stay loyal and generous, and the cost of a meal climbs out of reach for the families who can least bear it.",effects:{FI:3,FA:5,EN:-16}}},{id:"finance-0052",location:"finance",arc:"finance-t0-a47",stage:0,speaker:"Customs Commissioner",portrait:"fixer",tags:["customs","ports","corruption"],prompt:"The ports leak billions in duty through under-invoicing and bribed clearance, with the customs houses among the most lucrative postings in the state. The commissioner can automate and audit the whole system, breaking the rackets, or leave the golden geese to lay.",left:{id:"a",label:"Automate and audit customs.",tooltip:"A bribed customs house robs the whole nation.",reveal:"You digitise clearance and audit the postings hard. Duty revenue jumps and the rackets wither, and the officers who paid fortunes for the lucrative postings turn bitterly against you.",effects:{FI:6,GL:3,EN:2,FA:-6}},right:{id:"b",label:"Leave the customs rackets running.",tooltip:"The men in the customs houses have powerful patrons.",reveal:"You leave the ports' shadow economy intact. The patronage flows smoothly and the postings stay golden, and the treasury keeps collecting a fraction of the duty it is owed.",effects:{FI:-6,FA:3,EN:-6,GL:-3}}},{id:"finance-0053",location:"finance",arc:"finance-t0-a48",stage:0,speaker:"Revenue Board Chairman",portrait:"official",tags:["tax","elite","evasion"],prompt:"The country's tax-to-GDP ratio is among the world's lowest because the wealthy simply do not pay — and the board has long squeezed the salaried middle instead. The chairman can finally go after the rich evaders, who include donors and dynasts, or keep milking the easy salaried base.",left:{id:"a",label:"Go after the wealthy evaders.",tooltip:"A state funded by clerks while tycoons skate is doomed.",reveal:"You target the rich evaders, audits reaching into donor and dynastic ledgers. The revenue base broadens and the public cheers, but the powerful you have dunned plot their revenge.",effects:{FI:6,EN:6,GL:3,FA:-13}},right:{id:"b",label:"Keep squeezing the salaried base.",tooltip:"The easy taxpayer is the one who cannot run.",reveal:"You leave the rich alone and lean harder on the salaried. The revenue is reliable and the donors content, and the shrinking middle class learns exactly whose shoulders the state rests on.",effects:{FI:3,FA:3,EN:-13}}},{id:"finance-0054",location:"finance",arc:"finance-t0-a49",stage:0,speaker:"Digital Finance Adviser",portrait:"official",tags:["mobile-money","remittances","inclusion"],prompt:"Mobile money has banked the unbanked and could pull remittances out of the illegal hundi channels into the formal economy — if you incentivise it. The banks lobby against it, fearing disintermediation, and the hundi networks have their own quiet patrons.",left:{id:"a",label:"Boost mobile money and formal remittances.",tooltip:"A phone in every hand is a bank in every village.",reveal:"You push incentives for mobile remittances and the formal channels swell. The banks and the hundi networks both lose ground and grumble, but billions enter the legal economy and the unbanked gain access.",effects:{FI:6,EN:5,GL:2,FA:-3}},right:{id:"b",label:"Protect the banks, let hundi persist.",tooltip:"The banks are the system; do not undercut them.",reveal:"You shield the banks and leave the mobile push half-hearted. The hundi networks keep their grip on remittances, the reserves miss the inflows, and the village stays unbanked.",effects:{FA:3,FI:-10,EN:-3}}},{id:"finance-0055",location:"finance",arc:"finance-t0-a50",stage:0,speaker:"Pay Commission Chair",portrait:"official",tags:["salaries","bureaucracy","budget"],prompt:"A new pay commission recommends a huge salary hike for the civil service — buying the bureaucracy's loyalty and curbing petty corruption, but blowing a vast hole in the recurrent budget for years. The chair awaits your decision.",left:{id:"a",label:"Grant the full pay rise.",tooltip:"A well-paid official is a loyal, honest one.",reveal:"You award the generous hike and the bureaucracy is delighted and bound to you. Petty bribery eases, but the wage bill swells permanently, crowding out the development budget for years.",effects:{MI:2,FA:3,FI:-13,EN:-3}},right:{id:"b",label:"Grant a modest, affordable rise.",tooltip:"A salary I cannot sustain is a strike deferred.",reveal:"You give a restrained increase the budget can bear. The civil servants grumble at the modesty and some petty corruption persists, but the fiscal hole stays survivable.",effects:{FI:3,EN:2,FA:-3}}},{id:"finance-0056",location:"finance",arc:"finance-t0-a51",stage:0,speaker:"Financial Intelligence Chief",portrait:"shadow",tags:["laundering","over-invoicing","capital-flight"],prompt:"Billions flee the country each year through over- and under-invoiced trade, spiriting wealth to second homes abroad — and the launderers include some of your biggest backers. The chief can build a real enforcement net, or keep the channel quietly open for friends.",left:{id:"a",label:"Build the anti-laundering net.",tooltip:"A river of stolen money flowing abroad bleeds us white.",reveal:"You stand up real trade-laundering enforcement and the outflows slow. The reserves steady and the world's watchdogs approve, but your backers' escape route is now monitored, and they are furious.",effects:{FI:5,GL:5,EN:3,FA:-10}},right:{id:"b",label:"Keep the laundering channel open.",tooltip:"The men who move that money also fund the party.",reveal:"You leave the over-invoicing pipeline flowing. Your backers keep stashing wealth abroad and stay loyal, and the reserves keep haemorrhaging out through a hole you chose not to plug.",effects:{FA:5,FI:-10,GL:-6}}},{id:"finance-0057",location:"finance",arc:"finance-t0-a52",stage:0,speaker:"Investment Authority Chief",portrait:"ambassador",tags:["sez","fdi","incentives"],prompt:"To lure foreign factories into the new economic zones, investors demand decade-long tax holidays, free land, and guaranteed power. The chief says the jobs and FDI are worth it; the revenue board warns you are giving away the future tax base to win a present photo-op.",left:{id:"a",label:"Grant the generous investor incentives.",tooltip:"An empty zone earns nothing; fill it at any price.",reveal:"You hand out the tax holidays and the factories come. Jobs and FDI flow in for the headlines, and the revenue board quietly notes the decade of tax you have signed away.",effects:{FI:3,EN:3,GL:3,RE:-3}},right:{id:"b",label:"Offer leaner, time-limited incentives.",tooltip:"A zone bought with the whole future is a bad bargain.",reveal:"You offer modest, sunset-clause incentives. Some footloose investors look elsewhere and the zones fill slower, but the deals that land actually pay tax within the decade.",effects:{FI:3,GL:-3,EN:2}}},{id:"finance-0058",location:"finance",arc:"finance-t0-a53",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["deficit","printing","inflation"],prompt:"The government is broke and the bills are due. The easiest fix is to have the central bank simply print money to cover the deficit — quick, painless today, and a slow detonator of inflation tomorrow. The governor warns it is the road every ruined economy has walked.",left:{id:"a",label:"Print money to cover the deficit.",tooltip:"A bill paid today is a bill paid.",reveal:"You lean on the printing press and the bills are met. The relief is immediate and the cost deferred, as the new money seeps into prices and the inflation you deferred compounds.",effects:{FI:5,EN:-13,GL:-6}},right:{id:"b",label:"Refuse to monetise the deficit.",tooltip:"A printing press is a slow-motion default.",reveal:"You hold the line against monetisation and cut or borrow instead. The squeeze is painful and immediate, but you spare the country the inflationary spiral that has ruined so many.",effects:{GL:3,FI:-6,EN:-3}}},{id:"finance-0059",location:"finance",arc:"finance-t0-a54",stage:0,speaker:"Agricultural Bank Chairman",portrait:"people",tags:["sme","farmers","credit"],prompt:"Small farmers and tiny businesses are starved of credit, locked out by banks that lend only to the big and the connected. The chairman wants a subsidised small-credit drive to the grassroots — risky, costly, and politically golden — versus keeping lending safe and concentrated.",left:{id:"a",label:"Drive subsidised credit to the grassroots.",tooltip:"A loan to a farmer grows more than a loan to a tycoon.",reveal:"You push cheap credit out to farmers and micro-enterprises. Default risk and cost rise, but the rural economy stirs to life and millions feel the state's hand for the first time.",effects:{EN:8,FI:-10}},right:{id:"b",label:"Keep lending safe and concentrated.",tooltip:"A bank that lends to the poor is a bank that fails.",reveal:"You keep credit flowing to the safe and the big. The banks' books stay clean, and the small farmer and the micro-trader keep borrowing from the moneylender at ruinous rates.",effects:{FI:3,EN:-10,FA:2}}},{id:"finance-0060",location:"finance",arc:"finance-t0-a55",stage:0,speaker:"Treasury Operations Chief",portrait:"official",tags:["liquidity","festival","wages"],prompt:"Eid is days away and the garment factories cannot make payroll and bonuses for millions of workers, who will riot if sent home empty-handed for the holiday. The chief can extend emergency state liquidity to the owners, or let the owners face their own workers.",left:{id:"a",label:"Extend emergency liquidity to the factories.",tooltip:"A million unpaid workers at Eid is a powder keg.",reveal:"You bail out the payrolls and the workers go home paid for the holiday. The owners are rescued from their own mismanagement again, learning once more that the state will always catch them.",effects:{EN:6,FI:-10,FA:2}},right:{id:"b",label:"Let the owners face their workers.",tooltip:"I will not bankroll the bonuses of profitable men.",reveal:"You refuse the bailout and tell the owners to pay their own way. Some factories erupt in unrest over delayed wages, but the owners learn the treasury is not their overdraft.",effects:{FI:3,EN:-10,FA:-3}}},{id:"finance-0061",location:"finance",arc:"finance-t0-a56",stage:0,speaker:"Export Promotion Director",portrait:"official",tags:["exports","diversification","garments"],prompt:"The economy is dangerously dependent on garments for almost all its exports. The director wants to pour incentives into new sectors — pharma, leather, IT services, shipbuilding — a slow, uncertain bet, versus doubling down on the garment cash cow that already works.",left:{id:"a",label:"Invest in export diversification.",tooltip:"An economy on one leg falls when that leg is kicked.",reveal:"You back the emerging sectors with incentives and infrastructure. The payoff is slow and some bets will fail, but the export base begins, finally, to broaden beyond the loom.",effects:{FI:2,GL:3,EN:3,RE:2}},right:{id:"b",label:"Double down on garments.",tooltip:"Why bet on maybes when the looms pay now?",reveal:"You concentrate support on the proven garment sector. Exports stay strong and the cash flows, and the economy's single point of failure grows ever more dangerous and ever more entrenched.",effects:{FI:5,EN:-3,GL:-3}}},{id:"finance-0062",location:"finance",arc:"finance-t0-a57",stage:0,speaker:"Digital Economy Adviser",portrait:"people",tags:["it","freelancers","youth"],prompt:"Hundreds of thousands of young freelancers earn foreign currency online, but they are taxed clumsily, blocked from easy payment channels, and ignored. The adviser wants a freelancer-friendly regime of easy payments and tax breaks to grow a new export pillar.",left:{id:"a",label:"Build the freelancer-friendly regime.",tooltip:"A laptop in a village earns dollars from the world.",reveal:"You smooth payments, ease taxes, and back training for the digital workforce. A new stream of foreign currency grows, and a generation of the young find work without leaving home.",effects:{FI:5,EN:5,GL:2}},right:{id:"b",label:"Leave the freelancers to fend for themselves.",tooltip:"A scattered cottage industry is not a strategy.",reveal:"You keep the clumsy status quo. The freelancers route their earnings through grey channels or move abroad, and a homegrown export pillar withers before it can take root.",effects:{FI:-3,EN:-6,GL:-3}}},{id:"finance-0063",location:"finance",arc:"finance-t0-a58",stage:0,speaker:"Financial Intelligence Chief",portrait:"ambassador",tags:["capital-flight","second-homes","elite"],prompt:"Exposés abroad reveal your elite — ministers, MPs, tycoons — own fortunes in foreign property they could never have earned honestly. The world offers cooperation to trace and freeze it. The chief asks whether to pursue the trail or quietly let it lie.",left:{id:"a",label:"Pursue and repatriate the hidden wealth.",tooltip:"Stolen money parked abroad still belongs to the people.",reveal:"You take up the foreign cooperation and chase the laundered fortunes home. Some assets are frozen and the public is electrified, but the exposed elite — your own ranks — declare quiet war.",effects:{FI:5,GL:5,EN:6,FA:-16}},right:{id:"b",label:"Let the trail go cold.",tooltip:"Half my cabinet owns those flats.",reveal:"You decline to pursue the foreign holdings. Your elite's offshore nest eggs stay safe and they stay loyal, and the message that the powerful loot with impunity is stamped a little deeper.",effects:{FA:6,FI:-6,EN:-13,GL:-10}}},{id:"finance-0064",location:"finance",arc:"finance-t0-a59",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["crypto","regulation","capital-controls"],prompt:"Cryptocurrency is spreading among the young as a hedge against the falling taka and a hole in your capital controls. The governor can ban it outright as a laundering and flight risk, or regulate and tax it as an inevitable new asset.",left:{id:"a",label:"Ban cryptocurrency outright.",tooltip:"A currency I cannot see is a hole in the dam.",reveal:"You ban crypto and threaten the traders. The official capital controls hold a little better, but the trade simply goes underground, and the tech-savvy young add another grievance to the pile.",effects:{FI:2,MI:2,GL:-3,EN:-6}},right:{id:"b",label:"Regulate and tax it instead.",tooltip:"Better to tax the tide than to forbid it.",reveal:"You bring crypto into a regulated, taxed framework. The capital-flight risk is real and the controls leakier, but you tax the activity, attract some fintech, and keep faith with the young.",effects:{FI:3,GL:2,EN:2}}},{id:"finance-0065",location:"finance",arc:"finance-t0-a60",stage:0,speaker:"PPP Authority Chief",portrait:"fixer",tags:["ppp","infrastructure","contracts"],prompt:"A private consortium offers to build and run a major toll expressway under a public-private partnership — sparing the budget the upfront cost, but locking the public into decades of toll payments and a sweetheart guarantee that the state covers any shortfall.",left:{id:"a",label:"Sign the PPP with the state guarantee.",tooltip:"Roads now, paid for by tomorrow's tolls.",reveal:"The expressway gets built without upfront state money. The consortium pockets guaranteed returns for decades, and the 'minimum revenue' clause quietly hands the risk back to the public purse.",effects:{RE:3,FI:2,EN:2,GL:-3}},right:{id:"b",label:"Demand fair terms or build it publicly.",tooltip:"A guarantee that the state eats all losses is a gift, not a partnership.",reveal:"You refuse the lopsided guarantee and renegotiate or build it yourself. The road is slower to come and the budget strained, but the public is not signed up to underwrite private profit.",effects:{FI:-6,EN:2,GL:2}}},{id:"finance-0066",location:"finance",arc:"finance-t0-a61",stage:0,speaker:"Planning Commission Member",portrait:"official",tags:["development-budget","spending","quality"],prompt:"The annual development budget is chronically rushed out in the final months in a splurge of low-quality, padded projects, so the money is 'spent' on paper. The member wants a shift to fewer, well-vetted projects — slower disbursement, better roads — over the year-end dash.",left:{id:"a",label:"Reform toward fewer, better projects.",tooltip:"A road built twice is a road paid for thrice.",reveal:"You impose vetting and steady disbursement over the year-end splurge. The 'utilisation' numbers dip and the contractors grumble, but the projects that get built actually last.",effects:{FI:3,EN:5,GL:2,FA:-3}},right:{id:"b",label:"Keep the year-end spending dash.",tooltip:"Unspent money is a bureaucrat's failure on paper.",reveal:"You let the final-quarter splurge continue. The disbursement targets are hit and everyone looks busy, and the padded, half-built projects crumble within a season or two.",effects:{FA:2,FI:-3,EN:-10}}},{id:"finance-0067",location:"finance",arc:"finance-t0-a62",stage:0,speaker:"Microfinance Regulator",portrait:"people",tags:["microfinance","debt","poverty"],prompt:"The microfinance sector that the country pioneered now risks over-lending, trapping the rural poor in spirals of debt to multiple lenders at high effective rates. The regulator wants caps and a shared credit registry; the big MFIs, politically influential, resist.",left:{id:"a",label:"Cap rates and build a debt registry.",tooltip:"A loan that traps is no longer a ladder.",reveal:"You cap effective rates and require a shared registry to stop multiple-lending. The big lenders fight the limits, but the rural poor stop drowning under stacked, overlapping loans.",effects:{EN:6,GL:2,FI:-3,FA:-3}},right:{id:"b",label:"Leave the sector to self-regulate.",tooltip:"Do not break the model the world copied.",reveal:"You leave the MFIs to their own devices. The model's reputation is preserved, and in the villages the quiet debt spirals tighten, household by over-borrowed household.",effects:{FI:2,FA:2,EN:-10}}},{id:"finance-0068",location:"finance",arc:"finance-t0-a63",stage:0,speaker:"Defence Finance Secretary",portrait:"general",tags:["defence","budget","spending"],prompt:"The military, restive and powerful, wants a major budget increase for new hardware and perks — loyalty insurance for a government that needs the barracks onside. The secretary notes the money would gut the social spending you have promised the public.",left:{id:"a",label:"Grant the military budget increase.",tooltip:"A contented barracks is a sleeping coup.",reveal:"You fund the military's wish-list and the brass is reassured of your favour. The barracks stay loyal, and the schools, clinics, and pensions you promised the public quietly shrink to pay for it.",effects:{MI:6,FA:2,FI:-10,EN:-10}},right:{id:"b",label:"Hold the defence budget, fund the public.",tooltip:"A nation is defended by its people's wellbeing too.",reveal:"You hold the line on defence and protect social spending. The public services hold, but the generals feel slighted and watched, and a restive barracks is a risk you now carry.",effects:{EN:6,GL:2,MI:-10,FI:-3}}},{id:"finance-0069",location:"finance",arc:"finance-t0-a64",stage:0,speaker:"Auditor General",portrait:"official",tags:["reserves","transparency","audit"],prompt:"The true, spendable level of the foreign reserves has been quietly overstated for years by counting funds that are already committed. An honest restatement would calm no one and spook the markets; continued obfuscation buys time but compounds the eventual reckoning.",left:{id:"a",label:"Publish the honest, lower reserve figure.",tooltip:"A number built on a lie collapses worse later.",reveal:"You restate the reserves truthfully. The markets and the public are rattled by the lower figure, but the credibility you buy with honesty steadies the longer game and the IMF's trust.",effects:{GL:5,FI:-6,EN:-3}},right:{id:"b",label:"Keep counting the committed funds.",tooltip:"A panic today is worse than a problem deferred.",reveal:"You keep the flattering figure on the books. The markets stay calm on a number that is not real, and the day the truth finally surfaces, the fall will be all the further.",effects:{FI:3,GL:-10,EN:-3}}},{id:"finance-0070",location:"finance",arc:"finance-t0-a65",stage:0,speaker:"Bank Inspection Chief",portrait:"shadow",tags:["fraud","banks","scandal"],prompt:"A colossal loan fraud has surfaced at a state bank — thousands of crores siphoned out on forged collateral by a ring with reach into the board and the regulator. The chief can mount a full, public investigation, or contain it quietly to protect confidence and connected names.",left:{id:"a",label:"Order a full public investigation.",tooltip:"A fraud buried festers into a collapse.",reveal:"You open a transparent probe and the arrests climb toward the boardroom and beyond. Confidence wobbles at the spectacle, but the looters face justice and the system is forced to clean house.",effects:{GL:5,EN:5,FI:-6,FA:-10}},right:{id:"b",label:"Contain it quietly.",tooltip:"A public scandal runs the depositors to the doors.",reveal:"You keep the fraud out of the headlines and settle it in the dark. Confidence holds on the surface, the connected escape, and the hole in the bank is quietly stuffed with public money.",effects:{FI:2,FA:3,EN:-10,GL:-10}}},{id:"finance-0071",location:"finance",arc:"finance-t0-a65",stage:1,speaker:"Bank Inspection Chief",portrait:"shadow",tags:["fraud","banks","scandal"],prompt:"Your handling of the first fraud set the tone, and now a second bank reports a similar hole. The chief warns that the rot is systemic and demands a sweeping regulatory overhaul with real independence — which would clip the wings of the very politicians who appoint the boards.",left:{id:"a",label:"Grant the regulator real independence.",tooltip:"A watchdog on the owner's leash guards nothing.",reveal:"You hand the banking regulator genuine independence and teeth. The politicians who packed the boards lose their grip and rage, but the banking sector gains its first real check in a generation.",effects:{GL:5,EN:5,FI:2,FA:-10}},right:{id:"b",label:"Keep the regulator under political control.",tooltip:"An independent watchdog bites the hand that feeds the party.",reveal:"You keep the regulator pliant. The board appointments stay a political spoil, the frauds keep their cover, and the banking system slides deeper toward a reckoning no one is watching for.",effects:{FA:5,FI:-6,EN:-10,GL:-6}}},{id:"finance-0072",location:"finance",arc:"finance-t0-a66",stage:0,speaker:"Remittance Policy Director",portrait:"people",tags:["remittances","incentive","reserves"],prompt:"Remittances are slipping into the illegal hundi channel because the official rate is poor. The director proposes a cash incentive on every dollar sent home through banks — costly to the budget, but a magnet to pull billions back into the reserves.",left:{id:"a",label:"Fund the remittance cash incentive.",tooltip:"A bonus on every dollar is a dollar in the vault.",reveal:"You pay the incentive and the official remittances surge as hundi loses its edge. The budget takes a real hit, but the reserves swell with the inflows you lured back into the light.",effects:{FI:5,EN:3,GL:2}},right:{id:"b",label:"Skip the incentive to save the budget.",tooltip:"I will not pay people to do what they should anyway.",reveal:"You forgo the incentive. The budget is spared the cost, but the remittances keep leaking into hundi, the reserves miss the inflows, and the black-market dollar keeps its premium.",effects:{FI:-6,EN:-3,GL:-3}}},{id:"finance-0073",location:"finance",arc:"finance-t0-a66",stage:1,speaker:"Remittance Policy Director",portrait:"people",tags:["remittances","incentive","reserves"],prompt:"The incentive worked, but exporters cry foul: the same scheme that lifts remittances has effectively given migrant dollars a better rate than export dollars, and the garment lobby demands equal treatment or threatens to hold earnings offshore.",left:{id:"a",label:"Extend the incentive to exporters too.",tooltip:"One dollar should be worth another, whoever earned it.",reveal:"You level the field and incentivise export proceeds as well. The reserves keep filling and the exporters are placated, but the budget's incentive bill balloons toward the unsustainable.",effects:{FI:2,GL:2,EN:-3}},right:{id:"b",label:"Hold the line, remittances only.",tooltip:"I cannot subsidise every dollar in the economy.",reveal:"You refuse to widen the scheme. The budget is protected, but the garment lobby retaliates by parking earnings abroad, and some of the reserve gain leaks back out the other side.",effects:{FI:2,FA:-3,GL:-3}}},{id:"finance-0074",location:"finance",arc:"finance-t0-a67",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["imports","lc","reserves"],prompt:"To stem the reserve drain, the governor can choke the letters of credit that finance imports — banning 'luxury' goods and rationing dollars. It saves precious reserves, but it also starves factories of raw materials and spawns a corrupt queue for who gets a dollar.",left:{id:"a",label:"Clamp down hard on import LCs.",tooltip:"A dollar saved is a dollar that stays in the vault.",reveal:"You ration the LCs and the reserve bleed slows. Factories starved of imported inputs cut shifts, a black market in LC approvals blooms, and the well-connected jump the dollar queue.",effects:{FI:5,EN:-10,FA:2,GL:-3}},right:{id:"b",label:"Keep imports flowing, defend reserves elsewhere.",tooltip:"A factory without inputs is a layoff with a delay.",reveal:"You keep the import channel open and seek savings elsewhere. Industry keeps running and no corrupt LC queue forms, but the reserves keep draining toward the danger line.",effects:{EN:3,FI:-10,GL:2}}},{id:"finance-0075",location:"finance",arc:"finance-t0-a67",stage:1,speaker:"Central Bank Governor",portrait:"official",tags:["imports","lc","reserves"],prompt:"The import curbs hit a nerve: shortages of medicines, industrial inputs, and even some foods are biting, and the manufacturers warn of mass layoffs. The governor asks whether to keep the squeeze or selectively reopen the most essential imports.",left:{id:"a",label:"Hold the squeeze to protect reserves.",tooltip:"The reserves must come first or nothing else holds.",reveal:"You maintain the clampdown. The reserves are defended, but the shortages deepen into closed factories and empty pharmacy shelves, and the hardship radiates through the economy.",effects:{FI:5,EN:-13,GL:-3}},right:{id:"b",label:"Reopen essential imports selectively.",tooltip:"I will not ration medicine to save a statistic.",reveal:"You carve out medicines, food, and key inputs from the curbs. The reserve relief is smaller, but the worst shortages ease and the factories keep their workers on the line.",effects:{EN:5,FI:-6,GL:2}}},{id:"finance-0076",location:"finance",arc:"finance-t0-a68",stage:0,speaker:"Statistics Bureau Chief",portrait:"shadow",tags:["gdp","statistics","credibility"],prompt:"The bureau can 'rebase' and massage the GDP figures to show a glittering growth rate that flatters your rule and tops the regional league tables. Economists already mutter that the numbers do not match the power use or the imports. The chief awaits your nod.",left:{id:"a",label:"Publish the flattering growth figures.",tooltip:"A nation grows as fast as its statistics say.",reveal:"You release the burnished numbers and top the league tables. The applause is real and the doubt is louder; when reality diverges from the data, the whole record becomes suspect.",effects:{FI:3,GL:2,EN:-10}},right:{id:"b",label:"Publish honest, humbler figures.",tooltip:"A growth rate I have to defend is not growth.",reveal:"You release credible numbers, modest as they are. The headlines are duller and rivals crow, but the data the country plans by — and the lenders trust — stays sound.",effects:{GL:3,EN:2,FI:-6}}},{id:"finance-0077",location:"finance",arc:"finance-t0-a69",stage:0,speaker:"Wage Commission Chair",portrait:"people",tags:["wages","labour","cost"],prompt:"A national minimum wage covering every sector would lift millions of the working poor — and the employers, your donors, warn it will price out jobs and torch competitiveness. The chair needs the level set.",left:{id:"a",label:"Set a meaningful national minimum wage.",tooltip:"A wage too low to live on is a subsidy to the boss.",reveal:"You set a real floor under wages. Millions of the working poor breathe easier, the donors howl about competitiveness, and a few marginal employers do shed jobs.",effects:{EN:8,FI:-6,FA:-6}},right:{id:"b",label:"Keep wages to the market.",tooltip:"A floor too high empties the factory.",reveal:"You leave wages to the market and the donors content. Competitiveness is protected and the jobs stay, and the working poor keep grinding at a wage that never quite covers the rent.",effects:{FI:3,FA:3,EN:-13}}},{id:"finance-0078",location:"finance",arc:"finance-t0-a70",stage:0,speaker:"Consumer Protection Director",portrait:"shadow",tags:["e-commerce","ponzi","fraud"],prompt:"A wildly popular e-commerce platform turns out to be a Ponzi scheme — taking advance payments for goods it never delivers, with hundreds of thousands of customers' money gone. The director can move now to freeze and prosecute, or hesitate while the founders flee.",left:{id:"a",label:"Freeze and prosecute immediately.",tooltip:"A scam this size will not be allowed to vanish.",reveal:"You freeze the accounts and arrest the founders before they bolt. Some customer money is clawed back, and the swift action signals that the digital wild-west has a sheriff at last.",effects:{EN:6,GL:3,FI:2}},right:{id:"b",label:"Move slowly and study the case.",tooltip:"A hasty freeze could spook the whole sector.",reveal:"You proceed cautiously and the founders launder and flee. The customers' money evaporates, the scandal metastasises, and trust in the entire e-commerce sector collapses.",effects:{FI:-6,EN:-13,GL:-6}}},{id:"finance-0079",location:"finance",arc:"finance-t0-a71",stage:0,speaker:"Bank Inspection Chief",portrait:"shadow",tags:["nbfi","embezzlement","regulator"],prompt:"A non-bank financial institution has been looted to its bones by a single fugitive operator who captured its board and siphoned out a fortune — with the regulator asleep or complicit. The chief asks whether to pursue the fugitive and the enablers, or quietly write it off.",left:{id:"a",label:"Pursue the fugitive and the enablers.",tooltip:"A theft this brazen demands a reckoning.",reveal:"You launch an international pursuit and turn the lens on the regulators who slept. The fugitive is hunted and some enablers fall, and the financial watchdogs are forced, painfully, to wake.",effects:{GL:5,EN:5,FA:-10,FI:2}},right:{id:"b",label:"Write it off quietly.",tooltip:"A public hunt only advertises how deep the rot runs.",reveal:"You let the loss be quietly absorbed. The fugitive keeps his fortune abroad, the sleeping regulators keep their jobs, and the next operator notes how softly a billion can be stolen here.",effects:{FA:3,FI:-6,EN:-10,GL:-6}}},{id:"finance-0080",location:"finance",arc:"finance-t0-a72",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["autonomy","monetary","independence"],prompt:"The finance ministry wants the central bank to bend monetary policy to the government's election-year wishes — cheap credit, a propped currency, printed money — over the governor's professional judgment. He asks you to protect his independence, or to bring the bank to heel.",left:{id:"a",label:"Bring the central bank to heel.",tooltip:"A bank that defies the government is a rival.",reveal:"You subordinate the central bank to the ministry's will. The election-year sugar flows, and the institution's hard-won credibility — the thing that anchors inflation and the currency — bleeds away.",effects:{FI:3,MI:2,GL:-10,EN:-6}},right:{id:"b",label:"Protect the central bank's independence.",tooltip:"A tame central bank is a slow-motion crisis.",reveal:"You shield the governor's autonomy. The ministry fumes at being denied its election-year levers, but the bank keeps the credibility that holds the currency and the lenders' trust.",effects:{GL:5,FI:-3,EN:2}}},{id:"finance-0081",location:"finance",arc:"finance-t0-a73",stage:0,speaker:"Food Directorate Chief",portrait:"people",tags:["procurement","farmers","rice"],prompt:"Harvest is in, and you set the price at which the state buys rice from farmers. A high procurement price rewards the farmer and floods the public granary at cost; a low one saves money but leaves the grower at the mercy of the millers' cartel.",left:{id:"a",label:"Set a high, farmer-friendly price.",tooltip:"A farmer paid fairly plants again.",reveal:"You buy at a generous price and fill the granary. The growers prosper and the food reserve swells, at a real cost to the budget that the millers' cartel would have pocketed anyway.",effects:{EN:6,FI:-10}},right:{id:"b",label:"Set a low procurement price.",tooltip:"The granary cannot bankrupt the treasury.",reveal:"You buy cheap and save the budget. The granary fills at less cost, but the farmer, undercut, sells to the millers' cartel at a loss and curses the season.",effects:{FI:5,EN:-10}}},{id:"finance-0082",location:"finance",arc:"finance-t0-a74",stage:0,speaker:"Food Directorate Chief",portrait:"relief",tags:["oms","inflation","poor"],prompt:"Food prices have spiked and the urban poor are skipping meals. The chief can throw open the state granary in subsidised open-market sales across the cities — costly, and a magnet for skimming — or hold the reserve against a worse shortage to come.",left:{id:"a",label:"Open the granary in subsidised sales.",tooltip:"A hungry city is a city on the edge.",reveal:"You flood the cities with cheap state rice and the queues ease. The reserve drains and skimming creeps in at the trucks, but the poor eat and the streets stay calm.",effects:{EN:6,FI:-6}},right:{id:"b",label:"Hold the reserve for a worse day.",tooltip:"A granary emptied early starves a later crisis.",reveal:"You ration the reserve against future shortage. The budget and the buffer are protected, but the urban poor go hungry now, and the resentment simmers in the bread queues.",effects:{FI:3,EN:-13}}},{id:"finance-0083",location:"finance",arc:"finance-t0-a75",stage:0,speaker:"Social Protection Director",portrait:"people",tags:["cash-transfer","education","poverty"],prompt:"A conditional cash-transfer scheme would pay poor mothers to keep their children in school and at the clinic — proven to cut poverty and stunting — but it demands a vast, well-run delivery system and a permanent budget line the finance hawks resist.",left:{id:"a",label:"Launch the conditional cash transfer.",tooltip:"Money to a mother for her child's schooling pays back for decades.",reveal:"You build the scheme and the payments reach poor mothers. The delivery is a logistical mountain and the budget line permanent, but school attendance climbs and a poverty cycle starts to break.",effects:{EN:8,GL:3,FI:-13}},right:{id:"b",label:"Stick with cheaper in-kind handouts.",tooltip:"A grand transfer scheme is a budget I cannot promise forever.",reveal:"You keep the patchy in-kind handouts instead. The budget is spared the permanent commitment, and the chance to bind relief to schooling and health is left on the table.",effects:{FI:3,EN:-6}}},{id:"finance-0084",location:"finance",arc:"finance-t0-a76",stage:0,speaker:"Revenue Board Chairman",portrait:"official",tags:["property-tax","wealth","elite"],prompt:"The cities are full of untaxed mansions and empty investment flats hoarded by the rich, while the state scrapes for revenue. A real property tax would tap that idle wealth — and fall squarely on the affluent, donors and dynasts among them.",left:{id:"a",label:"Introduce a real property tax.",tooltip:"A palace should pay more than a payslip.",reveal:"You bring in a genuine property tax on the high end. The revenue base broadens onto idle wealth, the affluent grumble and lobby, and for once the rich shoulder a fair share.",effects:{FI:6,EN:5,FA:-10,GL:2}},right:{id:"b",label:"Leave property lightly taxed.",tooltip:"The men in those mansions are the men who fund me.",reveal:"You leave the mansions and empty flats lightly taxed. The donors are content and their wealth stays idle and untouched, and the revenue gap is filled, as ever, by those who cannot dodge.",effects:{FA:3,FI:-6,EN:-10}}},{id:"finance-0085",location:"finance",arc:"finance-t0-a77",stage:0,speaker:"Revenue Board Chairman",portrait:"ambassador",tags:["digital-tax","big-tech","revenue"],prompt:"The global tech giants earn fortunes in advertising and services here while paying almost no tax. A digital-services tax would capture that — and risk retaliation, throttled services, and a quarrel with Washington that other files cannot afford.",left:{id:"a",label:"Impose the digital-services tax.",tooltip:"A giant that earns here pays here.",reveal:"You tax the tech giants' local earnings. The revenue is real and popular, but the platforms threaten to throttle services and Washington adds it to a list of grievances against you.",effects:{FI:5,GL:-6,EN:2}},right:{id:"b",label:"Hold off to avoid the quarrel.",tooltip:"A fight with the platforms and Washington at once is a fight I lose.",reveal:"You shelve the tax to keep the peace. The giants keep earning tax-free, the revenue stays forgone, and your dependence on their services and Washington's goodwill stays unchallenged.",effects:{GL:2,FI:-6}}},{id:"finance-0086",location:"finance",arc:"finance-t0-a78",stage:0,speaker:"Debt Management Director",portrait:"ambassador",tags:["diaspora-bond","infrastructure","funding"],prompt:"You can raise development funds by selling a patriotic bond to the diaspora — cheaper than markets, binding the expatriates to the homeland — but a default or a scandal would betray the very people who trusted you most, and they vote and remit.",left:{id:"a",label:"Issue the diaspora infrastructure bond.",tooltip:"Let the children abroad help build the home.",reveal:"The diaspora subscribes generously and the projects get cheap funding. You have also taken the savings of trusting expatriates, and any stumble in repayment would be a betrayal felt worldwide.",effects:{FI:5,GL:2,RE:2}},right:{id:"b",label:"Fund development through other means.",tooltip:"I will not stake my people's trust on a bond.",reveal:"You decline to tap the diaspora's savings. The funding is costlier and slower, but you do not put the expatriates' faith — and their remittances — on the line.",effects:{GL:2,FI:-6}}},{id:"finance-0087",location:"finance",arc:"finance-t0-a79",stage:0,speaker:"Agriculture Finance Secretary",portrait:"people",tags:["diesel","irrigation","subsidy"],prompt:"Diesel for the irrigation pumps has spiked with world prices, threatening the boro rice crop that feeds the nation. The secretary wants an emergency diesel subsidy for farmers — costly and leak-prone — or you can let the fuel price pass through to the field.",left:{id:"a",label:"Fund the emergency irrigation subsidy.",tooltip:"A dry pump in boro season is a famine in waiting.",reveal:"You subsidise the diesel and the pumps keep running through the dry season. The crop is saved and the farmers grateful, at a heavy cost and with the usual leakage at the depots.",effects:{EN:6,RE:2,FI:-10}},right:{id:"b",label:"Let the fuel price pass through.",tooltip:"I cannot subsidise the world's oil price for every pump.",reveal:"You let the diesel cost hit the field. The budget is spared, but the irrigation falters, the boro crop wobbles, and the spectre of a thin harvest looms over the year.",effects:{FI:3,EN:-10,RE:-3}}},{id:"finance-0088",location:"finance",arc:"finance-t0-a80",stage:0,speaker:"Revenue Board Chairman",portrait:"official",tags:["sin-tax","health","revenue"],prompt:"Steep new taxes on tobacco, sugary drinks, and processed junk would raise revenue and improve public health at once — a rare win-win — but the powerful food and tobacco lobbies, and the price-sensitive public, will both push back hard.",left:{id:"a",label:"Impose the health-protecting sin taxes.",tooltip:"A tax that fills the treasury and empties the wards is a gift.",reveal:"You levy the sin taxes and revenue and health both improve. The lobbies fight and the public grumbles at pricier vices, but consumption of the worst products begins to fall.",effects:{FI:5,EN:5,FA:-6}},right:{id:"b",label:"Spare the consumer and the lobbies.",tooltip:"A new tax on small pleasures is a small revolt.",reveal:"You hold off on the sin taxes. The lobbies and the public are spared, and so is the disease and the revenue forgone, as the wards fill and the treasury stays thin.",effects:{FA:2,FI:-6,EN:-6}}},{id:"finance-0089",location:"finance",arc:"finance-t0-a81",stage:0,speaker:"Budget Secretary",portrait:"official",tags:["fiscal-rule","debt","discipline"],prompt:"A fiscal-responsibility law would cap the deficit and debt by statute, binding you and every successor to discipline — a credibility prize for the lenders, and a self-imposed straitjacket that forbids the populist splurges that win elections.",left:{id:"a",label:"Enact the binding fiscal rule.",tooltip:"A state that cannot bind itself cannot be trusted.",reveal:"You pass the fiscal-responsibility law. The lenders cheer the credibility and the markets calm, and you have tied your own hands against the easy election-year splurge.",effects:{GL:5,FI:3,EN:-3}},right:{id:"b",label:"Keep your fiscal hands free.",tooltip:"A rule that forbids me to spend in a crisis is a trap.",reveal:"You decline the statutory cap. You keep the freedom to splurge when politics demands, and the lenders keep their doubt about whether the deficit will ever truly be controlled.",effects:{FI:-3,EN:2,GL:-6}}},{id:"finance-0090",location:"finance",arc:"finance-t0-a82",stage:0,speaker:"Large Taxpayer Unit Chief",portrait:"official",tags:["transfer-pricing","multinationals","evasion"],prompt:"Multinational firms shift their local profits abroad through rigged internal pricing, paying almost no tax here. The chief wants a hard transfer-pricing crackdown to capture that revenue; the firms threaten to scale back investment and lobby their embassies.",left:{id:"a",label:"Crack down on transfer-pricing abuse.",tooltip:"Profits earned here should be taxed here.",reveal:"You enforce transfer-pricing rules and claw back real revenue. The multinationals grumble and a few trim investment, but the era of booking local fortunes as foreign losses ends.",effects:{FI:6,GL:2,EN:2}},right:{id:"b",label:"Tread softly to keep the investors sweet.",tooltip:"A spooked multinational takes its factory elsewhere.",reveal:"You go easy to protect the investment climate. The firms keep shifting their profits offshore tax-free, and the revenue you could have captured stays on a balance sheet in another country.",effects:{GL:2,FI:-10}}},{id:"finance-0091",location:"finance",arc:"finance-t0-a83",stage:0,speaker:"Agriculture Finance Secretary",portrait:"people",tags:["insurance","farmers","climate"],prompt:"Floods, cyclones, and droughts wipe out farmers' crops and push them into ruinous debt every year. A subsidised crop-insurance scheme would cushion them against the climate — a costly, complex new system, versus the cheaper status quo of ad-hoc disaster relief.",left:{id:"a",label:"Build the subsidised crop-insurance scheme.",tooltip:"A farmer insured plants without fear.",reveal:"You stand up crop insurance for the climate-battered. The system is costly and complex to run, but a ruined harvest no longer means a ruined family, and the farmers plant with confidence.",effects:{EN:6,RE:2,FI:-10}},right:{id:"b",label:"Stick with ad-hoc disaster relief.",tooltip:"A whole insurance system is a luxury; relief is enough.",reveal:"You keep the patchy, after-the-fact relief. It is cheaper and simpler, and each disaster still sweeps another cohort of farmers from their land into the moneylender's grip.",effects:{FI:3,EN:-6}}},{id:"finance-0092",location:"finance",arc:"finance-t0-a84",stage:0,speaker:"Provident Fund Trustee",portrait:"official",tags:["pension-fund","investment","risk"],prompt:"The vast public provident and pension funds sit in low-yield government paper. A reform would let them invest in markets and infrastructure for higher returns — and expose millions of workers' retirements to risk, manipulation, and the temptation to fund pet projects.",left:{id:"a",label:"Let the funds chase higher market returns.",tooltip:"Idle retirement money should work harder.",reveal:"You free the funds to invest in markets and infrastructure. Returns rise in good years, but the workers' retirements now ride the market's moods, and the temptation to steer them into pet projects is real.",effects:{FI:3,RE:2,EN:-6}},right:{id:"b",label:"Keep retirement money safe and dull.",tooltip:"A pensioner's savings are not a venture fund.",reveal:"You keep the funds in safe, dull government paper. The returns are modest, but the workers' retirements are not gambled on markets or raided for politically favoured schemes.",effects:{EN:3,FI:-3}}},{id:"finance-0093",location:"finance",arc:"finance-t0-a85",stage:0,speaker:"Stimulus Coordination Chief",portrait:"fixer",tags:["stimulus","sme","leakage"],prompt:"A huge emergency stimulus must flow fast to keep firms alive through a shock — but speed means weak controls, and the big, connected firms are already first in the queue while the small ones that need it most have no bank relationship to claim it.",left:{id:"a",label:"Push the money out fast through the banks.",tooltip:"Speed saves firms; controls can come later.",reveal:"You disburse fast through the banks, and the big connected firms hoover up the lion's share. Many are saved, but the small firms that needed it most are left out, and the leakage is enormous.",effects:{FI:3,FA:3,EN:-10}},right:{id:"b",label:"Build a fair channel to the small firms.",tooltip:"A stimulus that feeds the fed is no stimulus.",reveal:"You insist on a slower channel that reaches the genuinely small and informal. The big firms wait and grumble and a few fail in the delay, but the rescue reaches those it was meant for.",effects:{EN:6,FI:-6,FA:-6}}},{id:"finance-0094",location:"finance",arc:"finance-t0-a86",stage:0,speaker:"Securities Regulator",portrait:"shadow",tags:["ipo","market","manipulation"],prompt:"A wave of companies wants to list, and insiders are pricing the IPOs to enrich a favoured few before dumping on the retail crowd. The regulator can enforce fair, fundamentals-based pricing — slowing the listings — or let the lucrative game run.",left:{id:"a",label:"Enforce fair IPO pricing.",tooltip:"A market rigged at the listing is rotten at the root.",reveal:"You impose disciplined, fundamentals-based pricing. The listings slow and the insiders lose their easy killing, but the retail investor stops being the designated bag-holder.",effects:{GL:3,EN:5,FI:-3,FA:-3}},right:{id:"b",label:"Let the listing game run.",tooltip:"A busy market looks like a healthy one.",reveal:"You let the rigged IPOs flow. The market looks vibrant and the insiders prosper, and the small investors who buy the dumped shares learn, again, who the market is really for.",effects:{FI:3,FA:2,EN:-10}}},{id:"finance-0095",location:"finance",arc:"finance-t0-a87",stage:0,speaker:"Banking Division Secretary",portrait:"official",tags:["banks","exposure","concentration"],prompt:"A few giant business groups have borrowed so heavily from the banks that the failure of any one could topple the system. The secretary wants strict single-borrower limits enforced; the groups — major donors — call it a chokehold on the engines of the economy.",left:{id:"a",label:"Enforce strict single-borrower limits.",tooltip:"A bank chained to one tycoon falls with him.",reveal:"You force the concentration down. The over-leveraged groups must deleverage and protest bitterly, but the banking system stops being hostage to a handful of empires.",effects:{FI:3,GL:3,EN:3,FA:-10}},right:{id:"b",label:"Relax the limits for the big groups.",tooltip:"The great groups are the engines; do not stall them.",reveal:"You let the concentration ride. The tycoons keep borrowing freely and stay loyal, and the system's fate stays welded to a few balance sheets that are too big to fail and too connected to refuse.",effects:{FI:2,FA:3,EN:-6,GL:-6}}},{id:"finance-0096",location:"finance",arc:"finance-t0-a88",stage:0,speaker:"Banking Division Secretary",portrait:"fixer",tags:["banks","family-control","governance"],prompt:"A law lets a single family hold a bank's board for years through multiple directorships — a recipe for the insider looting that has hollowed banks before. A reform would break the family grip; the banking dynasties, deeply tied to your party, will fight it.",left:{id:"a",label:"Break the family grip on bank boards.",tooltip:"A bank run as a family fief gets looted as one.",reveal:"You cap family directorships and tenure. The banking dynasties rage and lean on their party ties, but the boards open up and the insider-looting machine loses its grease.",effects:{GL:5,EN:5,FI:2,FA:-13}},right:{id:"b",label:"Preserve the family directorships.",tooltip:"The banking families are pillars of the party.",reveal:"You keep the family-control law intact. The dynasties stay grateful and entrenched, and the next hollowed-out bank is already being quietly emptied by the board that owns it.",effects:{FA:5,FI:-3,EN:-10,GL:-6}}},{id:"finance-0097",location:"finance",arc:"finance-t0-a89",stage:0,speaker:"Tariff Commission Chief",portrait:"official",tags:["dumping","tariffs","industry"],prompt:"A flood of cheap, possibly dumped, foreign goods is undercutting your domestic manufacturers. The chief can slap on protective anti-dumping duties to save the local industry and jobs — raising prices for consumers — or keep the market open and cheap.",left:{id:"a",label:"Impose protective anti-dumping duties.",tooltip:"A factory drowned in cheap imports is a town unemployed.",reveal:"You shield the domestic industry with duties. The local manufacturers and their workers are saved, the exporting nation protests to the trade body, and consumers pay more for the protected goods.",effects:{FI:2,EN:3,GL:-6}},right:{id:"b",label:"Keep the market open and cheap.",tooltip:"A consumer's cheap goods are a benefit too.",reveal:"You leave the market open. Consumers enjoy the cheap imports, but the domestic factories buckle and shed jobs, hollowing out the very industry you hoped to grow.",effects:{GL:2,FI:-3,EN:-6}}},{id:"finance-0098",location:"finance",arc:"finance-t0-a90",stage:0,speaker:"Budget Secretary",portrait:"official",tags:["soe","losses","transparency"],prompt:"The state enterprises' staggering losses are hidden off-budget, quietly funded by directed bank loans and never shown to parliament. The secretary can bring them onto the books for honest accounting — a shocking number — or keep them comfortably in the shadows.",left:{id:"a",label:"Bring the SOE losses onto the budget.",tooltip:"A loss hidden is a debt compounding in the dark.",reveal:"You consolidate the hidden losses into the open budget. The true deficit number shocks, but the lenders respect the honesty and the bleeding enterprises can finally be confronted.",effects:{GL:5,EN:2,FI:-6}},right:{id:"b",label:"Keep the losses off-budget.",tooltip:"An ugly number published is a panic invited.",reveal:"You leave the SOE losses in the shadows. The headline deficit stays flattering, and the hidden hole keeps growing, funded by banks that will one day present the bill.",effects:{FI:3,GL:-10,EN:-3}}},{id:"finance-0099",location:"finance",arc:"finance-t0-a91",stage:0,speaker:"Anti-Money-Laundering Director",portrait:"ambassador",tags:["fatf","compliance","reputation"],prompt:"The global financial watchdog threatens to grey-list the country over weak money-laundering and terror-financing controls — a label that would choke correspondent banking and scare investors. Fixing it means real enforcement against laundering your own backers enjoy.",left:{id:"a",label:"Enforce hard to avoid the grey list.",tooltip:"A grey-listed nation is a nation cut off.",reveal:"You build genuine anti-laundering enforcement and dodge the listing. Correspondent banking stays open and investors calm, but your backers' laundering channels are now watched, and they are furious.",effects:{GL:6,FI:3,FA:-10}},right:{id:"b",label:"Do the minimum and risk the listing.",tooltip:"I will not strangle my friends' money to please a watchdog.",reveal:"You make cosmetic changes and your backers keep their channels. The watchdog grey-lists you, correspondent banks pull back, and the cost of every cross-border transaction climbs.",effects:{FA:3,GL:-13,FI:-10}}},{id:"finance-0100",location:"finance",arc:"finance-t0-a92",stage:0,speaker:"Land Reform Commissioner",portrait:"official",tags:["benami","property","corruption"],prompt:"Vast wealth hides in 'benami' property — assets held in others' names to disguise the true, often corrupt, owner. A law to pierce these veils and seize illicit holdings would be transformative, and would expose fortunes held by the very powerful.",left:{id:"a",label:"Enact and enforce the benami law.",tooltip:"A fortune in a servant's name is a confession.",reveal:"You pass the law and begin piercing the false ownership. Illicit fortunes are exposed and some seized, and the powerful who hid behind nominees are suddenly, dangerously visible.",effects:{GL:5,EN:6,FI:3,FA:-13}},right:{id:"b",label:"Leave benami holdings undisturbed.",tooltip:"Too many of those names lead back to my own.",reveal:"You let the benami fortunes lie. The powerful keep their disguised wealth, the loophole stays wide open, and the corrupt accumulation of decades goes quietly unchallenged.",effects:{FA:5,FI:-3,EN:-10,GL:-6}}},{id:"finance-0101",location:"finance",arc:"finance-t0-a93",stage:0,speaker:"Customs Commissioner",portrait:"shadow",tags:["gold","smuggling","policy"],prompt:"Tonnes of gold pass through the country's airports as smuggled transit, enriching syndicates with airport and police protection. The commissioner can legalise and tax gold imports to kill the smuggling's logic, or keep cracking down while the rackets thrive.",left:{id:"a",label:"Legalise and tax gold imports.",tooltip:"A trade taxed in daylight starves the smuggler.",reveal:"You open a legal, taxed gold-import channel. The smuggling syndicates lose their edge, the jewellers and the treasury gain, and a shadow trade is dragged into the light.",effects:{FI:5,GL:2,EN:2,FA:-3}},right:{id:"b",label:"Keep the ban and the crackdowns.",tooltip:"Legalising smuggling rewards the smuggler.",reveal:"You keep gold imports banned and chase the couriers. The headline seizures look tough, but the protected syndicates keep the bulk of the trade and the airport rackets stay golden.",effects:{MI:2,FI:-3,EN:-6}}},{id:"finance-0102",location:"finance",arc:"finance-t0-a94",stage:0,speaker:"Customs Commissioner",portrait:"shadow",tags:["vat-refund","drawback","fraud"],prompt:"Exporters claim duty drawbacks and VAT refunds on goods that were never made or shipped, draining the treasury through forged paperwork blessed by bribed officers. The commissioner can install a tracked, audited system, or leave the lucrative scam alone.",left:{id:"a",label:"Track and audit every refund claim.",tooltip:"A refund on a phantom export is theft with a stamp.",reveal:"You digitise and audit the refund system and the phantom claims collapse. Real exporters wait a little longer for genuine refunds, but a vast leak of public money is plugged.",effects:{FI:6,GL:2,FA:-6}},right:{id:"b",label:"Leave the refund system as it is.",tooltip:"A crackdown punishes the honest exporter too.",reveal:"You leave the refund pipeline loose. The genuine exporters get their money fast, and so do the fraudsters claiming on exports that never existed, bleeding the treasury all the while.",effects:{FI:-6,FA:2,EN:-6}}},{id:"finance-0103",location:"finance",arc:"finance-t0-a95",stage:0,speaker:"Customs Commissioner",portrait:"shadow",tags:["bonded-warehouse","duty","diversion"],prompt:"Duty-free raw materials imported for export factories under the bonded-warehouse scheme are being diverted onto the local market, undercutting honest producers and dodging duty. The commissioner can audit the bonds hard, or protect the well-connected abusers.",left:{id:"a",label:"Audit the bonded warehouses hard.",tooltip:"A duty-free import sold at home is smuggling by license.",reveal:"You audit the bonds and catch the diverters. Honest producers stop being undercut and the duty is recovered, and the connected abusers and their patrons turn on you.",effects:{FI:5,EN:3,FA:-6}},right:{id:"b",label:"Protect the connected abusers.",tooltip:"The men running those bonds run the party's accounts.",reveal:"You leave the bonded scam alone. The diverted goods keep flooding the local market duty-free, honest producers keep losing, and the racket's patrons stay loyal and rich.",effects:{FA:3,FI:-6,EN:-6}}},{id:"finance-0104",location:"finance",arc:"finance-t0-a96",stage:0,speaker:"Revenue Board Chairman",portrait:"official",tags:["inheritance-tax","wealth","dynasty"],prompt:"Great fortunes pass untaxed from one generation to the next, entrenching a hereditary elite. An inheritance tax would raise revenue and loosen the dynastic grip on wealth — and fall hardest on the established families, your own circle among them.",left:{id:"a",label:"Introduce an inheritance tax.",tooltip:"A fortune unearned should not pass wholly untouched.",reveal:"You levy a tax on great inheritances. Revenue rises and dynastic wealth loosens at the edges, and the established families — yours included — recoil at the precedent.",effects:{FI:5,EN:5,FA:-13}},right:{id:"b",label:"Leave inheritances untaxed.",tooltip:"I will not be the one to tax my own children's legacy.",reveal:"You spare inheritances the tax. The hereditary elite keeps its fortunes intact across generations, and the chance to broaden revenue and loosen dynastic wealth passes by.",effects:{FA:5,FI:-6,EN:-6}}},{id:"finance-0105",location:"finance",arc:"finance-t0-a97",stage:0,speaker:"Insurance Regulator",portrait:"people",tags:["microinsurance","poverty","resilience"],prompt:"A single illness, death, or flood pushes poor families into destitution. A microinsurance push — tiny premiums, simple payouts, delivered through mobile money — would cushion them, but it needs subsidy and tight regulation to keep the insurers from cheating the poor.",left:{id:"a",label:"Drive a regulated microinsurance scheme.",tooltip:"A few taka of cover stands between a family and ruin.",reveal:"You build subsidised, well-regulated microinsurance. The cost and oversight are real, but a flood or a funeral stops meaning the loss of everything for millions of poor households.",effects:{EN:6,FI:-6,GL:2}},right:{id:"b",label:"Leave the poor to informal coping.",tooltip:"A whole insurance system for tiny premiums earns nothing.",reveal:"You leave the poor to their informal safety nets of debt and charity. The budget is spared, and the next flood or illness keeps sweeping families from the edge into destitution.",effects:{FI:2,EN:-10}}},{id:"finance-0106",location:"finance",arc:"finance-t0-a98",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["islamic-finance","sukuk","savings"],prompt:"A large, pious pool of savings sits outside the banks because it shuns interest. A proper Islamic-finance framework and sovereign sukuk could mobilise that money for development — but it demands real Sharia governance, not a cosmetic relabelling that invites scandal.",left:{id:"a",label:"Build genuine Islamic finance and sukuk.",tooltip:"Faith-shy savings can still build roads.",reveal:"You establish credible Islamic-finance rules and issue sukuk. A vast pool of pious savings enters the formal economy and funds development, and the framework's integrity wins trust.",effects:{FI:5,EN:3,GL:2}},right:{id:"b",label:"Slap an Islamic label on conventional products.",tooltip:"The label is what the market wants; the substance is detail.",reveal:"You relabel conventional products as Islamic without real substance. The savings trickle in, but the scholars cry foul, a mis-selling scandal brews, and trust in the whole sector frays.",effects:{FI:2,EN:-6,GL:-3}}},{id:"finance-0107",location:"finance",arc:"finance-t0-a99",stage:0,speaker:"Banking Division Secretary",portrait:"official",tags:["deposit-insurance","savers","stability"],prompt:"Small savers have almost no protection if a bank fails, and rumours of trouble trigger panicked runs. A proper deposit-insurance scheme would protect savers and calm the system — funded by a levy the banks will resist, and a public backstop in a real crisis.",left:{id:"a",label:"Establish robust deposit insurance.",tooltip:"A saver who fears for his deposit starts a run.",reveal:"You build real deposit insurance funded by a bank levy. The banks grumble at the cost, but small savers gain protection and the system gains a shock absorber against panic.",effects:{FI:3,EN:5,GL:2,FA:-3}},right:{id:"b",label:"Leave savers to take their chances.",tooltip:"A levy on the banks is a cost passed to the customer.",reveal:"You decline the scheme to spare the banks the levy. The savers stay exposed, and the next rumour about a weak bank empties its counters before the truth can catch up.",effects:{FI:2,EN:-10}}},{id:"finance-0108",location:"finance",arc:"finance-t0-a100",stage:0,speaker:"Education Finance Secretary",portrait:"people",tags:["stipend","girls","education"],prompt:"The school stipend that keeps poor children — especially girls — in class is too small and reaches too few. Expanding it would lift enrolment and delay child marriage, a proven investment, at a steep and permanent cost to the budget.",left:{id:"a",label:"Expand the school stipend widely.",tooltip:"A stipend that keeps a girl in school changes a generation.",reveal:"You widen and raise the stipend. Enrolment climbs, child marriages slip later, and the budget takes a heavy permanent load for a payoff measured in decades.",effects:{EN:8,GL:3,FI:-13}},right:{id:"b",label:"Keep the stipend small and targeted.",tooltip:"A generous stipend is a budget line forever.",reveal:"You keep the stipend lean. The budget is protected, but the poorest children — and the girls most at risk of early marriage — keep dropping out for want of a few taka.",effects:{FI:3,EN:-6}}},{id:"finance-0109",location:"finance",arc:"finance-t0-a101",stage:0,speaker:"Women's Affairs Finance Officer",portrait:"people",tags:["maternity","allowance","poverty"],prompt:"Poor pregnant and nursing women work to the day they give birth and back, harming mother and child for want of any support. A national maternity allowance would change that — a costly, permanent commitment the finance hawks call unaffordable.",left:{id:"a",label:"Fund a national maternity allowance.",tooltip:"A nation that will not support its mothers stunts its future.",reveal:"You establish the maternity allowance. Mothers rest and nurse, infant health improves, and the budget carries a new permanent burden for a quietly transformative return.",effects:{EN:8,GL:3,FI:-10}},right:{id:"b",label:"Leave maternity support to charity.",tooltip:"A new allowance is a promise the budget cannot keep.",reveal:"You decline the allowance. The treasury is spared, and poor mothers keep labouring to the last day and back, the cost paid in their health and their children's.",effects:{FI:3,EN:-10}}},{id:"finance-0110",location:"finance",arc:"finance-t0-a102",stage:0,speaker:"Education Finance Secretary",portrait:"fixer",tags:["textbooks","printing","graft"],prompt:"The annual free-textbook programme — hundreds of millions of books to every child — is a logistical marvel riddled with printing-contract graft and quality-skimping. The secretary can clean up the tenders, angering a cartel of party-linked printers, or keep the books flowing on the cheap and corrupt status quo.",left:{id:"a",label:"Clean up the textbook tenders.",tooltip:"A child's book should not be a printer's bribe.",reveal:"You open the tenders and enforce quality. The party-linked printing cartel rages and threatens delays, but the books arrive better and the graft shrinks.",effects:{EN:5,FI:2,GL:2,FA:-6}},right:{id:"b",label:"Keep the printing cartel happy.",tooltip:"The books arrive on time; do not break the machine.",reveal:"You leave the cosy contracts intact. The books arrive on schedule, flimsy and over-priced, and the printers' cartel stays a reliable, grateful funder of the party.",effects:{FA:3,FI:-3,EN:-6}}},{id:"finance-0111",location:"finance",arc:"finance-t0-a103",stage:0,speaker:"Revenue Board Chairman",portrait:"official",tags:["tax-net","informal","compliance"],prompt:"Only a tiny fraction of citizens file taxes, and the chairman wants a drive to pull the vast informal middle — small traders, professionals, landlords — into the net. It would broaden revenue fairly, and it would knock on a million doors that have never paid and will resent it.",left:{id:"a",label:"Drive a broad tax-net expansion.",tooltip:"A nation where few pay is a nation few can fund.",reveal:"You launch the registration and enforcement drive. Revenue broadens onto those long outside the net, the new taxpayers grumble loudly, and the salaried at last get some company in paying.",effects:{FI:6,EN:3,FA:-6}},right:{id:"b",label:"Leave the informal economy untaxed.",tooltip:"A million new tax notices is a million new enemies.",reveal:"You hold off on the expansion. The informal middle keeps its untaxed cash, the revenue base stays narrow, and the few who do pay keep carrying the many who do not.",effects:{FA:2,FI:-6}}},{id:"finance-0112",location:"finance",arc:"finance-t0-a104",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["currency","redenomination","confidence"],prompt:"Years of inflation have left the currency cluttered with zeros, and a vanity proposal would lop several off to 'restore dignity' to the taka. The governor warns it is costly, disruptive, and purely cosmetic — fixing none of the inflation that caused the zeros.",left:{id:"a",label:"Redenominate the currency.",tooltip:"A proud currency wears fewer zeros.",reveal:"You lop the zeros off the taka in a grand relaunch. The notes look tidier and the optics flatter, and the costly, disruptive exercise changes nothing about the inflation that bloated them.",effects:{FI:-6,GL:2,EN:-3}},right:{id:"b",label:"Reject the cosmetic redenomination.",tooltip:"Zeros are a symptom; cutting them cures nothing.",reveal:"You spike the vanity project. There is no relaunch fanfare, but the money and disruption are saved, and you focus on the inflation that actually matters.",effects:{FI:3,GL:-3}}},{id:"finance-0113",location:"finance",arc:"finance-t0-a105",stage:0,speaker:"Financial Inclusion Director",portrait:"people",tags:["agent-banking","rural","inclusion"],prompt:"Agent banking — local shopkeepers acting as bank outlets — could bring real banking to villages that have never seen a branch. The director wants an aggressive rollout; the banks fear the fraud risk and the cannibalisation of their branch business.",left:{id:"a",label:"Push aggressive agent-banking rollout.",tooltip:"A bank counter in every bazaar banks the nation.",reveal:"You drive agent banking deep into the villages. The unbanked gain savings, credit, and payments for the first time, and the banks' fraud fears prove manageable against the reach gained.",effects:{EN:6,FI:3,GL:2}},right:{id:"b",label:"Let the banks set the pace.",tooltip:"A reckless rollout invites a fraud scandal.",reveal:"You leave the pace to the cautious banks. The fraud risk stays low, and so does the reach, and the villages keep waiting for a banking system that never quite arrives.",effects:{FI:2,EN:-6}}},{id:"finance-0114",location:"finance",arc:"finance-t0-a106",stage:0,speaker:"External Finance Secretary",portrait:"ambassador",tags:["world-bank","conditions","reform"],prompt:"The World Bank offers cheap budget support tied to governance reforms — procurement transparency, SOE discipline, subsidy reform. The secretary says the money is cheap and the reforms are sound; the catch is foreign conditions on domestic policy and the donors they annoy.",left:{id:"a",label:"Take the support and the reforms.",tooltip:"Cheap money and good medicine in one dose.",reveal:"You accept the budget support and enact the reforms. The cheap money helps and the governance genuinely improves, and the nationalists grumble about foreign hands on the tiller.",effects:{FI:5,GL:3,EN:2,FA:-3}},right:{id:"b",label:"Refuse the conditional support.",tooltip:"I will not let a foreign bank write my budget.",reveal:"You turn down the conditional money on principle. You keep full policy control, but you forgo cheap finance and the reforms that, conditions aside, the country actually needed.",effects:{FA:2,FI:-10,GL:-3}}},{id:"finance-0115",location:"finance",arc:"finance-t0-a107",stage:0,speaker:"Labour Finance Inspector",portrait:"people",tags:["wage-theft","workers","enforcement"],prompt:"Across the informal economy and even the factories, employers routinely withhold wages, overtime, and legal dues with near-total impunity. The inspector wants a real enforcement unit with teeth; the employers, many of them donors, call it harassment.",left:{id:"a",label:"Build a wage-enforcement unit with teeth.",tooltip:"A wage withheld is a wage stolen.",reveal:"You stand up a unit that actually recovers stolen wages and fines the thieves. Workers start getting their due, the donor-employers cry harassment, and a quiet everyday injustice meets a check.",effects:{EN:6,GL:2,FI:-3,FA:-6}},right:{id:"b",label:"Leave wage disputes to the workers.",tooltip:"An employer hounded for back-pay closes the gate.",reveal:"You decline to build the unit. The employers keep their impunity, and the workers keep chasing wages already earned and rarely paid in full.",effects:{FA:3,FI:2,EN:-10}}},{id:"finance-0116",location:"finance",arc:"finance-t0-a108",stage:0,speaker:"Budget Secretary",portrait:"fixer",tags:["recapitalisation","banks","bailout"],prompt:"The state banks, looted into insolvency, need recapitalising again from the budget — public money poured into holes dug by the very managers and defaulters who looted them, with no reform attached. The secretary asks whether to pay up or attach hard conditions.",left:{id:"a",label:"Recapitalise with no strings.",tooltip:"A failed state bank cannot simply be allowed to die.",reveal:"You pour public money into the looted banks again, no questions asked. They limp on, the loopers and defaulters who emptied them face nothing, and the cycle is set to repeat.",effects:{FI:-6,FA:3,EN:-10,GL:-6}},right:{id:"b",label:"Attach hard reform conditions.",tooltip:"I will not refill a bucket no one will fix.",reveal:"You make the bailout conditional on board purges, recoveries, and reform. The looters and their patrons fight it bitterly, but the public money goes in with at least a chance of staying.",effects:{GL:3,EN:3,FI:-6,FA:-10}}},{id:"finance-0117",location:"finance",arc:"finance-t0-a109",stage:0,speaker:"Revenue Board Chairman",portrait:"people",tags:["small-business","turnover-tax","simplicity"],prompt:"Small businesses are crushed by complex tax paperwork and the bribes that come with assessment. A simple flat turnover tax would ease their burden and pull them into the system — at the cost of some revenue from those who would have paid more honestly.",left:{id:"a",label:"Introduce the simple turnover tax.",tooltip:"A tax a shopkeeper can compute is a tax a shopkeeper pays.",reveal:"You bring in a flat, simple turnover tax for small firms. Compliance jumps as the paperwork and the bribes fall away, and the system gains millions of small, honest taxpayers.",effects:{FI:3,EN:5,FA:-3}},right:{id:"b",label:"Keep the existing complex assessment.",tooltip:"A flat tax leaves money on the table from the bigger fish.",reveal:"You keep the complex regime. The treasury squeezes more from the few who comply, and the rest stay outside, paying the assessor a bribe instead of the state a tax.",effects:{FI:2,EN:-6}}},{id:"finance-0118",location:"finance",arc:"finance-t0-a110",stage:0,speaker:"Central Bank Governor",portrait:"fixer",tags:["directed-lending","credit","distortion"],prompt:"The ministry wants the central bank to order the banks to pump cheap, directed credit into politically favoured sectors and firms. The governor warns it distorts the market and breeds bad loans; the politics says the favoured firms are friends who must be fed.",left:{id:"a",label:"Order the directed lending.",tooltip:"Credit steered to friends is friendship repaid.",reveal:"You direct the cheap credit to the favoured firms. They prosper on subsidised loans, the market distorts, and a fresh crop of politically-blessed bad loans begins to sprout.",effects:{FI:2,FA:3,EN:-6,GL:-6}},right:{id:"b",label:"Let credit follow the market.",tooltip:"Lending by favour is the seed of every banking crisis.",reveal:"You refuse to direct the credit. The favoured firms grumble at being denied their subsidy, but the banks lend on merit and the next wave of bad loans is not sown by decree.",effects:{GL:3,FI:2,EN:2,FA:-6}}},{id:"finance-0119",location:"finance",arc:"finance-t0-a111",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["interest-rate","inflation","growth"],prompt:"Inflation is biting hard, and the textbook answer is to raise interest rates and choke it — at the cost of slowing growth, raising borrowing costs, and angering the business lobby and the public both. The governor asks whether to tighten or to keep money cheap.",left:{id:"a",label:"Raise rates to crush inflation.",tooltip:"Unchecked inflation robs every wage and saving.",reveal:"You tighten hard and inflation begins, slowly, to ease. Borrowing costs jump, growth cools, the business lobby howls, and the painful medicine works as medicine does.",effects:{FI:3,GL:3,EN:-10}},right:{id:"b",label:"Keep money cheap to protect growth.",tooltip:"A choked economy is a poorer one for everyone.",reveal:"You keep rates low to protect growth and jobs. The business lobby is pleased and the expansion continues, and inflation keeps gnawing at every wage and every saving in the country.",effects:{EN:2,FI:-6,GL:-3}}},{id:"finance-0120",location:"finance",arc:"finance-t0-a112",stage:0,speaker:"Investment Authority Chief",portrait:"ambassador",tags:["fdi","screening","sovereignty"],prompt:"Foreign capital wants to buy into ports, telecoms, and banks — strategic sectors. A screening regime would protect national security and prevent a single foreign power buying influence; an open-door policy would maximise the investment you desperately need.",left:{id:"a",label:"Screen FDI in strategic sectors.",tooltip:"Some assets must not be owned from abroad.",reveal:"You set up a screening regime for strategic sectors. Some investment is deterred and the open-economy purists complain, but no single foreign power buys a chokehold on your ports or banks.",effects:{GL:2,MI:3,FI:-6}},right:{id:"b",label:"Keep an open door for all FDI.",tooltip:"Capital is capital; the country needs it.",reveal:"You keep the door wide open. The investment flows in handsomely, and with it a foreign power's quiet acquisition of stakes in the infrastructure your security depends on.",effects:{FI:5,GL:2,MI:-6}}},{id:"finance-0121",location:"finance",arc:"finance-t0-a113",stage:0,speaker:"Land Reform Commissioner",portrait:"people",tags:["land-records","digitisation","corruption"],prompt:"Land records are a chaos of forgeries and bribes, the single biggest source of litigation and graft in the country. Digitising them would end a century of fraud and dispossession — and gut a vast, lucrative ecosystem of clerks, touts, and forgers tied to local power.",left:{id:"a",label:"Digitise the land records.",tooltip:"A clear title is the poor man's strongest shield.",reveal:"You drive the digitisation through against fierce resistance. The forgers and touts lose their racket, land litigation eases, and the poor gain titles that can finally be defended.",effects:{EN:6,GL:3,FI:2,FA:-6}},right:{id:"b",label:"Leave the paper land records be.",tooltip:"Untangling a century of forgery is a war I cannot win.",reveal:"You leave the land-records chaos intact. The clerks and touts keep their lucrative fraud, the courts stay clogged with land disputes, and the powerful keep dispossessing the weak by forged deed.",effects:{FA:3,FI:-3,EN:-10}}},{id:"finance-0122",location:"finance",arc:"finance-t0-a114",stage:0,speaker:"Ports Finance Director",portrait:"official",tags:["port","efficiency","trade"],prompt:"The main port's chronic congestion costs the economy billions in demurrage and delay, but fixing it means automating operations and breaking the entrenched labour and handling syndicates that profit from the chaos. The director asks whether to take them on.",left:{id:"a",label:"Modernise the port, break the syndicates.",tooltip:"A clogged port is a tax on every import and export.",reveal:"You automate the port and break the handling syndicates. The demurrage bill plummets and trade speeds up, and the displaced syndicate bosses and their political patrons declare war.",effects:{FI:5,GL:3,EN:2,FA:-6}},right:{id:"b",label:"Leave the port and its syndicates be.",tooltip:"A port shutdown over reform would cripple the economy.",reveal:"You avoid the fight with the port syndicates. The congestion and demurrage grind on as a permanent drag, and the economy quietly pays the syndicates' toll on every container.",effects:{FA:2,FI:-6,GL:-3}}},{id:"finance-0123",location:"finance",arc:"finance-t0-a115",stage:0,speaker:"Digital Finance Adviser",portrait:"people",tags:["digital-payments","cash","transparency"],prompt:"The economy runs on untraceable cash, fuelling tax evasion and graft. A hard push toward digital payments — incentives, merchant mandates, interoperability — would widen the tax net and cut corruption, but it sidelines the cash-poor and the elderly and threatens the informal traders.",left:{id:"a",label:"Drive the shift to digital payments.",tooltip:"Cash in the dark is where taxes go to die.",reveal:"You push hard for digital payments and the tax net widens as cash retreats. Corruption gets harder to hide, and the cash-poor and elderly struggle, needing support to keep up.",effects:{FI:5,EN:2,GL:2}},right:{id:"b",label:"Let cash and digital coexist gently.",tooltip:"A nation forced cashless overnight abandons its poorest.",reveal:"You let the transition come gradually. No one is left stranded by a sudden cashless push, but the untraceable cash economy keeps shielding the evaders and the grafters.",effects:{EN:2,FI:-3}}},{id:"finance-0124",location:"finance",arc:"finance-t0-a116",stage:0,speaker:"Telecom Finance Director",portrait:"ambassador",tags:["spectrum","auction","revenue"],prompt:"New mobile spectrum is up for auction. You can set a punishing reserve price to milk the operators for maximum one-time revenue, or price it to spur cheap, fast data and broad coverage that grows the digital economy for years.",left:{id:"a",label:"Maximise the auction revenue.",tooltip:"Spectrum is a one-time treasure; sell it dear.",reveal:"You squeeze the operators for a record auction haul. The treasury banks a windfall, and the operators, recouping it, keep data dear and coverage thin for years to come.",effects:{FI:6,EN:-6,RE:-3}},right:{id:"b",label:"Price spectrum for cheap, wide data.",tooltip:"Cheap data grows more than a one-time cheque.",reveal:"You price the spectrum to spur coverage and affordable data. The one-time haul is smaller, but cheap fast internet spreads, and the digital economy it feeds pays back for years.",effects:{EN:5,GL:2,FI:-6}}},{id:"finance-0125",location:"finance",arc:"finance-t0-a117",stage:0,speaker:"Aviation Finance Secretary",portrait:"fixer",tags:["airline","losses","soe"],prompt:"The national airline bleeds money on padded leasing deals, overstaffing, and graft, kept aloft for prestige and patronage. The secretary can force a painful restructuring or privatisation, or keep subsidising the flag in the sky.",left:{id:"a",label:"Restructure or privatise the airline.",tooltip:"A flag that flies on subsidy flies on borrowed time.",reveal:"You force the restructuring, cutting the padded leases and the overstaffing. The unions and the brokers who profited rage, but the airline stops being a bottomless drain on the treasury.",effects:{FI:6,GL:2,EN:-10,FA:-6}},right:{id:"b",label:"Keep subsidising the flag carrier.",tooltip:"A nation's airline is a nation's face.",reveal:"You keep the airline aloft on subsidy. The flag flies and the patronage flows, and the padded deals and graft keep the losses mounting flight after flight.",effects:{FA:3,FI:-10,EN:-3}}},{id:"finance-0126",location:"finance",arc:"finance-t0-a118",stage:0,speaker:"Fiscal Climate Adviser",portrait:"official",tags:["carbon-tax","climate","revenue"],prompt:"A modest carbon levy on fuels and heavy industry would raise revenue and nudge the economy greener, and play well with climate donors. It would also raise costs across the board and hit the industries and consumers already squeezed by inflation.",left:{id:"a",label:"Introduce the carbon levy.",tooltip:"The polluter should pay, and the treasury should collect.",reveal:"You bring in a carbon levy. Revenue rises, the economy nudges greener, and the climate donors approve, while industry and consumers feel one more cost in an already pinched year.",effects:{FI:3,EN:3,GL:3,RE:2}},right:{id:"b",label:"Hold off on the carbon tax.",tooltip:"A new fuel levy amid inflation is a riot ordered in advance.",reveal:"You shelve the carbon tax. Industry and consumers are spared another cost, and the revenue, the green nudge, and the donor goodwill all go uncollected.",effects:{FI:-3,EN:-3,GL:-3}}},{id:"finance-0127",location:"finance",arc:"finance-t0-a119",stage:0,speaker:"Revenue Board Chairman",portrait:"shadow",tags:["capital-gains","stock-market","elite"],prompt:"Large stock-market gains go almost entirely untaxed, a quiet gift to the wealthy and the manipulators. A capital-gains tax would be fair and raise real revenue — and the big investors and brokers, well-connected, warn it will crash the market in protest.",left:{id:"a",label:"Tax large capital gains.",tooltip:"A fortune made on the bourse should pay like any other.",reveal:"You tax the big market gains. Revenue rises and fairness with it, the small investor is spared, and the big players stage a noisy sell-off and lean on every connection they have.",effects:{FI:5,EN:3,FA:-6}},right:{id:"b",label:"Leave market gains untaxed.",tooltip:"A capital-gains tax could spook the whole bourse.",reveal:"You leave the gains untaxed to keep the market calm. The wealthy and the manipulators keep their tax-free windfalls, and the revenue and the fairness go uncollected.",effects:{FA:2,FI:-6,EN:-3}}},{id:"finance-0128",location:"finance",arc:"finance-t0-a120",stage:0,speaker:"External Finance Secretary",portrait:"ambassador",tags:["imf","transparency","data"],prompt:"The IMF's annual review will publish a candid assessment of the economy — the real reserves, the hidden debts, the bad loans. You can cooperate fully and let the unflattering truth out, or pressure for a softened report that protects the rosy official narrative.",left:{id:"a",label:"Cooperate fully with a candid review.",tooltip:"A diagnosis softened is a disease untreated.",reveal:"You let the IMF publish the unvarnished assessment. The numbers sting and the opposition feasts, but the lenders and markets reward the transparency, and the problems can finally be named.",effects:{GL:5,FI:-3,EN:-3}},right:{id:"b",label:"Pressure for a softened report.",tooltip:"An honest report is a headline against me.",reveal:"You lean on the mission for a gentler write-up. The official narrative survives intact, the markets are soothed by a number that is not quite real, and the IMF's quiet doubts deepen.",effects:{FI:2,GL:-10}}},{id:"finance-0129",location:"finance",arc:"finance-t0-a121",stage:0,speaker:"Industrial Safety Secretary",portrait:"people",tags:["garments","safety","factories"],prompt:"After a catastrophic factory collapse, a binding international safety accord requires costly retrofits — fire exits, structural fixes — that the buyers demand and the owners resist. The secretary asks whether to enforce the accord fully or help owners dodge it.",left:{id:"a",label:"Enforce the safety accord fully.",tooltip:"A factory that buries its workers is no asset.",reveal:"You enforce the retrofits hard, factory by factory. The owners howl at the cost and a few lines close, but the death-trap buildings are fixed and the buyers keep their orders.",effects:{EN:8,GL:5,FI:-6,FA:-6}},right:{id:"b",label:"Help owners dodge the costly retrofits.",tooltip:"Protect the owners who keep a million employed.",reveal:"You help the owners paper over the accord. The retrofits go undone, the lines stay cheap, and the next fire or collapse is already being built into a building no one fixed.",effects:{FI:3,FA:3,EN:-16,GL:-10}}},{id:"finance-0130",location:"finance",arc:"finance-t0-a122",stage:0,speaker:"Tariff Commission Chief",portrait:"official",tags:["machinery","duty","industry"],prompt:"Industrialists want all imported capital machinery to come in duty-free to spur investment and modernisation. It would genuinely help manufacturers re-tool — and it is also a famous loophole for importing finished goods disguised as 'machinery' to dodge duty entirely.",left:{id:"a",label:"Grant broad duty-free machinery imports.",tooltip:"Cheap machines build modern factories.",reveal:"You open the duty-free channel wide. Genuine manufacturers re-tool cheaply, and the disguised-import racket revives alongside, smuggling finished goods in under the machinery label.",effects:{FI:-3,EN:3,RE:2}},right:{id:"b",label:"Allow it narrowly with tight verification.",tooltip:"A loophole for machines becomes a loophole for everything.",reveal:"You permit duty-free machinery only with strict end-use verification. The honest manufacturers grumble at the paperwork, but the disguised-import loophole stays shut and the duty is protected.",effects:{FI:3,EN:2,FA:-3}}},{id:"finance-0131",location:"finance",arc:"finance-t0-a123",stage:0,speaker:"ICT Investment Director",portrait:"official",tags:["it","hi-tech-park","jobs"],prompt:"A flagship hi-tech park could anchor a software and electronics industry and tens of thousands of skilled jobs — if it gets real power, connectivity, and tenants. Too many such parks have become empty monuments. The director asks whether to commit fully or modestly.",left:{id:"a",label:"Commit fully to the hi-tech park.",tooltip:"The future's factories are made of code.",reveal:"You back the park with reliable power, fibre, and incentives, and court real anchor tenants. The cost is high and the bet uncertain, but a genuine tech cluster and its skilled jobs begin to form.",effects:{EN:5,FI:-10,GL:2,RE:2}},right:{id:"b",label:"Build it modestly and hope.",tooltip:"A grand park half-empty is a grand embarrassment.",reveal:"You build a modest version and hope tenants come. The cost is contained, but without serious infrastructure and incentives the park risks joining the country's collection of hollow monuments.",effects:{FI:-3,EN:2}}},{id:"finance-0132",location:"finance",arc:"finance-t0-a124",stage:0,speaker:"SME Finance Director",portrait:"people",tags:["women","entrepreneurs","credit"],prompt:"Women entrepreneurs are almost entirely locked out of formal credit by collateral demands and bias. A dedicated, lightly-collateralised fund would unleash a wave of women-led small businesses — at higher default risk and the grumbling of bankers who call it charity.",left:{id:"a",label:"Launch the women-entrepreneur credit fund.",tooltip:"Half the talent locked out is half the economy lost.",reveal:"You build the dedicated fund. Default risk runs higher and the bankers grumble, but a wave of women-led businesses opens, and a vast pool of stifled enterprise finally finds capital.",effects:{EN:6,FI:-6,GL:2}},right:{id:"b",label:"Leave SME credit gender-blind.",tooltip:"Special funds breed special defaults.",reveal:"You keep credit 'neutral', which in practice means collateral-bound and male. The default risk stays low and the bankers content, and women entrepreneurs keep borrowing from family or not at all.",effects:{FI:2,EN:-6}}},{id:"finance-0133",location:"finance",arc:"finance-t0-a125",stage:0,speaker:"Planning Commission Member",portrait:"fixer",tags:["mp-fund","patronage","local"],prompt:"Each MP gets a large annual development fund to spend in their constituency — a patronage machine that builds loyalty and, often, the MP's own house and friends' contracts. The member asks whether to keep the fund or route the money through audited local government.",left:{id:"a",label:"Keep the MP development funds.",tooltip:"An MP without a chequebook is an MP without friends.",reveal:"You keep the funds flowing to the MPs. They build loyalty and the occasional genuine road, and skim and steer the rest to their own contractors and kin, audited by no one.",effects:{FA:5,MI:2,EN:-10,FI:-3}},right:{id:"b",label:"Route the money through local government.",tooltip:"Development should follow a plan, not a member's whim.",reveal:"You move the money to audited local councils. The MPs lose a treasured lever and seethe, but the development spreads by need and plan rather than by the member's favour.",effects:{EN:6,GL:3,FA:-10}}},{id:"finance-0134",location:"finance",arc:"finance-t0-a126",stage:0,speaker:"External Finance Secretary",portrait:"ambassador",tags:["rating","markets","reform"],prompt:"The credit-rating agencies will downgrade the country unless you show real fiscal reform — but the reforms (subsidy cuts, tax rises) are politically toxic. A downgrade raises every future borrowing cost; ignoring it keeps the politics easy and the future dear.",left:{id:"a",label:"Reform to protect the rating.",tooltip:"A downgrade taxes every loan for a decade.",reveal:"You enact the painful reforms and stave off the downgrade. The public feels the squeeze and grumbles, but the rating holds and the country's future borrowing stays affordable.",effects:{GL:3,FI:3,EN:-13}},right:{id:"b",label:"Ignore the agencies, keep the politics easy.",tooltip:"I will not cut subsidies to please a foreign rating.",reveal:"You spare the public the reforms and take the downgrade. The politics stay calm now, and every loan the country raises henceforth carries a higher price for the rating you let slip.",effects:{EN:3,FI:-10,GL:-6}}},{id:"finance-0135",location:"finance",arc:"finance-t0-a127",stage:0,speaker:"Budget Secretary",portrait:"fixer",tags:["allowance","veterans","spending"],prompt:"The freedom-fighter honour allowance is being expanded again, with the rolls swelling implausibly as the genuine veterans age and 'new' ones appear with forged certificates. The secretary can audit and clean the rolls, angering a sacred constituency, or keep paying all comers.",left:{id:"a",label:"Audit and clean the veteran rolls.",tooltip:"A forged certificate dishonours the real heroes.",reveal:"You audit the rolls and strip out the forgeries. The genuine veterans are honoured and the fraud purged, and the cleansing of a sacred list draws furious accusations of disrespect.",effects:{FI:3,GL:2,EN:2,FA:-6}},right:{id:"b",label:"Keep paying the swollen rolls.",tooltip:"I will not be the one to question a freedom-fighter's claim.",reveal:"You leave the rolls untouched. The genuine and the forged draw the honour allowance alike, the sacred constituency stays placated, and the fraud quietly bloats the budget line.",effects:{FA:5,FI:-6,EN:-3}}},{id:"finance-0136",location:"finance",arc:"finance-t0-a128",stage:0,speaker:"Transport Economy Adviser",portrait:"people",tags:["gig-economy","ride-share","workers"],prompt:"Ride-share and delivery apps have created work for hundreds of thousands of young people — and stripped them of any protection, pay floor, or benefits. The adviser wants to regulate the platforms with minimum earnings and insurance; the apps and the cheap-fare public resist.",left:{id:"a",label:"Regulate the gig platforms.",tooltip:"A job with no floor is a trap with an app.",reveal:"You impose minimum earnings, insurance, and dispute rights on the platforms. Fares rise a little and the apps threaten to scale back, but a precarious workforce gains a measure of security.",effects:{EN:6,FI:-3,GL:2}},right:{id:"b",label:"Leave the gig economy unregulated.",tooltip:"Cheap rides and easy work are their own reward.",reveal:"You leave the platforms free. Fares stay low and the apps expand, and the young riders and drivers keep working without a floor, a benefit, or a safety net beneath them.",effects:{FI:2,EN:-10}}},{id:"finance-0137",location:"finance",arc:"finance-t0-a129",stage:0,speaker:"Commerce Envoy",portrait:"ambassador",tags:["fta","regional","trade"],prompt:"A regional free-trade agreement would open big neighbouring markets to your exports — and open your own market to a flood of their cheaper goods that could swamp domestic industry. The envoy asks whether to sign the deal or protect the home market.",left:{id:"a",label:"Sign the regional free-trade deal.",tooltip:"A market opened both ways favours the competitive.",reveal:"You sign the FTA and your exporters gain access to vast new markets. Some domestic industries, undercut by cheaper imports, buckle and shed jobs, and the adjustment is wrenching.",effects:{GL:5,FI:2,EN:-6}},right:{id:"b",label:"Protect the home market.",tooltip:"Free trade with a giant is a flood with a treaty.",reveal:"You decline the deal to shield domestic industry. The home producers are protected and the jobs held, but your exporters lose the access, and the integration the region is moving toward leaves you behind.",effects:{EN:2,FI:-3,GL:-6}}},{id:"finance-0138",location:"finance",arc:"finance-t0-a130",stage:0,speaker:"Revenue Board Chairman",portrait:"people",tags:["stamp-duty","property","informality"],prompt:"Property-transfer stamp duty is so high that almost everyone under-declares the sale price, fuelling black money and starving the treasury. Cutting the rate would boost honest declarations and the property market; the hawks fear the short-term revenue dip.",left:{id:"a",label:"Cut the stamp duty to boost compliance.",tooltip:"A rate too high is a rate evaded.",reveal:"You slash the stamp duty. Declarations jump toward honesty, the property market quickens, and after a brief dip the revenue actually rises as the under-declaration racket collapses.",effects:{FI:3,EN:3,GL:2}},right:{id:"b",label:"Keep the high stamp duty.",tooltip:"A rate cut is a revenue cut I cannot risk now.",reveal:"You keep the duty high. The headline rate looks lucrative, and the universal under-declaration keeps fuelling black money while the treasury collects on fictional sale prices.",effects:{FI:-3,EN:-3}}},{id:"finance-0139",location:"finance",arc:"finance-t0-a131",stage:0,speaker:"Industries Secretary",portrait:"people",tags:["sme","manufacturing","cluster"],prompt:"A gritty cluster of small workshops makes the spare parts and machines that keep industry and agriculture running — undercapitalised, unregulated, and ignored. A support push of credit, training, and standards could turn it into a real manufacturing base, or you can keep chasing flashier prizes.",left:{id:"a",label:"Invest in the light-engineering cluster.",tooltip:"A nation that makes its own parts depends on no one's.",reveal:"You back the workshops with credit, training, and standards. The transformation is slow and unglamorous, but an import-substituting manufacturing base — and skilled jobs — takes root.",effects:{EN:5,FI:-6,RE:2}},right:{id:"b",label:"Chase the flashier industrial prizes.",tooltip:"Workshops do not make headlines.",reveal:"You steer support to glossier projects instead. The flagship announcements dazzle, and the unsung workshops that actually keep industry running stay starved and stuck.",effects:{GL:2,FI:-3,EN:-3}}},{id:"finance-0140",location:"finance",arc:"finance-t0-a132",stage:0,speaker:"External Finance Secretary",portrait:"ambassador",tags:["adb","loan","megaproject"],prompt:"A development bank offers a large soft loan for a flagship transport corridor — cheaper than markets, but with rigorous procurement and environmental conditions that will slow the build and block the cost-padding your contractors expect.",left:{id:"a",label:"Take the loan with all its conditions.",tooltip:"Cheap money and clean procurement together.",reveal:"You take the soft loan and accept the rigorous conditions. The build is slower and the contractors are denied their padding, but the corridor is cheaply financed and honestly built.",effects:{FI:3,GL:3,EN:2,FA:-6}},right:{id:"b",label:"Fund it your own way, conditions-free.",tooltip:"I will not let a bank's auditors run my project.",reveal:"You skip the conditional loan and finance it domestically. The contractors get their padding and the speed they want, and the project costs more, runs dirtier, and strains the budget.",effects:{FA:3,FI:-10,EN:-3}}},{id:"finance-0141",location:"finance",arc:"finance-t0-a133",stage:0,speaker:"Central Bank Governor",portrait:"shadow",tags:["currency","high-note","black-money"],prompt:"Introducing a new high-denomination note would ease the bulk of large cash transactions — convenient, and a famous enabler of hoarding, bribery, and black money. The governor asks whether to print it or hold the line on the largest note.",left:{id:"a",label:"Introduce the high-denomination note.",tooltip:"A bigger note is a smaller suitcase.",reveal:"You print the big note. Large cash deals get easier for everyone, including the hoarders, bribers, and launderers who can now move fortunes in a slim envelope.",effects:{FI:2,EN:-6,GL:-3}},right:{id:"b",label:"Hold the line on the largest note.",tooltip:"A big note is a bribe's best friend.",reveal:"You refuse the high-denomination note. Large cash deals stay bulky and a little harder to hide, a small friction against the corruption that thrives on portable wealth.",effects:{GL:2,EN:2}}},{id:"finance-0142",location:"finance",arc:"finance-t0-a134",stage:0,speaker:"Urban Economy Officer",portrait:"people",tags:["vendors","informal","licensing"],prompt:"The cities run on hundreds of thousands of street vendors who block footpaths, pay daily bribes to police and mastans, and have no legal standing. The officer can formalise them with licences and designated zones, or keep clearing them in periodic, futile drives.",left:{id:"a",label:"Formalise and license the vendors.",tooltip:"A hawker licensed is a hawker freed from the mastan.",reveal:"You license the vendors and assign them zones. The police and mastans lose their daily extortion and resent it, but the vendors gain legal standing and the footpaths get some order.",effects:{EN:6,FI:2,MI:-3,FA:-3}},right:{id:"b",label:"Keep clearing them in periodic drives.",tooltip:"The footpaths belong to the pedestrian.",reveal:"You keep mounting eviction drives that scatter the vendors for a day before they return. The bribes keep flowing to police and mastans, and nothing actually changes but the optics.",effects:{MI:2,FI:-3,EN:-10}}},{id:"finance-0143",location:"finance",arc:"finance-t0-a135",stage:0,speaker:"Railway Finance Secretary",portrait:"people",tags:["railway","losses","subsidy"],prompt:"The state railway loses money on every ticket — cheap fares, overstaffing, ticketless travel, and graft — yet it is the lifeline of the poor. The secretary can hike fares and cut staff to stem the losses, or keep the cheap, bleeding service running.",left:{id:"a",label:"Reform fares and staffing.",tooltip:"A railway that bankrupts itself serves no one long.",reveal:"You raise fares, curb the ticketless, and trim the bloat. The losses narrow and the service steadies, but the poor who depend on cheap travel feel the pinch and the unions strike.",effects:{FI:5,EN:-10,FA:-3}},right:{id:"b",label:"Keep the cheap service bleeding.",tooltip:"The train is the poor man's only affordable distance.",reveal:"You keep fares low and the trains rolling at a loss. The poor keep their cheap lifeline, and the railway keeps draining the budget, its graft and overstaffing untouched.",effects:{EN:5,FI:-10}}},{id:"finance-0144",location:"finance",arc:"finance-t0-a136",stage:0,speaker:"Industries Secretary",portrait:"doctor",tags:["pharma","api","self-reliance"],prompt:"The proud pharmaceutical industry imports nearly all its active ingredients, leaving it hostage to foreign supply. A dedicated API park would build self-reliance and a high-value export edge — a costly, slow industrial bet versus simply importing as before.",left:{id:"a",label:"Build the pharmaceutical API park.",tooltip:"An industry that imports its core imports its fate.",reveal:"You commit to the API park. The investment is heavy and the payoff years away, but the pharma industry begins to make its own ingredients and an export edge sharpens.",effects:{FI:-6,EN:3,GL:2,RE:2}},right:{id:"b",label:"Keep importing the active ingredients.",tooltip:"Why build what I can buy?",reveal:"You keep relying on imported ingredients. The capital is saved, and the industry stays one foreign supply-shock away from a shortage of the medicines the country and its exports depend on.",effects:{FI:2,EN:-3,GL:-3}}},{id:"finance-0145",location:"finance",arc:"finance-t0-a137",stage:0,speaker:"Revenue Board Chairman",portrait:"people",tags:["sim-tax","internet","access"],prompt:"Taxes on SIM cards, handsets, and data are an easy, lucrative revenue stream — and a regressive tax on the very connectivity that drives the digital economy and reaches the rural poor. The chairman asks whether to raise these taxes or cut them.",left:{id:"a",label:"Raise the SIM and data taxes.",tooltip:"A connected nation can spare a few taka per gigabyte.",reveal:"You raise the connectivity taxes and the revenue flows easily. Data and phones get dearer, the rural poor and the digital economy both feel it, and a regressive levy deepens.",effects:{FI:5,EN:-10}},right:{id:"b",label:"Cut the regressive connectivity taxes.",tooltip:"A tax on data is a tax on the future.",reveal:"You cut the SIM and data taxes. The easy revenue is forgone, but cheaper connectivity spreads to the rural poor and feeds the digital economy that pays back many times over.",effects:{EN:5,GL:2,FI:-6}}},{id:"finance-0146",location:"finance",arc:"finance-t0-a138",stage:0,speaker:"Cottage Industry Director",portrait:"people",tags:["handloom","heritage","artisans"],prompt:"The famed handloom weavers and artisans — keepers of a heritage craft — are being wiped out by cheap power-loom imitations and debt. A revival of credit, design support, and a protected 'heritage' label could save them, or you can let the market take its course.",left:{id:"a",label:"Fund the handloom revival.",tooltip:"A craft lost is a heritage no money rebuilds.",reveal:"You back the weavers with credit, design, and a protected heritage label. The cost is modest and the market still hard, but a dying craft and the communities who keep it get a fighting chance.",effects:{EN:5,GL:2,FI:-6}},right:{id:"b",label:"Let the market take its course.",tooltip:"Nostalgia cannot outcompete a power loom.",reveal:"You let the handloom communities fend for themselves. The cheaper power-loom goods win, the looms fall silent one village at a time, and a centuries-old craft fades toward memory.",effects:{FI:2,EN:-6}}},{id:"finance-0147",location:"finance",arc:"finance-t0-a139",stage:0,speaker:"Export Zone Authority Chief",portrait:"people",tags:["epz","wages","investment"],prompt:"The export-processing zones, your showcase for foreign investors, run on a wage floor lower than the national minimum and a ban on unions. Raising the EPZ wage and allowing unions would be just — and might spook the investors the zones were built to attract.",left:{id:"a",label:"Raise EPZ wages and allow unions.",tooltip:"A showcase built on suppressed wages shames the show.",reveal:"You lift the EPZ wage and permit unions. Some investors grumble and threaten to look elsewhere, but the zone workers gain dignity and pay, and the showcase stops being a sweatshop with landscaping.",effects:{EN:6,GL:3,FI:-6,FA:-3}},right:{id:"b",label:"Keep the EPZ wages low and unions banned.",tooltip:"The investors came for the cheap, calm labour.",reveal:"You keep the zones cheap and union-free. The investors stay content and the FDI flows, and the zone workers keep earning below the national floor with no voice to change it.",effects:{FI:5,FA:2,EN:-13,GL:-3}}},{id:"finance-0148",location:"finance",arc:"finance-t0-a140",stage:0,speaker:"Revenue Board Chairman",portrait:"people",tags:["advance-tax","compliance","burden"],prompt:"The web of advance and source taxes deducted on imports, utilities, and transactions has become a hidden, regressive burden — easy to collect, but falling on businesses and consumers regardless of actual profit, and impossible for the small to reclaim. The chairman asks whether to rationalise it.",left:{id:"a",label:"Rationalise the advance-tax web.",tooltip:"A tax collected before profit is a tax on existence.",reveal:"You prune the tangle of advance taxes. Collection gets a little harder and revenue dips short-term, but the hidden burden on the small and the consumer eases and the system grows fairer.",effects:{EN:5,GL:2,FI:-6}},right:{id:"b",label:"Keep the easy advance-tax collection.",tooltip:"A tax collected at source is a tax that does not escape.",reveal:"You keep the advance-tax web intact. Collection stays easy and leak-proof, and the hidden, regressive burden goes on falling hardest on those least able to reclaim it.",effects:{FI:3,EN:-6}}},{id:"finance-0149",location:"finance",arc:"finance-t0-a141",stage:0,speaker:"Budget Secretary",portrait:"fixer",tags:["budget","deficit","populism"],prompt:"Election year, and the cabinet wants the largest budget in history — a blizzard of new schemes, subsidies, and giveaways — funded by optimistic revenue forecasts and borrowing. The secretary warns the numbers do not add up; the politics says they do not have to.",left:{id:"a",label:"Unveil the record populist budget.",tooltip:"A budget is a promise, and promises win votes.",reveal:"You unveil the record-shattering budget to fanfare. The schemes dazzle and the votes warm, and the fantastical revenue forecasts collapse within months, forcing painful cuts you will own.",effects:{EN:5,FI:-13,GL:-6}},right:{id:"b",label:"Present a sober, credible budget.",tooltip:"A budget built on fantasy is a crisis with a launch date.",reveal:"You table a realistic budget the numbers actually support. The cabinet grumbles that it lacks fireworks for the campaign, but the lenders trust it and no mid-year reckoning lies in wait.",effects:{GL:5,FI:3,EN:-3}}},{id:"finance-0150",location:"finance",arc:"finance-t0-a141",stage:1,speaker:"Budget Secretary",portrait:"fixer",tags:["budget","deficit","populism"],prompt:"The budget is passed, and now the chronic gap between the grand announcements and the money actually disbursed yawns wide — schemes launched with fanfare sit unfunded and half-built. The secretary asks whether to chase headline announcements or quietly fund what was already promised.",left:{id:"a",label:"Announce yet more new schemes.",tooltip:"A ribbon cut is worth more than a road finished.",reveal:"You keep launching glittering new schemes over the unfinished ones. The headlines flow, the backlog of half-built promises grows, and the public learns that an announcement here rarely becomes a thing.",effects:{FA:2,EN:-10,FI:-3}},right:{id:"b",label:"Fund and finish what was promised.",tooltip:"A promise kept quietly beats ten announced loudly.",reveal:"You stop the announcement treadmill and fund the existing commitments to completion. There are fewer ribbons to cut, but the schools, roads, and clinics already promised actually get built.",effects:{EN:6,GL:2,FI:-6}}},{id:"finance-0151",location:"finance",arc:"finance-t1-a0",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["reserves","forex","imf"],prompt:'A term later, the same fault line tears open again. The Governor lays the reserves chart on your desk — a line sliding toward three months of imports. "We have been counting money we do not have as reserves. The real number is worse, and the IMF will see through the trick at the next review."',left:{id:"a",label:"Keep publishing the flattering number.",tooltip:"Confidence is a currency too.",reveal:"The headline reserves look calm; importers and rating agencies quietly stop believing you, and the black-market dollar climbs.",effects:{FI:3,GL:-13,EN:-6}},right:{id:"b",label:"Publish the true, lower figure.",tooltip:"A lie in the books is a run waiting to happen.",reveal:"The honesty stings the markets for a week, then steadies them. The IMF, reassured by candour, eases the next tranche.",effects:{FI:-10,GL:8,MI:-6}}},{id:"finance-0152",location:"finance",arc:"finance-t1-a0",stage:1,speaker:"Central Bank Governor",portrait:"official",tags:["reserves","forex","imf"],prompt:"Years into your rule, the matter you thought buried resurfaces — harder. To defend the taka you have been burning reserves to hold the peg. The Governor says you can either let the currency float and watch prices leap, or keep bleeding dollars to defend a number you cannot hold.",left:{id:"a",label:"Float the taka.",tooltip:"Better a fair price than an empty vault.",reveal:"The taka drops; exporters and remitters cheer while every imported good — fuel, food, medicine — jumps overnight. The streets feel it instantly.",effects:{FI:6,GL:5,EN:-18}},right:{id:"b",label:"Keep defending the peg.",tooltip:"A cliff-edge devaluation would break the poor.",reveal:"You hold the line a while longer at the cost of the vault. The reserves thin toward the danger mark and the market sniffs the weakness.",effects:{FI:-16,EN:5,GL:-6}}},{id:"finance-0153",location:"finance",arc:"finance-t1-a0",stage:2,speaker:"Central Bank Governor",portrait:"official",tags:["reserves","forex","imf"],prompt:"A new season of power, an old problem with sharper teeth. Reserves hit the red line. The IMF will release an emergency tranche — but only if you cut energy subsidies the same week. Your advisors warn that the price shock could put people on the streets within days.",left:{id:"a",label:"Take the tranche, cut the subsidies.",tooltip:"Solvency now, anger managed later.",reveal:"Dollars refill the vault as fuel and power prices spike. The crisis on the balance sheet becomes a crisis in the bazaars.",effects:{FI:10,GL:6,EN:-18,MI:-6}},right:{id:"b",label:"Refuse the conditions, seek bilateral loans.",tooltip:"I will not detonate prices on a foreign schedule.",reveal:"You borrow from friendly capitals instead — costlier, with strings of their own. The subsidy holds; the debt stack grows more dangerous.",effects:{FI:3,GL:-6,EN:5,RE:-6}}},{id:"finance-0154",location:"finance",arc:"finance-t1-a1",stage:0,speaker:"Bank Reform Commissioner",portrait:"official",tags:["banks","default-loans","cronies"],prompt:`The crisis returns, and this time the cabinet is watching. The Commissioner names the rot: a handful of business families have looted the banks through ever-rolled 'rescheduled' loans, and several of them fund your campaigns. "Classify the bad loans honestly and the banks look insolvent. Hide them and they rot from inside."`,left:{id:"a",label:"Keep rescheduling the cronies' loans.",tooltip:"These men keep the party funded.",reveal:"The books stay pretty and the donors stay loyal. The hole grows in the dark, and one bank's collapse could pull down the rest.",effects:{FI:5,FA:3,GL:-13,EN:-6}},right:{id:"b",label:"Force honest classification and recovery.",tooltip:"A looted bank is a tax on every saver.",reveal:"You name the defaulters and freeze their rolling. The donors revolt and the books look grim — but depositors, and the IMF, exhale.",effects:{FI:-13,GL:8,MI:-6,FA:-10}}},{id:"finance-0155",location:"finance",arc:"finance-t1-a1",stage:1,speaker:"Bank Reform Commissioner",portrait:"official",tags:["banks","default-loans","cronies"],prompt:"Once more the issue lands on your desk, the stakes higher than before. Your honest-classification drive has cornered the country's biggest loan defaulter — who happens to own three TV channels and a slice of your party's purse. He offers a deal: a partial repayment and his media's undying loyalty, if you call off the rest.",left:{id:"a",label:"Take the partial deal and the loyalty.",tooltip:"Half a recovery and a friendly press is no small thing.",reveal:"He repays a fraction and his channels glow for you. Every other defaulter learns the price of getting caught is merely negotiable.",effects:{FI:3,FA:5,GL:-10,MI:3}},right:{id:"b",label:"Pursue full recovery, channels be damned.",tooltip:"The law cannot have a discount for the loud.",reveal:"You break him publicly. His networks turn on you nightly — but the message lands that the era of free money is over.",effects:{FI:6,GL:5,FA:-13,MI:-10}}},{id:"finance-0156",location:"finance",arc:"finance-t1-a2",stage:0,speaker:"Expatriate Welfare Secretary",portrait:"official",tags:["remittances","hundi","diaspora"],prompt:"Another year survived, and the reckoning circles back. Migrant workers are sending their money home through the illegal hundi network instead of the banks, because hundi gives a better rate and asks no questions. Billions of dollars bypass the reserves entirely. The Secretary wants a 2.5% cash incentive to lure them back.",left:{id:"a",label:"Pay the incentive on legal remittances.",tooltip:"Buy the dollars back into the system.",reveal:"Formal inflows jump and the reserves breathe — at a real fiscal cost, and with smugglers adapting their margins fast.",effects:{FI:6,EN:3,GL:3}},right:{id:"b",label:"Crack down on hundi operators instead.",tooltip:"Punish the channel, not subsidise the rival.",reveal:"Raids disrupt the networks briefly. The operators reroute through crypto and gold; workers, harassed, trust the banks even less.",effects:{FI:-6,MI:5,GL:-6}}},{id:"finance-0157",location:"finance",arc:"finance-t1-a3",stage:0,speaker:"Garment Buyers' Consortium",portrait:"official",tags:["rmg","exports","wages"],prompt:"The ground has shifted; the same demand arrives with new menace. The Western buyers' consortium that takes most of your garments delivers an ultimatum dressed as concern: raise the minimum wage and improve safety, or they shift orders to cheaper rivals. Your factory owners say a wage hike will close mills.",left:{id:"a",label:"Mandate the wage rise the buyers want.",tooltip:"Cheap labour is a race we lose anyway.",reveal:"Wages rise; the buyers stay and the workers quiet. Marginal factories shutter, and the owners — your donors — are furious.",effects:{GL:6,EN:6,FI:-13,FA:-6}},right:{id:"b",label:"Protect the owners, keep wages flat.",tooltip:"Mills closed help no worker at all.",reveal:"The owners are grateful and the lines keep running. Some buyers quietly diversify away, and the wage protests build.",effects:{FI:6,FA:5,EN:-16,GL:-10}}},{id:"finance-0158",location:"finance",arc:"finance-t1-a4",stage:0,speaker:"Megaproject Coordinator",portrait:"official",tags:["debt","infrastructure","china"],prompt:"History rhymes: the conflict reopens deeper than last time. The grand projects — bridges, rail, power plants — are monuments and millstones both. A coordinator warns that the foreign loans behind them balloon next year, and one lender wants port-equity collateral if you cannot pay on time.",left:{id:"a",label:"Offer port equity to roll the debt.",tooltip:"Keep the cranes turning at any cost.",reveal:"The repayment is rescheduled and construction continues. A strategic port is now partly mortgaged to a foreign creditor.",effects:{FI:5,RE:-10,GL:-13,MI:-6}},right:{id:"b",label:"Pause new projects and prioritise repayment.",tooltip:"No more monuments we cannot afford.",reveal:"You freeze the ribbon-cuttings to service the debt. The optics dull and contractors grumble, but the balance sheet stops bleeding.",effects:{FI:6,GL:3,EN:-6,FA:-6}}},{id:"finance-0159",location:"finance",arc:"finance-t1-a5",stage:0,speaker:"Financial Intelligence Chief",portrait:"official",tags:["laundering","capital-flight","elite"],prompt:'Mid-reign, the old wound is torn afresh. The FIU chief shows you the outflows: the same elite that complains about the dollar shortage is quietly wiring fortunes into second homes abroad. "They starve the reserves they then blame you for. I can name them — many are friends."',left:{id:"a",label:"Bury the report to protect the names.",tooltip:"These are the people who hold the regime up.",reveal:"The list disappears and the friends stay close. The reserves keep leaking out the back door you chose not to lock.",effects:{FI:-10,FA:5,GL:-10}},right:{id:"b",label:"Publish it and freeze the worst offenders.",tooltip:"Patriotism that flees with the money is none.",reveal:"You name and freeze. The elite is enraged and the courts will be slow — but capital flight stutters and the public roars approval.",effects:{FI:6,EN:5,GL:5,FA:-13}}},{id:"finance-0160",location:"finance",arc:"finance-t1-a6",stage:0,speaker:"Trade & Prices Adviser",portrait:"people",tags:["inflation","subsidies","food"],prompt:"The pressure you deferred has come due, larger now. Rice, oil, and onions have outrun wages and the kitchen is now a political battlefield. The adviser offers two levers: open emergency duty-free imports that hammer the budget, or hold the line and tell people to tighten belts they have already cinched.",left:{id:"a",label:"Flood the market with duty-free imports.",tooltip:"An empty plate topples governments faster than deficits.",reveal:"Prices ease at the bazaar and tempers cool. The deficit widens and local farmers, undercut, send their own anger upward.",effects:{EN:8,FI:-13,RE:-6}},right:{id:"b",label:"Hold firm and protect domestic farmers.",tooltip:"Cheap imports today, dead farms tomorrow.",reveal:"The farmers keep their margins and the budget holds. Urban households seethe as the kitchen stays expensive.",effects:{FI:5,RE:3,EN:-16,FA:-6}}},{id:"finance-0161",location:"finance",arc:"finance-t1-a7",stage:0,speaker:"Sovereign Ratings Analyst",portrait:"ambassador",tags:["rating","markets","confidence"],prompt:"A later term, and the quarrel has hardened into a test. A ratings agency is poised to downgrade you to junk, which would spike borrowing costs across the board. The analyst hints the decision could 'go either way' with the right gestures — fiscal transparency, or a quietly arranged hospitality.",left:{id:"a",label:"Arrange the quiet hospitality.",tooltip:"A friendly rating is cheaper than a downgrade.",reveal:"The downgrade is shelved this cycle. The fix is fragile and faintly corrupt; the next analyst may not be so amenable.",effects:{FI:5,GL:-10,EN:-6}},right:{id:"b",label:"Open the books and take the rating you earn.",tooltip:"I will not bribe my way out of arithmetic.",reveal:"You bare the fiscal accounts honestly. The downgrade may come, but investors who reward candour begin, cautiously, to return.",effects:{FI:-10,GL:6,MI:-3}}},{id:"finance-0162",location:"finance",arc:"finance-t1-a8",stage:0,speaker:"NBR Chairman",portrait:"official",tags:["tax","nbr","informal"],prompt:"The country has changed, but this fault line has not — only worsened. Barely 2% of the country files taxes; the chairman wants an aggressive drive to widen the net into the vast informal economy. The shopkeepers and traders who fund half your local committees are already calling.",left:{id:"a",label:"Push the tax-net drive hard.",tooltip:"A state cannot run on 2% of its people.",reveal:"Revenue creeps up and the IMF nods — while market associations declare a shutter-down strike against you.",effects:{FI:10,GL:5,EN:-13,FA:-6}},right:{id:"b",label:"Go gently, spare the traders.",tooltip:"Do not squeeze the people who keep me standing.",reveal:"The committees stay loyal and the books stay thin. The tax-to-GDP ratio remains among the lowest on earth.",effects:{FA:6,FI:-13,GL:-10}}},{id:"finance-0163",location:"finance",arc:"finance-t1-a9",stage:0,speaker:"Budget Adviser",portrait:"official",tags:["black-money","whitening","budget"],prompt:"It returns, as these things do, with the patience gone. The adviser proposes the familiar budget clause: let undisclosed 'black money' be whitened by paying a flat low tax, no questions asked. It would pull billions into the formal economy — and reward exactly the people who hid it.",left:{id:"a",label:"Keep the whitening window open.",tooltip:"Better the money home than abroad.",reveal:"Hidden fortunes surface and the deficit eases. Honest taxpayers fume that crime pays a lower rate than they do.",effects:{FI:10,EN:-13,GL:-10}},right:{id:"b",label:"Scrap the whitening scheme.",tooltip:"I will not legislate a discount for thieves.",reveal:"You close the loophole on principle. The flagged billions stay offshore, and the budget must find them elsewhere.",effects:{GL:5,EN:5,FI:-16}}},{id:"finance-0164",location:"finance",arc:"finance-t1-a10",stage:0,speaker:"Stock Exchange Chair",portrait:"official",tags:["dse","market","retail"],prompt:"Years on, the matter is no longer private; the press is already circling. The share index is in free-fall and small investors are burning effigies outside the exchange. The chair wants you to impose an artificial 'floor price' freezing shares from falling further.",left:{id:"a",label:"Impose the floor price.",tooltip:"Stop the bleeding on the screens.",reveal:"The index steadies on paper; trading dries up as no one will buy a price that cannot fall. Foreign funds flee the frozen market.",effects:{EN:5,FI:-10,GL:-13}},right:{id:"b",label:"Let the market clear and fund investor education.",tooltip:"A propped market is a trap with a delay.",reveal:"The index overshoots down, then finds a real bottom. The pain is sharp and the recovery, when it comes, is trusted.",effects:{GL:5,FI:3,EN:-13}}},{id:"finance-0165",location:"finance",arc:"finance-t1-a10",stage:1,speaker:"Stock Exchange Chair",portrait:"official",tags:["dse","market","retail"],prompt:"The same knot, retied tighter, lands before you once more. With the market cratered, a tycoon offers to 'rescue' it by buying en masse — if you hand his group a state bank and a telecom licence in return.",left:{id:"a",label:"Take the tycoon's rescue.",tooltip:"A white knight asks his price.",reveal:"Shares rally on his buying spree. You have sold public assets to paper over a market panic, and he now owns a piece of the state.",effects:{FI:6,EN:3,GL:-13,FA:3}},right:{id:"b",label:"Refuse and let a real recovery take its time.",tooltip:"I will not ransom the bourse to one man.",reveal:"The market mends slowly without a saviour. The tycoon turns his media against you for the snub.",effects:{GL:5,FI:-10,MI:-6}}},{id:"finance-0166",location:"finance",arc:"finance-t1-a11",stage:0,speaker:"Debt Management Chief",portrait:"official",tags:["eurobond","debt","markets"],prompt:"Another monsoon, another return of an argument you cannot end. Reserves are tight and the chief proposes a debut dollar Eurobond — quick foreign cash, but at a punishing coupon that locks in high interest for a decade if the markets smell desperation.",left:{id:"a",label:"Issue the Eurobond now.",tooltip:"Cash today is worth the coupon.",reveal:"Dollars arrive and the reserves breathe. The expensive interest bill compounds quietly for ten years.",effects:{FI:8,GL:3,EN:-6}},right:{id:"b",label:"Wait for calmer markets and cut imports instead.",tooltip:"I will not borrow dear out of panic.",reveal:"You squeeze import demand to hold the line. It bites at home now, but spares the country a decade of costly debt.",effects:{FI:-6,EN:-10,GL:3}}},{id:"finance-0167",location:"finance",arc:"finance-t1-a12",stage:0,speaker:"Agriculture Secretary",portrait:"official",tags:["subsidy","fertiliser","farmers"],prompt:"Deep into the reign, the issue demands a final-sounding answer. Global fertiliser prices have tripled. The secretary warns that without a fat subsidy the next harvest fails — but the subsidy alone would blow a hole in the budget the IMF is watching.",left:{id:"a",label:"Fund the full fertiliser subsidy.",tooltip:"A failed harvest is a famine and a fall.",reveal:"The fields stay green and the farmers bless you. The deficit balloons and the IMF frowns at the next review.",effects:{EN:8,RE:3,FI:-16}},right:{id:"b",label:"Trim the subsidy to satisfy the lenders.",tooltip:"The books must balance somewhere.",reveal:"You please the creditors and thin the subsidy. Input costs hit the villages, and rural anger ferments.",effects:{FI:6,GL:3,EN:-16,FA:-6}}},{id:"finance-0168",location:"finance",arc:"finance-t1-a13",stage:0,speaker:"Pension Authority Head",portrait:"official",tags:["pension","welfare","funding"],prompt:"The reckoning you postponed has matured into a crisis. Your flagship universal pension scheme is wildly popular — and quietly unfunded past the first few years. The head asks whether to keep enrolling millions on a promise the treasury cannot yet keep.",left:{id:"a",label:"Keep enrolling — worry about funding later.",tooltip:"The promise wins this decade's votes.",reveal:"Millions sign up to applause. You have built a magnificent liability your successors will curse.",effects:{EN:8,FA:3,FI:-13}},right:{id:"b",label:"Slow enrolment until it is actuarially sound.",tooltip:"A pension that bounces is a betrayal.",reveal:"You cap the scheme to make it real. The rollout looks timid, but the cheque will clear when it comes due.",effects:{FI:5,GL:3,EN:-13}}},{id:"finance-0169",location:"finance",arc:"finance-t1-a14",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["banks","merger","weak-banks"],prompt:"A new chapter, the same antagonists, less room to manoeuvre. Five insolvent banks are walking corpses, kept alive by liquidity from the central bank. The governor wants to force-merge them into stronger ones — wiping out politically-connected directors.",left:{id:"a",label:"Force the mergers through.",tooltip:"Let the dead banks be buried.",reveal:"The rot is consolidated and capped. The ousted directors — several are donors — swear vengeance.",effects:{FI:8,GL:5,FA:-13}},right:{id:"b",label:"Keep them on life support a while longer.",tooltip:"Not before the election, not these names.",reveal:"The zombies shuffle on, draining liquidity. The reckoning is postponed and made larger.",effects:{FA:5,FI:-13,GL:-6}}},{id:"finance-0170",location:"finance",arc:"finance-t1-a15",stage:0,speaker:"Mobile Finance Regulator",portrait:"official",tags:["mfs","bkash","fintech"],prompt:"The old fault line widens; this time there is no quiet option. Mobile money moves the wages of the whole working class now, and the dominant operator wants to raise cash-out fees. The poorest pay those fees; the operator employs thousands and lobbies hard.",left:{id:"a",label:"Cap the cash-out fees.",tooltip:"The garment girl should keep her wage.",reveal:"The fee cap eases millions of small lives. The operator threatens to cut rural agents in protest.",effects:{EN:8,FA:3,FI:-10}},right:{id:"b",label:"Let the operator set its fees.",tooltip:"A profitable rail keeps expanding.",reveal:"The network grows and invests; the daily skim off the poor grows with it.",effects:{FI:5,GL:3,EN:-13}}},{id:"finance-0171",location:"finance",arc:"finance-t1-a16",stage:0,speaker:"Customs Intelligence Chief",portrait:"shadow",tags:["misinvoicing","laundering","trade"],prompt:"Time has not healed it — the conflict comes back armed. The chief lays out how billions leave the country through fake import invoices — over-paying foreign 'suppliers' who are really the importers' own offshore shells. The biggest offenders dine with your ministers.",left:{id:"a",label:"Order a real crackdown on misinvoicing.",tooltip:"Plug the hole in the hull.",reveal:"Customs tightens and capital flight slows. Powerful importers, exposed, fund your rivals overnight.",effects:{FI:8,GL:5,FA:-13}},right:{id:"b",label:"Let the audit quietly stall.",tooltip:"Some hulls are best left unexamined.",reveal:"The trade continues and the friends stay close. The reserves keep leaking out the side the cameras never see.",effects:{FA:5,FI:-10,GL:-10}}},{id:"finance-0172",location:"finance",arc:"finance-t1-a17",stage:0,speaker:"Fuel Pricing Board",portrait:"official",tags:["fuel","bpc","subsidy"],prompt:"Once again, and with the whole house holding its breath. The state oil company bleeds crores a day selling diesel below cost. The board wants an automatic price-adjustment formula — fuel prices that rise with the world market, untouched by your hand.",left:{id:"a",label:"Adopt the automatic formula.",tooltip:"Take the politics out of the pump.",reveal:"The oil company stops bleeding; fuel jumps with every global tick, and transport strikes follow each rise.",effects:{FI:8,GL:5,EN:-16}},right:{id:"b",label:"Keep prices fixed and eat the loss.",tooltip:"Cheap diesel keeps the country moving.",reveal:"Buses and irrigation pumps run cheap. The subsidy drains the budget and distorts every market it touches.",effects:{EN:6,FI:-16,RE:-6}}},{id:"finance-0173",location:"finance",arc:"finance-t1-a18",stage:0,speaker:"Treasury Economist",portrait:"official",tags:["currency","dual-rate","taka"],prompt:"The matter resurfaces in a harder year, patience exhausted. A grey gap has opened between the official taka rate and the street rate, breeding arbitrage and a black market. The economist says you must unify the rates — a one-time devaluation that will sting everyone at once.",left:{id:"a",label:"Unify the rate, take the devaluation.",tooltip:"One honest price beats two dishonest ones.",reveal:"The black market shrinks and exporters cheer; every imported good leaps in price the same morning.",effects:{FI:6,GL:5,EN:-16}},right:{id:"b",label:"Hold the official rate and ration dollars.",tooltip:"A sudden devaluation would break the poor.",reveal:"You keep the headline rate and dole out scarce dollars by favour — a system that breeds its own corruption.",effects:{FI:-10,EN:3,GL:-10}}},{id:"finance-0174",location:"finance",arc:"finance-t1-a19",stage:0,speaker:"Foreign Loans Director",portrait:"official",tags:["china","debt","geopolitics"],prompt:"A later season of rule, the stakes now openly existential. Beijing offers soft loans for a glittering ring road, far cheaper than the markets. The opposition is already chanting 'debt trap', and the West is watching whose money paves your capital.",left:{id:"a",label:"Take the Chinese loan.",tooltip:"Cheap concrete is cheap concrete.",reveal:"The ring road rises on easy terms. The 'debt-trap' headlines and Western coolness are the price of the bargain.",effects:{FI:8,RE:5,GL:-13}},right:{id:"b",label:"Decline and tender it to the markets.",tooltip:"I will not mortgage the capital to one capital.",reveal:"You pay more for diversified financing and Western goodwill. The project crawls; the books strain.",effects:{GL:5,FI:-13,RE:-6}}},{id:"finance-0175",location:"finance",arc:"finance-t1-a20",stage:0,speaker:"Pay Commission Head",portrait:"official",tags:["wages","civil-service","budget"],prompt:"It comes around again, and the margin for error is gone. Two million civil servants want a new pay scale, and they staff every office you rely on. A generous raise wins a loyal bureaucracy; it also locks in a wage bill that eats the development budget.",left:{id:"a",label:"Grant the generous pay rise.",tooltip:"A happy bureaucracy is a working one.",reveal:"The files move and the clerks smile. The recurring wage bill devours the money meant for bridges and clinics.",effects:{MI:5,FA:3,FI:-16,EN:-6}},right:{id:"b",label:"Offer a modest, affordable raise.",tooltip:"The state cannot be a charity for itself.",reveal:"You protect the development budget. A sullen civil service slow-walks everything for a season.",effects:{FI:6,EN:3,MI:-10}}},{id:"finance-0176",location:"finance",arc:"finance-t1-a21",stage:0,speaker:"Export Promotion Chief",portrait:"official",tags:["rmg","incentive","exports"],prompt:"The same demand, but the reign is older and the knives sharper. Exporters get a cash incentive on every dollar of garments shipped — a subsidy the IMF calls a distortion and wants gone. The factory owners say cutting it now hands the orders to Vietnam.",left:{id:"a",label:"Keep the export cash incentive.",tooltip:"Do not gift our orders to Hanoi.",reveal:"The looms keep their edge and the dollars keep coming. The IMF marks another unmet condition against you.",effects:{FI:5,GL:-10,EN:3,FA:3}},right:{id:"b",label:"Phase out the incentive as promised.",tooltip:"A crutch carried too long becomes a cast.",reveal:"You please the lenders and prod exporters to compete on merit. Margins thin; some marginal factories fold.",effects:{GL:6,FI:-10,EN:-10}}},{id:"finance-0177",location:"finance",arc:"finance-t1-a22",stage:0,speaker:"Deficit Financing Officer",portrait:"official",tags:["printing","inflation","central-bank"],prompt:"Years deep, the unresolved returns to be resolved for good. Short of cash before the budget, an officer suggests the oldest trick: have the central bank simply print money to cover the gap. It is invisible today and inflationary tomorrow.",left:{id:"a",label:"Print to cover the deficit.",tooltip:"No one feels it this quarter.",reveal:"The gap is filled with fresh notes. Inflation stirs in the months ahead, a tax no one voted for.",effects:{FI:6,EN:-16,GL:-6}},right:{id:"b",label:"Refuse and borrow honestly instead.",tooltip:"I will not pay tomorrow's prices for today's gap.",reveal:"You raise the money through bonds, dearer but cleaner. The deficit is honest and the taka steadier.",effects:{GL:5,FI:-6,EN:3}}},{id:"finance-0178",location:"finance",arc:"finance-t1-a23",stage:0,speaker:"e-Commerce Victims' Delegation",portrait:"people",tags:["scam","ecommerce","refunds"],prompt:"The conflict reignites, and the world is watching this time. A glittering online marketplace took advance payments for goods it never had and collapsed, taking the savings of a hundred thousand families. They camp outside your office demanding their money back.",left:{id:"a",label:"Order a state-backed refund fund.",tooltip:"The state failed to police it; the state pays.",reveal:"Families recover a fraction of their savings. The treasury absorbs a scam it did not commit, and others ask why they were not bailed out too.",effects:{EN:8,FA:3,FI:-16}},right:{id:"b",label:"Pursue the founders, but no public refund.",tooltip:"I will jail the thieves, not reward the gamble.",reveal:"You freeze assets and prosecute. The recovered crumbs disappoint the crowd, but the precedent of no-bailout holds.",effects:{GL:3,FI:3,EN:-13}}},{id:"finance-0179",location:"finance",arc:"finance-t1-a24",stage:0,speaker:"Revenue Reform Adviser",portrait:"official",tags:["wealth-tax","surcharge","elite"],prompt:"A familiar crisis, escalated by everything you let slide. The adviser proposes a stiff surcharge on the largest fortunes — popular with the street, loathed by the class that funds campaigns and owns the newspapers.",left:{id:"a",label:"Impose the wealth surcharge.",tooltip:"Those with the most can give the most.",reveal:"Public revenue and approval both rise. The moneyed class opens its war chest against you and its front pages turn cold.",effects:{FI:8,EN:6,FA:-13}},right:{id:"b",label:"Shelve it to keep the donors close.",tooltip:"I cannot fight the people who fund me.",reveal:"The fortunes stay untaxed and the donors stay sweet. The street notes whose interests the budget serves.",effects:{FA:5,FI:-10,EN:-10}}},{id:"finance-0180",location:"finance",arc:"finance-t1-a25",stage:0,speaker:"Import Policy Officer",portrait:"official",tags:["lc","luxury","reserves"],prompt:"The fault line cracks wider; the decision can no longer wait. To defend the reserves, an officer wants to choke letters of credit for 'luxury' imports — cars, cosmetics, fruit. It saves dollars and irritates exactly the affluent who notice empty shelves.",left:{id:"a",label:"Restrict the luxury LCs.",tooltip:"Dollars are for medicine, not Mercedes.",reveal:"Reserves stop bleeding on baubles. The affluent grumble about scarcity, and some smuggling reroutes the trade.",effects:{FI:6,GL:3,EN:-6,FA:-6}},right:{id:"b",label:"Keep imports open to avoid the optics of scarcity.",tooltip:"Empty shelves photograph badly.",reveal:"The shops stay stocked and the rich content. The reserves keep draining on things the country need not buy.",effects:{FA:3,FI:-13,GL:-6}}},{id:"finance-0181",location:"finance",arc:"finance-t1-a26",stage:0,speaker:"Loan Classification Board",portrait:"official",tags:["rescheduling","defaulters","banks"],prompt:"Late in the reign, the old question demands a heavier answer. The board can relax the loan-rescheduling rules so habitual defaulters look 'regular' again with a token down-payment. It flatters the banks' books and rewards the very borrowers who never pay.",left:{id:"a",label:"Relax the rules, flatter the books.",tooltip:"A pretty balance sheet calms the market.",reveal:"Default ratios drop on paper overnight. The rot deepens in the dark, and the honest borrower wonders why he bothers.",effects:{FI:5,GL:-10,FA:3}},right:{id:"b",label:"Tighten classification to the real number.",tooltip:"Call a bad loan a bad loan.",reveal:"The true scale of default is finally visible. It looks ugly and frightens markets briefly — but the cleanup can begin.",effects:{GL:5,FI:-10,EN:3,FA:-6}}},{id:"finance-0182",location:"finance",arc:"finance-t1-a27",stage:0,speaker:"Privatisation Commissioner",portrait:"official",tags:["privatisation","jute","state-firms"],prompt:"It returns once more — and this round may be the one remembered. The state jute and textile mills lose money every single year, yet they employ tens of thousands and carry the romance of the founding economy. The commissioner wants them sold or shut.",left:{id:"a",label:"Shut and sell the loss-making mills.",tooltip:"Nostalgia is not a business plan.",reveal:"The hemorrhage stops and buyers move in. Thousands of mill workers and their unions march on your gate.",effects:{FI:8,GL:3,EN:-16,MI:-6}},right:{id:"b",label:"Keep the mills open with state money.",tooltip:"These looms built the nation.",reveal:"The jobs and the heritage survive on subsidy. The losses recur, year after year, a line item that never dies.",effects:{EN:5,FA:3,FI:-16}}},{id:"finance-0183",location:"finance",arc:"finance-t1-a28",stage:0,speaker:"National Savings Director",portrait:"official",tags:["sanchayapatra","savings","rates"],prompt:"The reckoning circles back, grown teeth in the waiting. Government savings certificates pay pensioners and widows a generous fixed return — and cost the treasury dearly as everyone piles in. The director wants to cut the rate.",left:{id:"a",label:"Cut the savings-certificate rate.",tooltip:"The treasury cannot subsidise every saver.",reveal:"The interest bill eases. Pensioners and widows who counted on that return feel the floor drop, and say so loudly.",effects:{FI:8,GL:3,EN:-13}},right:{id:"b",label:"Protect the small savers' rate.",tooltip:"The widow's certificate is sacred.",reveal:"You shield the small savers and eat the cost. The high-rollers exploit the same window, and the bill grows.",effects:{EN:6,FA:3,FI:-16}}},{id:"finance-0184",location:"finance",arc:"finance-t1-a29",stage:0,speaker:"Special Economic Zone Director",portrait:"official",tags:["sez","tax-holiday","investment"],prompt:"Another term, the same antagonist, the stakes raised again. A foreign consortium will build a vast economic zone and bring jobs — if you grant a fifteen-year tax holiday so generous the project pays almost nothing into the treasury for a generation.",left:{id:"a",label:"Grant the long tax holiday.",tooltip:"Jobs now, taxes eventually.",reveal:"The cranes arrive and employment rises. The treasury forgoes a fortune for fifteen years to win the ribbon-cutting.",effects:{EN:6,FI:-10,GL:5,RE:3}},right:{id:"b",label:"Negotiate a shorter, fairer holiday.",tooltip:"I will host investment, not subsidise it forever.",reveal:"You drive a harder bargain. The consortium hesitates and shrinks the project — but the state keeps a slice of the upside.",effects:{FI:5,GL:-6,EN:-6}}},{id:"finance-0185",location:"finance",arc:"finance-t1-a30",stage:0,speaker:"Anti-Tobacco Coalition",portrait:"people",tags:["tobacco","tax","health"],prompt:"The matter, long deferred, lands with the force of a verdict. Doctors want tobacco taxed steeply to curb a public-health disaster; the tobacco giants are among your largest taxpayers and employ a vast leaf-growing belt that votes.",left:{id:"a",label:"Tax tobacco hard.",tooltip:"A cigarette tax is a life saved and a taka earned.",reveal:"Revenue and public health both rise. The tobacco lobby and its farming districts turn sharply against you.",effects:{FI:6,EN:6,FA:-10}},right:{id:"b",label:"Keep tobacco taxes low.",tooltip:"Do not gut a top taxpayer and a voting belt.",reveal:"The companies stay sweet and the leaf districts loyal. The wards fill with the slow harvest of that bargain.",effects:{FI:3,FA:3,EN:-16}}},{id:"finance-0186",location:"finance",arc:"finance-t1-a31",stage:0,speaker:"Land Registration Reformer",portrait:"official",tags:["real-estate","black-money","registration"],prompt:"Years on and unhealed, the conflict returns to claim its answer. Property is bought at a fraction of its true value on paper, hiding black money and starving the treasury of registration tax. Digitising and revaluing it would expose a lot of powerful people.",left:{id:"a",label:"Digitise and revalue property.",tooltip:"Drag the land market into the light.",reveal:"Registration revenue surges and a laundering channel narrows. Builders and land barons — and their political patrons — howl.",effects:{FI:8,EN:3,GL:3,FA:-13}},right:{id:"b",label:"Leave the registers as they are.",tooltip:"Some ledgers are best left yellowed.",reveal:"The cosy undervaluation continues. Black money keeps flowing into bricks while the treasury watches it pass.",effects:{FA:5,FI:-13,GL:-6}}},{id:"finance-0187",location:"finance",arc:"finance-t1-a32",stage:0,speaker:"Hajj Management Director",portrait:"cleric",tags:["hajj","pilgrims","cost"],prompt:"The same fault line, the harder hour, the narrower path. Airfares and Saudi fees have pushed the pilgrimage beyond ordinary families. The director asks whether to subsidise Hajj from the budget — pious and popular, or a costly precedent the secularists will attack.",left:{id:"a",label:"Subsidise the pilgrimage.",tooltip:"Let the faithful afford the journey.",reveal:"Grateful pilgrims bless your name from Mecca. The treasury and the secular press both wince at the bill.",effects:{FA:5,EN:5,FI:-13,GL:-6}},right:{id:"b",label:"Keep Hajj unsubsidised but cut the agents' fees.",tooltip:"Faith should not be a fiscal line.",reveal:"You squeeze the middlemen instead of the budget. The devout are mildly disappointed; the books stay clean.",effects:{FI:5,GL:3,EN:-6,FA:-6}}},{id:"finance-0188",location:"finance",arc:"finance-t1-a33",stage:0,speaker:"Climate Fund Auditor",portrait:"official",tags:["climate","fund","graft"],prompt:"It comes back sharpened by every season you survived. The donor-funded climate adaptation pot — embankments, shelters, resilient seed — has leaked badly into the pockets of local officials. A hard audit would recover money and embarrass your own party men.",left:{id:"a",label:"Order the hard audit and claw the money back.",tooltip:"Stolen flood money is blood money.",reveal:"Recovered crores return to the embankments. The implicated party officials become loud, wounded enemies.",effects:{EN:6,GL:6,FI:3,FA:-13}},right:{id:"b",label:"Bury the audit to protect the party.",tooltip:"Do not hand the donors a scandal.",reveal:"The leak stays hidden and the party intact. The embankments stay thin, and the next flood collects the difference.",effects:{FA:5,EN:-16,GL:-10}}},{id:"finance-0189",location:"finance",arc:"finance-t1-a34",stage:0,speaker:"Sovereign Fund Proponent",portrait:"official",tags:["reserves","sovereign-fund","investment"],prompt:"A later year of power, the old crisis now a true test of it. An adviser wants to carve a sovereign wealth fund out of the foreign reserves to invest in big domestic projects. Bold — but every dollar parked in concrete is a dollar not defending the taka in a crisis.",left:{id:"a",label:"Launch the sovereign fund from reserves.",tooltip:"Idle reserves should build the country.",reveal:"Grand projects get cheap money and momentum. The reserve buffer thins, and a future shock will find less cushion.",effects:{RE:5,EN:5,FI:-10,GL:-6}},right:{id:"b",label:"Keep the reserves as a war chest.",tooltip:"Reserves are the wall against the storm.",reveal:"You guard the buffer and pass on the projects. Critics call it timid; the next currency scare proves it wise.",effects:{FI:6,GL:3,EN:-6}}},{id:"finance-0190",location:"finance",arc:"finance-t1-a35",stage:0,speaker:"VAT Online Director",portrait:"official",tags:["vat","digitisation","compliance"],prompt:"The unresolved returns, and this time it will not be deferred. Electronic VAT machines would capture billions that retailers currently pocket — but every shopkeeper sees a spy in the till, and they are a million-strong voting bloc.",left:{id:"a",label:"Mandate the electronic VAT machines.",tooltip:"An honest till funds an honest state.",reveal:"Consumption-tax revenue climbs steadily. A million shopkeepers grumble about the machine watching every sale.",effects:{FI:8,GL:3,EN:-6,FA:-6}},right:{id:"b",label:"Keep VAT collection manual and negotiable.",tooltip:"Do not put a meter on every shop counter.",reveal:"The shopkeepers stay content and the leakage continues. The treasury collects a fraction of what it is owed.",effects:{FA:5,FI:-13,GL:-6}}},{id:"finance-0191",location:"finance",arc:"finance-t1-a36",stage:0,speaker:"Garment Buyers' Auditor",portrait:"ambassador",tags:["rmg","compliance","wages"],prompt:"A term later, the same fault line tears open again. After a competitor's scandal, Western buyers demand audited proof that your factories pay the legal wage and the promised bonuses. Real compliance costs the owners; faking it risks the whole export market.",left:{id:"a",label:"Enforce real wage compliance.",tooltip:"The market is worth more than the margin.",reveal:"Buyers are reassured and orders hold; the workers are paid in full. Factory owners — your donors — bristle at the cost.",effects:{GL:6,EN:6,FI:-10,FA:-6}},right:{id:"b",label:"Help the owners present a compliant face.",tooltip:"Protect the owners who keep the lines running.",reveal:"The audit is smoothed over and margins protected. One leaked payslip could bring the whole edifice down.",effects:{FI:5,FA:3,GL:-13,EN:-10}}},{id:"finance-0192",location:"finance",arc:"finance-t1-a37",stage:0,speaker:"Revenue Board Chairman",portrait:"fixer",tags:["black-money","tax","whitening"],prompt:"Years into your rule, the matter you thought buried resurfaces — harder. A budget clause would let undisclosed 'black money' be legalised by paying a flat low tax, no questions asked — luring billions back into the formal economy and the property market. The chairman calls it pragmatic; honest taxpayers call it a reward for the crooked.",left:{id:"a",label:"Offer the no-questions whitening scheme.",tooltip:"Better the black money working here than hiding abroad.",reveal:"The clause passes and laundered crores flood into property and banks. The reserves and the books improve, and every honest taxpayer learns that cheating, in the end, is rewarded.",effects:{FI:8,FA:2,EN:-13,GL:-10}},right:{id:"b",label:"Refuse to legalise undisclosed wealth.",tooltip:"A state that pardons theft for a fee invites more theft.",reveal:"You kill the whitening clause. The hidden money stays hidden or flees abroad, and the budget is thinner for it, but the tax system keeps a shred of fairness and credibility.",effects:{GL:5,EN:5,FI:-13}}},{id:"finance-0193",location:"finance",arc:"finance-t1-a38",stage:0,speaker:"Securities Regulator",portrait:"official",tags:["stock-market","crash","retail"],prompt:"A new season of power, an old problem with sharper teeth. The bourse has crashed after a manipulated bubble, wiping out hundreds of thousands of small investors lured in by insiders who cashed out at the top. The regulator can mount a costly retail bailout and prosecute the manipulators, or let the market clear and the losers learn.",left:{id:"a",label:"Bail out small investors, prosecute manipulators.",tooltip:"A market that eats its small fish breeds no trust.",reveal:"You cushion the retail losses and go after the big manipulators. The bailout is costly and the syndicates fight back, but the small investor sees the state will not abandon them to the wolves.",effects:{EN:6,GL:3,FI:-13,FA:-6}},right:{id:"b",label:"Let the market clear on its own.",tooltip:"A gambler who loses cannot bill the state.",reveal:"You let the crash run its course. The treasury is spared, the manipulators keep their gains, and a generation of small savers swears off the market that fleeced them.",effects:{FI:3,EN:-13,GL:-3}}},{id:"finance-0194",location:"finance",arc:"finance-t1-a39",stage:0,speaker:"Privatisation Commission Chief",portrait:"official",tags:["soe","privatisation","jobs"],prompt:"The crisis returns, and this time the cabinet is watching. Dozens of state enterprises — mills, factories, a national airline — bleed subsidy every year, kept alive for the jobs and the patronage. The chief can privatise or shut the worst, stemming the losses, or keep them on life support to protect the workers and the votes.",left:{id:"a",label:"Privatise or shut the loss-makers.",tooltip:"A factory that only makes losses makes nothing.",reveal:"You sell or close the bleeding enterprises and stem the subsidy. The freed budget is real, but tens of thousands of workers lose their jobs and turn their fury on you.",effects:{FI:6,GL:3,EN:-13}},right:{id:"b",label:"Keep the enterprises on life support.",tooltip:"A wage lost is a household sunk.",reveal:"You keep the loss-makers running for the workers and the patronage. The jobs and the votes are safe, and the subsidy keeps draining money that schools and clinics will never see.",effects:{EN:5,FA:3,FI:-13}}},{id:"finance-0195",location:"finance",arc:"finance-t1-a40",stage:0,speaker:"Pension Authority Director",portrait:"people",tags:["pension","welfare","future"],prompt:"Once more the issue lands on your desk, the stakes higher than before. A national pension scheme would give the vast informal workforce security in old age — a transformative legacy — but it demands either contributions the poor can barely make or a vast permanent subsidy the budget can barely bear. The director needs your design.",left:{id:"a",label:"Launch a generously subsidised pension.",tooltip:"An old age without dignity is a society's shame.",reveal:"You build a pension reaching even the poorest with heavy state top-ups. The fiscal burden is enormous and permanent, but a generation of the elderly is lifted out of destitution.",effects:{EN:10,GL:3,FI:-16}},right:{id:"b",label:"Build a lean contributory pension.",tooltip:"A promise I cannot fund is a betrayal deferred.",reveal:"You launch a modest, mainly contribution-based scheme. It is fiscally sound but reaches the poorest thinly, and the informal workers who most need it can least afford to join.",effects:{FI:3,EN:3,GL:2}}},{id:"finance-0196",location:"finance",arc:"finance-t1-a41",stage:0,speaker:"IMF Programme Negotiator",portrait:"ambassador",tags:["imf","subsidy","austerity"],prompt:"Another year survived, and the reckoning circles back. The next IMF tranche hinges on slashing fuel and electricity subsidies — a move that steadies the budget and detonates the cost of living for everyone. The negotiator says the money is vital; the street says the price rises are unbearable.",left:{id:"a",label:"Cut the subsidies for the IMF tranche.",tooltip:"The fund's money keeps the lights on at all.",reveal:"You slash the subsidies and unlock the tranche. The reserves and the lenders are reassured, and the price of transport, food, and power detonates in every household.",effects:{FI:6,GL:5,EN:-18}},right:{id:"b",label:"Protect the subsidies, risk the tranche.",tooltip:"I will not buy a loan with my people's hunger.",reveal:"You shield the subsidies and the IMF talks stall. The street is spared the shock, but the reserves keep bleeding and the lifeline you turned down may not be offered twice.",effects:{EN:6,FI:-13,GL:-6}}},{id:"finance-0197",location:"finance",arc:"finance-t1-a42",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["currency","float","devaluation"],prompt:"The ground has shifted; the same demand arrives with new menace. The taka is propped up at an artificial rate the reserves can no longer defend, feeding a black market. The governor urges letting it float to its real value — ending the drain, but spiking import prices and inflation overnight — or burning more reserves to hold the peg.",left:{id:"a",label:"Let the taka float to its real value.",tooltip:"A currency defended past its worth bankrupts the defender.",reveal:"You float the taka and the black-market premium vanishes. Import prices and inflation jump painfully, but the ruinous reserve drain stops and the market finds honest footing.",effects:{FI:5,GL:3,EN:-13}},right:{id:"b",label:"Burn reserves to hold the peg.",tooltip:"A falling taka is a falling government.",reveal:"You keep defending the rate. The official price holds and the public is spared the shock for now, but the reserves drain toward empty and the black market thrives in the gap.",effects:{EN:3,FI:-13,GL:-3}}},{id:"finance-0198",location:"finance",arc:"finance-t1-a43",stage:0,speaker:"Banking Division Secretary",portrait:"official",tags:["banks","merger","npl"],prompt:"History rhymes: the conflict reopens deeper than last time. Several banks are insolvent, hollowed out by insider looting and bad loans, and one is days from collapse. The secretary can force mergers into healthier banks — protecting depositors but rewarding the looters — or let a bank fail and shock the system into discipline.",left:{id:"a",label:"Force mergers to protect depositors.",tooltip:"A bank run is a fire that spreads.",reveal:"You merge the zombie banks into stronger ones and depositors are saved. The looters who gutted them walk away clean, and the healthy banks inherit a mountain of toxic debt.",effects:{FI:3,EN:2,GL:-3,FA:-3}},right:{id:"b",label:"Let an insolvent bank fail.",tooltip:"A bank that is never allowed to die never learns to live.",reveal:"You let one rotten bank collapse. Depositors panic and the system shudders, but for once the looters lose their bank, and every other board suddenly takes risk seriously.",effects:{GL:3,FI:-10,EN:-6}}},{id:"finance-0199",location:"finance",arc:"finance-t1-a44",stage:0,speaker:"Banking Division Secretary",portrait:"fixer",tags:["loans","defaulters","favours"],prompt:"Mid-reign, the old wound is torn afresh. The biggest loan defaulters — industrialists with party ties — want their bad loans rescheduled on absurdly soft terms again, kicking the reckoning down the road. The secretary says it props up the banks' books on paper; it also lets the willful defaulters off the hook forever.",left:{id:"a",label:"Grant the soft rescheduling again.",tooltip:"A defaulter's empire employs thousands; do not topple it.",reveal:"You let the big defaulters reschedule on featherbed terms. The banks' books look healthier on paper, the connected tycoons stay afloat, and the rot in the banking system deepens out of sight.",effects:{FI:3,FA:3,EN:-10,GL:-10}},right:{id:"b",label:"Force repayment or seizure.",tooltip:"A willful defaulter is a thief with a balance sheet.",reveal:"You refuse the rescheduling and move to recover or seize. The tycoons rage and call in their political chips, but billions in dead loans start, painfully, to come back.",effects:{GL:5,FI:3,EN:3,FA:-10}}},{id:"finance-0200",location:"finance",arc:"finance-t1-a45",stage:0,speaker:"Debt Management Director",portrait:"ambassador",tags:["eurobond","debt","markets"],prompt:"The pressure you deferred has come due, larger now. You can raise a large sum fast by issuing a sovereign bond on the international markets — no IMF conditions, no neighbourly strings — but at a steep interest rate that mortgages future budgets, and exposes you to the mercy of global bond traders.",left:{id:"a",label:"Issue the international bond.",tooltip:"Market money comes with no master attached.",reveal:"The bond raises the cash quickly and string-free. The high coupon settles onto future budgets, and your fortunes are now hostage to the moods of distant bond markets.",effects:{FI:5,GL:2,RE:2}},right:{id:"b",label:"Avoid the costly market borrowing.",tooltip:"A bond at usurer's rates is a trap with a ribbon.",reveal:"You skip the expensive bond and live within tighter means. The development plans shrink and the cash crunch bites, but you do not mortgage the next decade to the markets.",effects:{GL:2,FI:-6,EN:-3}}},{id:"finance-0201",location:"finance",arc:"finance-t1-a46",stage:0,speaker:"Trading Corporation Chief",portrait:"shadow",tags:["inflation","syndicate","food"],prompt:"A later term, and the quarrel has hardened into a test. A cartel of wholesalers is hoarding rice, onions, and oil to spike prices at will, squeezing every household — and several cartel bosses are party financiers. The chief can break the syndicate with raids and state imports, or protect the donors and let prices ride.",left:{id:"a",label:"Break the price syndicate.",tooltip:"A cartel that taxes every plate must be smashed.",reveal:"You raid the hoarders and flood the market with state imports. Prices ease and the public exhales, but the cartel bosses — your financiers — turn on you with their wallets shut.",effects:{EN:8,FI:-6,FA:-10}},right:{id:"b",label:"Protect the donors, let prices ride.",tooltip:"The men who fund the party are not lightly raided.",reveal:"You spare the syndicate and the hoarding continues. The financiers stay loyal and generous, and the cost of a meal climbs out of reach for the families who can least bear it.",effects:{FI:3,FA:5,EN:-16}}},{id:"finance-0202",location:"finance",arc:"finance-t1-a47",stage:0,speaker:"Customs Commissioner",portrait:"fixer",tags:["customs","ports","corruption"],prompt:"The country has changed, but this fault line has not — only worsened. The ports leak billions in duty through under-invoicing and bribed clearance, with the customs houses among the most lucrative postings in the state. The commissioner can automate and audit the whole system, breaking the rackets, or leave the golden geese to lay.",left:{id:"a",label:"Automate and audit customs.",tooltip:"A bribed customs house robs the whole nation.",reveal:"You digitise clearance and audit the postings hard. Duty revenue jumps and the rackets wither, and the officers who paid fortunes for the lucrative postings turn bitterly against you.",effects:{FI:6,GL:3,EN:2,FA:-6}},right:{id:"b",label:"Leave the customs rackets running.",tooltip:"The men in the customs houses have powerful patrons.",reveal:"You leave the ports' shadow economy intact. The patronage flows smoothly and the postings stay golden, and the treasury keeps collecting a fraction of the duty it is owed.",effects:{FI:-6,FA:3,EN:-6,GL:-3}}},{id:"finance-0203",location:"finance",arc:"finance-t1-a48",stage:0,speaker:"Revenue Board Chairman",portrait:"official",tags:["tax","elite","evasion"],prompt:"It returns, as these things do, with the patience gone. The country's tax-to-GDP ratio is among the world's lowest because the wealthy simply do not pay — and the board has long squeezed the salaried middle instead. The chairman can finally go after the rich evaders, who include donors and dynasts, or keep milking the easy salaried base.",left:{id:"a",label:"Go after the wealthy evaders.",tooltip:"A state funded by clerks while tycoons skate is doomed.",reveal:"You target the rich evaders, audits reaching into donor and dynastic ledgers. The revenue base broadens and the public cheers, but the powerful you have dunned plot their revenge.",effects:{FI:6,EN:6,GL:3,FA:-13}},right:{id:"b",label:"Keep squeezing the salaried base.",tooltip:"The easy taxpayer is the one who cannot run.",reveal:"You leave the rich alone and lean harder on the salaried. The revenue is reliable and the donors content, and the shrinking middle class learns exactly whose shoulders the state rests on.",effects:{FI:3,FA:3,EN:-13}}},{id:"finance-0204",location:"finance",arc:"finance-t1-a49",stage:0,speaker:"Digital Finance Adviser",portrait:"official",tags:["mobile-money","remittances","inclusion"],prompt:"Years on, the matter is no longer private; the press is already circling. Mobile money has banked the unbanked and could pull remittances out of the illegal hundi channels into the formal economy — if you incentivise it. The banks lobby against it, fearing disintermediation, and the hundi networks have their own quiet patrons.",left:{id:"a",label:"Boost mobile money and formal remittances.",tooltip:"A phone in every hand is a bank in every village.",reveal:"You push incentives for mobile remittances and the formal channels swell. The banks and the hundi networks both lose ground and grumble, but billions enter the legal economy and the unbanked gain access.",effects:{FI:6,EN:5,GL:2,FA:-3}},right:{id:"b",label:"Protect the banks, let hundi persist.",tooltip:"The banks are the system; do not undercut them.",reveal:"You shield the banks and leave the mobile push half-hearted. The hundi networks keep their grip on remittances, the reserves miss the inflows, and the village stays unbanked.",effects:{FA:3,FI:-10,EN:-3}}},{id:"finance-0205",location:"finance",arc:"finance-t1-a50",stage:0,speaker:"Pay Commission Chair",portrait:"official",tags:["salaries","bureaucracy","budget"],prompt:"The same knot, retied tighter, lands before you once more. A new pay commission recommends a huge salary hike for the civil service — buying the bureaucracy's loyalty and curbing petty corruption, but blowing a vast hole in the recurrent budget for years. The chair awaits your decision.",left:{id:"a",label:"Grant the full pay rise.",tooltip:"A well-paid official is a loyal, honest one.",reveal:"You award the generous hike and the bureaucracy is delighted and bound to you. Petty bribery eases, but the wage bill swells permanently, crowding out the development budget for years.",effects:{MI:2,FA:3,FI:-13,EN:-3}},right:{id:"b",label:"Grant a modest, affordable rise.",tooltip:"A salary I cannot sustain is a strike deferred.",reveal:"You give a restrained increase the budget can bear. The civil servants grumble at the modesty and some petty corruption persists, but the fiscal hole stays survivable.",effects:{FI:3,EN:2,FA:-3}}},{id:"finance-0206",location:"finance",arc:"finance-t1-a51",stage:0,speaker:"Financial Intelligence Chief",portrait:"shadow",tags:["laundering","over-invoicing","capital-flight"],prompt:"Another monsoon, another return of an argument you cannot end. Billions flee the country each year through over- and under-invoiced trade, spiriting wealth to second homes abroad — and the launderers include some of your biggest backers. The chief can build a real enforcement net, or keep the channel quietly open for friends.",left:{id:"a",label:"Build the anti-laundering net.",tooltip:"A river of stolen money flowing abroad bleeds us white.",reveal:"You stand up real trade-laundering enforcement and the outflows slow. The reserves steady and the world's watchdogs approve, but your backers' escape route is now monitored, and they are furious.",effects:{FI:5,GL:5,EN:3,FA:-10}},right:{id:"b",label:"Keep the laundering channel open.",tooltip:"The men who move that money also fund the party.",reveal:"You leave the over-invoicing pipeline flowing. Your backers keep stashing wealth abroad and stay loyal, and the reserves keep haemorrhaging out through a hole you chose not to plug.",effects:{FA:5,FI:-10,GL:-6}}},{id:"finance-0207",location:"finance",arc:"finance-t1-a52",stage:0,speaker:"Investment Authority Chief",portrait:"ambassador",tags:["sez","fdi","incentives"],prompt:"Deep into the reign, the issue demands a final-sounding answer. To lure foreign factories into the new economic zones, investors demand decade-long tax holidays, free land, and guaranteed power. The chief says the jobs and FDI are worth it; the revenue board warns you are giving away the future tax base to win a present photo-op.",left:{id:"a",label:"Grant the generous investor incentives.",tooltip:"An empty zone earns nothing; fill it at any price.",reveal:"You hand out the tax holidays and the factories come. Jobs and FDI flow in for the headlines, and the revenue board quietly notes the decade of tax you have signed away.",effects:{FI:3,EN:3,GL:3,RE:-3}},right:{id:"b",label:"Offer leaner, time-limited incentives.",tooltip:"A zone bought with the whole future is a bad bargain.",reveal:"You offer modest, sunset-clause incentives. Some footloose investors look elsewhere and the zones fill slower, but the deals that land actually pay tax within the decade.",effects:{FI:3,GL:-3,EN:2}}},{id:"finance-0208",location:"finance",arc:"finance-t1-a53",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["deficit","printing","inflation"],prompt:"The reckoning you postponed has matured into a crisis. The government is broke and the bills are due. The easiest fix is to have the central bank simply print money to cover the deficit — quick, painless today, and a slow detonator of inflation tomorrow. The governor warns it is the road every ruined economy has walked.",left:{id:"a",label:"Print money to cover the deficit.",tooltip:"A bill paid today is a bill paid.",reveal:"You lean on the printing press and the bills are met. The relief is immediate and the cost deferred, as the new money seeps into prices and the inflation you deferred compounds.",effects:{FI:5,EN:-13,GL:-6}},right:{id:"b",label:"Refuse to monetise the deficit.",tooltip:"A printing press is a slow-motion default.",reveal:"You hold the line against monetisation and cut or borrow instead. The squeeze is painful and immediate, but you spare the country the inflationary spiral that has ruined so many.",effects:{GL:3,FI:-6,EN:-3}}},{id:"finance-0209",location:"finance",arc:"finance-t1-a54",stage:0,speaker:"Agricultural Bank Chairman",portrait:"people",tags:["sme","farmers","credit"],prompt:"A new chapter, the same antagonists, less room to manoeuvre. Small farmers and tiny businesses are starved of credit, locked out by banks that lend only to the big and the connected. The chairman wants a subsidised small-credit drive to the grassroots — risky, costly, and politically golden — versus keeping lending safe and concentrated.",left:{id:"a",label:"Drive subsidised credit to the grassroots.",tooltip:"A loan to a farmer grows more than a loan to a tycoon.",reveal:"You push cheap credit out to farmers and micro-enterprises. Default risk and cost rise, but the rural economy stirs to life and millions feel the state's hand for the first time.",effects:{EN:8,FI:-10}},right:{id:"b",label:"Keep lending safe and concentrated.",tooltip:"A bank that lends to the poor is a bank that fails.",reveal:"You keep credit flowing to the safe and the big. The banks' books stay clean, and the small farmer and the micro-trader keep borrowing from the moneylender at ruinous rates.",effects:{FI:3,EN:-10,FA:2}}},{id:"finance-0210",location:"finance",arc:"finance-t1-a55",stage:0,speaker:"Treasury Operations Chief",portrait:"official",tags:["liquidity","festival","wages"],prompt:"The old fault line widens; this time there is no quiet option. Eid is days away and the garment factories cannot make payroll and bonuses for millions of workers, who will riot if sent home empty-handed for the holiday. The chief can extend emergency state liquidity to the owners, or let the owners face their own workers.",left:{id:"a",label:"Extend emergency liquidity to the factories.",tooltip:"A million unpaid workers at Eid is a powder keg.",reveal:"You bail out the payrolls and the workers go home paid for the holiday. The owners are rescued from their own mismanagement again, learning once more that the state will always catch them.",effects:{EN:6,FI:-10,FA:2}},right:{id:"b",label:"Let the owners face their workers.",tooltip:"I will not bankroll the bonuses of profitable men.",reveal:"You refuse the bailout and tell the owners to pay their own way. Some factories erupt in unrest over delayed wages, but the owners learn the treasury is not their overdraft.",effects:{FI:3,EN:-10,FA:-3}}},{id:"finance-0211",location:"finance",arc:"finance-t1-a56",stage:0,speaker:"Export Promotion Director",portrait:"official",tags:["exports","diversification","garments"],prompt:"Time has not healed it — the conflict comes back armed. The economy is dangerously dependent on garments for almost all its exports. The director wants to pour incentives into new sectors — pharma, leather, IT services, shipbuilding — a slow, uncertain bet, versus doubling down on the garment cash cow that already works.",left:{id:"a",label:"Invest in export diversification.",tooltip:"An economy on one leg falls when that leg is kicked.",reveal:"You back the emerging sectors with incentives and infrastructure. The payoff is slow and some bets will fail, but the export base begins, finally, to broaden beyond the loom.",effects:{FI:2,GL:3,EN:3,RE:2}},right:{id:"b",label:"Double down on garments.",tooltip:"Why bet on maybes when the looms pay now?",reveal:"You concentrate support on the proven garment sector. Exports stay strong and the cash flows, and the economy's single point of failure grows ever more dangerous and ever more entrenched.",effects:{FI:5,EN:-3,GL:-3}}},{id:"finance-0212",location:"finance",arc:"finance-t1-a57",stage:0,speaker:"Digital Economy Adviser",portrait:"people",tags:["it","freelancers","youth"],prompt:"Once again, and with the whole house holding its breath. Hundreds of thousands of young freelancers earn foreign currency online, but they are taxed clumsily, blocked from easy payment channels, and ignored. The adviser wants a freelancer-friendly regime of easy payments and tax breaks to grow a new export pillar.",left:{id:"a",label:"Build the freelancer-friendly regime.",tooltip:"A laptop in a village earns dollars from the world.",reveal:"You smooth payments, ease taxes, and back training for the digital workforce. A new stream of foreign currency grows, and a generation of the young find work without leaving home.",effects:{FI:5,EN:5,GL:2}},right:{id:"b",label:"Leave the freelancers to fend for themselves.",tooltip:"A scattered cottage industry is not a strategy.",reveal:"You keep the clumsy status quo. The freelancers route their earnings through grey channels or move abroad, and a homegrown export pillar withers before it can take root.",effects:{FI:-3,EN:-6,GL:-3}}},{id:"finance-0213",location:"finance",arc:"finance-t1-a58",stage:0,speaker:"Financial Intelligence Chief",portrait:"ambassador",tags:["capital-flight","second-homes","elite"],prompt:"The matter resurfaces in a harder year, patience exhausted. Exposés abroad reveal your elite — ministers, MPs, tycoons — own fortunes in foreign property they could never have earned honestly. The world offers cooperation to trace and freeze it. The chief asks whether to pursue the trail or quietly let it lie.",left:{id:"a",label:"Pursue and repatriate the hidden wealth.",tooltip:"Stolen money parked abroad still belongs to the people.",reveal:"You take up the foreign cooperation and chase the laundered fortunes home. Some assets are frozen and the public is electrified, but the exposed elite — your own ranks — declare quiet war.",effects:{FI:5,GL:5,EN:6,FA:-16}},right:{id:"b",label:"Let the trail go cold.",tooltip:"Half my cabinet owns those flats.",reveal:"You decline to pursue the foreign holdings. Your elite's offshore nest eggs stay safe and they stay loyal, and the message that the powerful loot with impunity is stamped a little deeper.",effects:{FA:6,FI:-6,EN:-13,GL:-10}}},{id:"finance-0214",location:"finance",arc:"finance-t1-a59",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["crypto","regulation","capital-controls"],prompt:"A later season of rule, the stakes now openly existential. Cryptocurrency is spreading among the young as a hedge against the falling taka and a hole in your capital controls. The governor can ban it outright as a laundering and flight risk, or regulate and tax it as an inevitable new asset.",left:{id:"a",label:"Ban cryptocurrency outright.",tooltip:"A currency I cannot see is a hole in the dam.",reveal:"You ban crypto and threaten the traders. The official capital controls hold a little better, but the trade simply goes underground, and the tech-savvy young add another grievance to the pile.",effects:{FI:2,MI:2,GL:-3,EN:-6}},right:{id:"b",label:"Regulate and tax it instead.",tooltip:"Better to tax the tide than to forbid it.",reveal:"You bring crypto into a regulated, taxed framework. The capital-flight risk is real and the controls leakier, but you tax the activity, attract some fintech, and keep faith with the young.",effects:{FI:3,GL:2,EN:2}}},{id:"finance-0215",location:"finance",arc:"finance-t1-a60",stage:0,speaker:"PPP Authority Chief",portrait:"fixer",tags:["ppp","infrastructure","contracts"],prompt:"It comes around again, and the margin for error is gone. A private consortium offers to build and run a major toll expressway under a public-private partnership — sparing the budget the upfront cost, but locking the public into decades of toll payments and a sweetheart guarantee that the state covers any shortfall.",left:{id:"a",label:"Sign the PPP with the state guarantee.",tooltip:"Roads now, paid for by tomorrow's tolls.",reveal:"The expressway gets built without upfront state money. The consortium pockets guaranteed returns for decades, and the 'minimum revenue' clause quietly hands the risk back to the public purse.",effects:{RE:3,FI:2,EN:2,GL:-3}},right:{id:"b",label:"Demand fair terms or build it publicly.",tooltip:"A guarantee that the state eats all losses is a gift, not a partnership.",reveal:"You refuse the lopsided guarantee and renegotiate or build it yourself. The road is slower to come and the budget strained, but the public is not signed up to underwrite private profit.",effects:{FI:-6,EN:2,GL:2}}},{id:"finance-0216",location:"finance",arc:"finance-t1-a61",stage:0,speaker:"Planning Commission Member",portrait:"official",tags:["development-budget","spending","quality"],prompt:"The same demand, but the reign is older and the knives sharper. The annual development budget is chronically rushed out in the final months in a splurge of low-quality, padded projects, so the money is 'spent' on paper. The member wants a shift to fewer, well-vetted projects — slower disbursement, better roads — over the year-end dash.",left:{id:"a",label:"Reform toward fewer, better projects.",tooltip:"A road built twice is a road paid for thrice.",reveal:"You impose vetting and steady disbursement over the year-end splurge. The 'utilisation' numbers dip and the contractors grumble, but the projects that get built actually last.",effects:{FI:3,EN:5,GL:2,FA:-3}},right:{id:"b",label:"Keep the year-end spending dash.",tooltip:"Unspent money is a bureaucrat's failure on paper.",reveal:"You let the final-quarter splurge continue. The disbursement targets are hit and everyone looks busy, and the padded, half-built projects crumble within a season or two.",effects:{FA:2,FI:-3,EN:-10}}},{id:"finance-0217",location:"finance",arc:"finance-t1-a62",stage:0,speaker:"Microfinance Regulator",portrait:"people",tags:["microfinance","debt","poverty"],prompt:"Years deep, the unresolved returns to be resolved for good. The microfinance sector that the country pioneered now risks over-lending, trapping the rural poor in spirals of debt to multiple lenders at high effective rates. The regulator wants caps and a shared credit registry; the big MFIs, politically influential, resist.",left:{id:"a",label:"Cap rates and build a debt registry.",tooltip:"A loan that traps is no longer a ladder.",reveal:"You cap effective rates and require a shared registry to stop multiple-lending. The big lenders fight the limits, but the rural poor stop drowning under stacked, overlapping loans.",effects:{EN:6,GL:2,FI:-3,FA:-3}},right:{id:"b",label:"Leave the sector to self-regulate.",tooltip:"Do not break the model the world copied.",reveal:"You leave the MFIs to their own devices. The model's reputation is preserved, and in the villages the quiet debt spirals tighten, household by over-borrowed household.",effects:{FI:2,FA:2,EN:-10}}},{id:"finance-0218",location:"finance",arc:"finance-t1-a63",stage:0,speaker:"Defence Finance Secretary",portrait:"general",tags:["defence","budget","spending"],prompt:"The conflict reignites, and the world is watching this time. The military, restive and powerful, wants a major budget increase for new hardware and perks — loyalty insurance for a government that needs the barracks onside. The secretary notes the money would gut the social spending you have promised the public.",left:{id:"a",label:"Grant the military budget increase.",tooltip:"A contented barracks is a sleeping coup.",reveal:"You fund the military's wish-list and the brass is reassured of your favour. The barracks stay loyal, and the schools, clinics, and pensions you promised the public quietly shrink to pay for it.",effects:{MI:6,FA:2,FI:-10,EN:-10}},right:{id:"b",label:"Hold the defence budget, fund the public.",tooltip:"A nation is defended by its people's wellbeing too.",reveal:"You hold the line on defence and protect social spending. The public services hold, but the generals feel slighted and watched, and a restive barracks is a risk you now carry.",effects:{EN:6,GL:2,MI:-10,FI:-3}}},{id:"finance-0219",location:"finance",arc:"finance-t1-a64",stage:0,speaker:"Auditor General",portrait:"official",tags:["reserves","transparency","audit"],prompt:"A familiar crisis, escalated by everything you let slide. The true, spendable level of the foreign reserves has been quietly overstated for years by counting funds that are already committed. An honest restatement would calm no one and spook the markets; continued obfuscation buys time but compounds the eventual reckoning.",left:{id:"a",label:"Publish the honest, lower reserve figure.",tooltip:"A number built on a lie collapses worse later.",reveal:"You restate the reserves truthfully. The markets and the public are rattled by the lower figure, but the credibility you buy with honesty steadies the longer game and the IMF's trust.",effects:{GL:5,FI:-6,EN:-3}},right:{id:"b",label:"Keep counting the committed funds.",tooltip:"A panic today is worse than a problem deferred.",reveal:"You keep the flattering figure on the books. The markets stay calm on a number that is not real, and the day the truth finally surfaces, the fall will be all the further.",effects:{FI:3,GL:-10,EN:-3}}},{id:"finance-0220",location:"finance",arc:"finance-t1-a65",stage:0,speaker:"Bank Inspection Chief",portrait:"shadow",tags:["fraud","banks","scandal"],prompt:"The fault line cracks wider; the decision can no longer wait. A colossal loan fraud has surfaced at a state bank — thousands of crores siphoned out on forged collateral by a ring with reach into the board and the regulator. The chief can mount a full, public investigation, or contain it quietly to protect confidence and connected names.",left:{id:"a",label:"Order a full public investigation.",tooltip:"A fraud buried festers into a collapse.",reveal:"You open a transparent probe and the arrests climb toward the boardroom and beyond. Confidence wobbles at the spectacle, but the looters face justice and the system is forced to clean house.",effects:{GL:5,EN:5,FI:-6,FA:-10}},right:{id:"b",label:"Contain it quietly.",tooltip:"A public scandal runs the depositors to the doors.",reveal:"You keep the fraud out of the headlines and settle it in the dark. Confidence holds on the surface, the connected escape, and the hole in the bank is quietly stuffed with public money.",effects:{FI:2,FA:3,EN:-10,GL:-10}}},{id:"finance-0221",location:"finance",arc:"finance-t1-a65",stage:1,speaker:"Bank Inspection Chief",portrait:"shadow",tags:["fraud","banks","scandal"],prompt:"Late in the reign, the old question demands a heavier answer. Your handling of the first fraud set the tone, and now a second bank reports a similar hole. The chief warns that the rot is systemic and demands a sweeping regulatory overhaul with real independence — which would clip the wings of the very politicians who appoint the boards.",left:{id:"a",label:"Grant the regulator real independence.",tooltip:"A watchdog on the owner's leash guards nothing.",reveal:"You hand the banking regulator genuine independence and teeth. The politicians who packed the boards lose their grip and rage, but the banking sector gains its first real check in a generation.",effects:{GL:5,EN:5,FI:2,FA:-10}},right:{id:"b",label:"Keep the regulator under political control.",tooltip:"An independent watchdog bites the hand that feeds the party.",reveal:"You keep the regulator pliant. The board appointments stay a political spoil, the frauds keep their cover, and the banking system slides deeper toward a reckoning no one is watching for.",effects:{FA:5,FI:-6,EN:-10,GL:-6}}},{id:"finance-0222",location:"finance",arc:"finance-t1-a66",stage:0,speaker:"Remittance Policy Director",portrait:"people",tags:["remittances","incentive","reserves"],prompt:"It returns once more — and this round may be the one remembered. Remittances are slipping into the illegal hundi channel because the official rate is poor. The director proposes a cash incentive on every dollar sent home through banks — costly to the budget, but a magnet to pull billions back into the reserves.",left:{id:"a",label:"Fund the remittance cash incentive.",tooltip:"A bonus on every dollar is a dollar in the vault.",reveal:"You pay the incentive and the official remittances surge as hundi loses its edge. The budget takes a real hit, but the reserves swell with the inflows you lured back into the light.",effects:{FI:5,EN:3,GL:2}},right:{id:"b",label:"Skip the incentive to save the budget.",tooltip:"I will not pay people to do what they should anyway.",reveal:"You forgo the incentive. The budget is spared the cost, but the remittances keep leaking into hundi, the reserves miss the inflows, and the black-market dollar keeps its premium.",effects:{FI:-6,EN:-3,GL:-3}}},{id:"finance-0223",location:"finance",arc:"finance-t1-a66",stage:1,speaker:"Remittance Policy Director",portrait:"people",tags:["remittances","incentive","reserves"],prompt:"The reckoning circles back, grown teeth in the waiting. The incentive worked, but exporters cry foul: the same scheme that lifts remittances has effectively given migrant dollars a better rate than export dollars, and the garment lobby demands equal treatment or threatens to hold earnings offshore.",left:{id:"a",label:"Extend the incentive to exporters too.",tooltip:"One dollar should be worth another, whoever earned it.",reveal:"You level the field and incentivise export proceeds as well. The reserves keep filling and the exporters are placated, but the budget's incentive bill balloons toward the unsustainable.",effects:{FI:2,GL:2,EN:-3}},right:{id:"b",label:"Hold the line, remittances only.",tooltip:"I cannot subsidise every dollar in the economy.",reveal:"You refuse to widen the scheme. The budget is protected, but the garment lobby retaliates by parking earnings abroad, and some of the reserve gain leaks back out the other side.",effects:{FI:2,FA:-3,GL:-3}}},{id:"finance-0224",location:"finance",arc:"finance-t1-a67",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["imports","lc","reserves"],prompt:"Another term, the same antagonist, the stakes raised again. To stem the reserve drain, the governor can choke the letters of credit that finance imports — banning 'luxury' goods and rationing dollars. It saves precious reserves, but it also starves factories of raw materials and spawns a corrupt queue for who gets a dollar.",left:{id:"a",label:"Clamp down hard on import LCs.",tooltip:"A dollar saved is a dollar that stays in the vault.",reveal:"You ration the LCs and the reserve bleed slows. Factories starved of imported inputs cut shifts, a black market in LC approvals blooms, and the well-connected jump the dollar queue.",effects:{FI:5,EN:-10,FA:2,GL:-3}},right:{id:"b",label:"Keep imports flowing, defend reserves elsewhere.",tooltip:"A factory without inputs is a layoff with a delay.",reveal:"You keep the import channel open and seek savings elsewhere. Industry keeps running and no corrupt LC queue forms, but the reserves keep draining toward the danger line.",effects:{EN:3,FI:-10,GL:2}}},{id:"finance-0225",location:"finance",arc:"finance-t1-a67",stage:1,speaker:"Central Bank Governor",portrait:"official",tags:["imports","lc","reserves"],prompt:"The matter, long deferred, lands with the force of a verdict. The import curbs hit a nerve: shortages of medicines, industrial inputs, and even some foods are biting, and the manufacturers warn of mass layoffs. The governor asks whether to keep the squeeze or selectively reopen the most essential imports.",left:{id:"a",label:"Hold the squeeze to protect reserves.",tooltip:"The reserves must come first or nothing else holds.",reveal:"You maintain the clampdown. The reserves are defended, but the shortages deepen into closed factories and empty pharmacy shelves, and the hardship radiates through the economy.",effects:{FI:5,EN:-13,GL:-3}},right:{id:"b",label:"Reopen essential imports selectively.",tooltip:"I will not ration medicine to save a statistic.",reveal:"You carve out medicines, food, and key inputs from the curbs. The reserve relief is smaller, but the worst shortages ease and the factories keep their workers on the line.",effects:{EN:5,FI:-6,GL:2}}},{id:"finance-0226",location:"finance",arc:"finance-t1-a68",stage:0,speaker:"Statistics Bureau Chief",portrait:"shadow",tags:["gdp","statistics","credibility"],prompt:"Years on and unhealed, the conflict returns to claim its answer. The bureau can 'rebase' and massage the GDP figures to show a glittering growth rate that flatters your rule and tops the regional league tables. Economists already mutter that the numbers do not match the power use or the imports. The chief awaits your nod.",left:{id:"a",label:"Publish the flattering growth figures.",tooltip:"A nation grows as fast as its statistics say.",reveal:"You release the burnished numbers and top the league tables. The applause is real and the doubt is louder; when reality diverges from the data, the whole record becomes suspect.",effects:{FI:3,GL:2,EN:-10}},right:{id:"b",label:"Publish honest, humbler figures.",tooltip:"A growth rate I have to defend is not growth.",reveal:"You release credible numbers, modest as they are. The headlines are duller and rivals crow, but the data the country plans by — and the lenders trust — stays sound.",effects:{GL:3,EN:2,FI:-6}}},{id:"finance-0227",location:"finance",arc:"finance-t1-a69",stage:0,speaker:"Wage Commission Chair",portrait:"people",tags:["wages","labour","cost"],prompt:"The same fault line, the harder hour, the narrower path. A national minimum wage covering every sector would lift millions of the working poor — and the employers, your donors, warn it will price out jobs and torch competitiveness. The chair needs the level set.",left:{id:"a",label:"Set a meaningful national minimum wage.",tooltip:"A wage too low to live on is a subsidy to the boss.",reveal:"You set a real floor under wages. Millions of the working poor breathe easier, the donors howl about competitiveness, and a few marginal employers do shed jobs.",effects:{EN:8,FI:-6,FA:-6}},right:{id:"b",label:"Keep wages to the market.",tooltip:"A floor too high empties the factory.",reveal:"You leave wages to the market and the donors content. Competitiveness is protected and the jobs stay, and the working poor keep grinding at a wage that never quite covers the rent.",effects:{FI:3,FA:3,EN:-13}}},{id:"finance-0228",location:"finance",arc:"finance-t1-a70",stage:0,speaker:"Consumer Protection Director",portrait:"shadow",tags:["e-commerce","ponzi","fraud"],prompt:"It comes back sharpened by every season you survived. A wildly popular e-commerce platform turns out to be a Ponzi scheme — taking advance payments for goods it never delivers, with hundreds of thousands of customers' money gone. The director can move now to freeze and prosecute, or hesitate while the founders flee.",left:{id:"a",label:"Freeze and prosecute immediately.",tooltip:"A scam this size will not be allowed to vanish.",reveal:"You freeze the accounts and arrest the founders before they bolt. Some customer money is clawed back, and the swift action signals that the digital wild-west has a sheriff at last.",effects:{EN:6,GL:3,FI:2}},right:{id:"b",label:"Move slowly and study the case.",tooltip:"A hasty freeze could spook the whole sector.",reveal:"You proceed cautiously and the founders launder and flee. The customers' money evaporates, the scandal metastasises, and trust in the entire e-commerce sector collapses.",effects:{FI:-6,EN:-13,GL:-6}}},{id:"finance-0229",location:"finance",arc:"finance-t1-a71",stage:0,speaker:"Bank Inspection Chief",portrait:"shadow",tags:["nbfi","embezzlement","regulator"],prompt:"A later year of power, the old crisis now a true test of it. A non-bank financial institution has been looted to its bones by a single fugitive operator who captured its board and siphoned out a fortune — with the regulator asleep or complicit. The chief asks whether to pursue the fugitive and the enablers, or quietly write it off.",left:{id:"a",label:"Pursue the fugitive and the enablers.",tooltip:"A theft this brazen demands a reckoning.",reveal:"You launch an international pursuit and turn the lens on the regulators who slept. The fugitive is hunted and some enablers fall, and the financial watchdogs are forced, painfully, to wake.",effects:{GL:5,EN:5,FA:-10,FI:2}},right:{id:"b",label:"Write it off quietly.",tooltip:"A public hunt only advertises how deep the rot runs.",reveal:"You let the loss be quietly absorbed. The fugitive keeps his fortune abroad, the sleeping regulators keep their jobs, and the next operator notes how softly a billion can be stolen here.",effects:{FA:3,FI:-6,EN:-10,GL:-6}}},{id:"finance-0230",location:"finance",arc:"finance-t1-a72",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["autonomy","monetary","independence"],prompt:"The unresolved returns, and this time it will not be deferred. The finance ministry wants the central bank to bend monetary policy to the government's election-year wishes — cheap credit, a propped currency, printed money — over the governor's professional judgment. He asks you to protect his independence, or to bring the bank to heel.",left:{id:"a",label:"Bring the central bank to heel.",tooltip:"A bank that defies the government is a rival.",reveal:"You subordinate the central bank to the ministry's will. The election-year sugar flows, and the institution's hard-won credibility — the thing that anchors inflation and the currency — bleeds away.",effects:{FI:3,MI:2,GL:-10,EN:-6}},right:{id:"b",label:"Protect the central bank's independence.",tooltip:"A tame central bank is a slow-motion crisis.",reveal:"You shield the governor's autonomy. The ministry fumes at being denied its election-year levers, but the bank keeps the credibility that holds the currency and the lenders' trust.",effects:{GL:5,FI:-3,EN:2}}},{id:"finance-0231",location:"finance",arc:"finance-t1-a73",stage:0,speaker:"Food Directorate Chief",portrait:"people",tags:["procurement","farmers","rice"],prompt:"A term later, the same fault line tears open again. Harvest is in, and you set the price at which the state buys rice from farmers. A high procurement price rewards the farmer and floods the public granary at cost; a low one saves money but leaves the grower at the mercy of the millers' cartel.",left:{id:"a",label:"Set a high, farmer-friendly price.",tooltip:"A farmer paid fairly plants again.",reveal:"You buy at a generous price and fill the granary. The growers prosper and the food reserve swells, at a real cost to the budget that the millers' cartel would have pocketed anyway.",effects:{EN:6,FI:-10}},right:{id:"b",label:"Set a low procurement price.",tooltip:"The granary cannot bankrupt the treasury.",reveal:"You buy cheap and save the budget. The granary fills at less cost, but the farmer, undercut, sells to the millers' cartel at a loss and curses the season.",effects:{FI:5,EN:-10}}},{id:"finance-0232",location:"finance",arc:"finance-t1-a74",stage:0,speaker:"Food Directorate Chief",portrait:"relief",tags:["oms","inflation","poor"],prompt:"Years into your rule, the matter you thought buried resurfaces — harder. Food prices have spiked and the urban poor are skipping meals. The chief can throw open the state granary in subsidised open-market sales across the cities — costly, and a magnet for skimming — or hold the reserve against a worse shortage to come.",left:{id:"a",label:"Open the granary in subsidised sales.",tooltip:"A hungry city is a city on the edge.",reveal:"You flood the cities with cheap state rice and the queues ease. The reserve drains and skimming creeps in at the trucks, but the poor eat and the streets stay calm.",effects:{EN:6,FI:-6}},right:{id:"b",label:"Hold the reserve for a worse day.",tooltip:"A granary emptied early starves a later crisis.",reveal:"You ration the reserve against future shortage. The budget and the buffer are protected, but the urban poor go hungry now, and the resentment simmers in the bread queues.",effects:{FI:3,EN:-13}}},{id:"finance-0233",location:"finance",arc:"finance-t1-a75",stage:0,speaker:"Social Protection Director",portrait:"people",tags:["cash-transfer","education","poverty"],prompt:"A new season of power, an old problem with sharper teeth. A conditional cash-transfer scheme would pay poor mothers to keep their children in school and at the clinic — proven to cut poverty and stunting — but it demands a vast, well-run delivery system and a permanent budget line the finance hawks resist.",left:{id:"a",label:"Launch the conditional cash transfer.",tooltip:"Money to a mother for her child's schooling pays back for decades.",reveal:"You build the scheme and the payments reach poor mothers. The delivery is a logistical mountain and the budget line permanent, but school attendance climbs and a poverty cycle starts to break.",effects:{EN:8,GL:3,FI:-13}},right:{id:"b",label:"Stick with cheaper in-kind handouts.",tooltip:"A grand transfer scheme is a budget I cannot promise forever.",reveal:"You keep the patchy in-kind handouts instead. The budget is spared the permanent commitment, and the chance to bind relief to schooling and health is left on the table.",effects:{FI:3,EN:-6}}},{id:"finance-0234",location:"finance",arc:"finance-t1-a76",stage:0,speaker:"Revenue Board Chairman",portrait:"official",tags:["property-tax","wealth","elite"],prompt:"The crisis returns, and this time the cabinet is watching. The cities are full of untaxed mansions and empty investment flats hoarded by the rich, while the state scrapes for revenue. A real property tax would tap that idle wealth — and fall squarely on the affluent, donors and dynasts among them.",left:{id:"a",label:"Introduce a real property tax.",tooltip:"A palace should pay more than a payslip.",reveal:"You bring in a genuine property tax on the high end. The revenue base broadens onto idle wealth, the affluent grumble and lobby, and for once the rich shoulder a fair share.",effects:{FI:6,EN:5,FA:-10,GL:2}},right:{id:"b",label:"Leave property lightly taxed.",tooltip:"The men in those mansions are the men who fund me.",reveal:"You leave the mansions and empty flats lightly taxed. The donors are content and their wealth stays idle and untouched, and the revenue gap is filled, as ever, by those who cannot dodge.",effects:{FA:3,FI:-6,EN:-10}}},{id:"finance-0235",location:"finance",arc:"finance-t1-a77",stage:0,speaker:"Revenue Board Chairman",portrait:"ambassador",tags:["digital-tax","big-tech","revenue"],prompt:"Once more the issue lands on your desk, the stakes higher than before. The global tech giants earn fortunes in advertising and services here while paying almost no tax. A digital-services tax would capture that — and risk retaliation, throttled services, and a quarrel with Washington that other files cannot afford.",left:{id:"a",label:"Impose the digital-services tax.",tooltip:"A giant that earns here pays here.",reveal:"You tax the tech giants' local earnings. The revenue is real and popular, but the platforms threaten to throttle services and Washington adds it to a list of grievances against you.",effects:{FI:5,GL:-6,EN:2}},right:{id:"b",label:"Hold off to avoid the quarrel.",tooltip:"A fight with the platforms and Washington at once is a fight I lose.",reveal:"You shelve the tax to keep the peace. The giants keep earning tax-free, the revenue stays forgone, and your dependence on their services and Washington's goodwill stays unchallenged.",effects:{GL:2,FI:-6}}},{id:"finance-0236",location:"finance",arc:"finance-t1-a78",stage:0,speaker:"Debt Management Director",portrait:"ambassador",tags:["diaspora-bond","infrastructure","funding"],prompt:"Another year survived, and the reckoning circles back. You can raise development funds by selling a patriotic bond to the diaspora — cheaper than markets, binding the expatriates to the homeland — but a default or a scandal would betray the very people who trusted you most, and they vote and remit.",left:{id:"a",label:"Issue the diaspora infrastructure bond.",tooltip:"Let the children abroad help build the home.",reveal:"The diaspora subscribes generously and the projects get cheap funding. You have also taken the savings of trusting expatriates, and any stumble in repayment would be a betrayal felt worldwide.",effects:{FI:5,GL:2,RE:2}},right:{id:"b",label:"Fund development through other means.",tooltip:"I will not stake my people's trust on a bond.",reveal:"You decline to tap the diaspora's savings. The funding is costlier and slower, but you do not put the expatriates' faith — and their remittances — on the line.",effects:{GL:2,FI:-6}}},{id:"finance-0237",location:"finance",arc:"finance-t1-a79",stage:0,speaker:"Agriculture Finance Secretary",portrait:"people",tags:["diesel","irrigation","subsidy"],prompt:"The ground has shifted; the same demand arrives with new menace. Diesel for the irrigation pumps has spiked with world prices, threatening the boro rice crop that feeds the nation. The secretary wants an emergency diesel subsidy for farmers — costly and leak-prone — or you can let the fuel price pass through to the field.",left:{id:"a",label:"Fund the emergency irrigation subsidy.",tooltip:"A dry pump in boro season is a famine in waiting.",reveal:"You subsidise the diesel and the pumps keep running through the dry season. The crop is saved and the farmers grateful, at a heavy cost and with the usual leakage at the depots.",effects:{EN:6,RE:2,FI:-10}},right:{id:"b",label:"Let the fuel price pass through.",tooltip:"I cannot subsidise the world's oil price for every pump.",reveal:"You let the diesel cost hit the field. The budget is spared, but the irrigation falters, the boro crop wobbles, and the spectre of a thin harvest looms over the year.",effects:{FI:3,EN:-10,RE:-3}}},{id:"finance-0238",location:"finance",arc:"finance-t1-a80",stage:0,speaker:"Revenue Board Chairman",portrait:"official",tags:["sin-tax","health","revenue"],prompt:"History rhymes: the conflict reopens deeper than last time. Steep new taxes on tobacco, sugary drinks, and processed junk would raise revenue and improve public health at once — a rare win-win — but the powerful food and tobacco lobbies, and the price-sensitive public, will both push back hard.",left:{id:"a",label:"Impose the health-protecting sin taxes.",tooltip:"A tax that fills the treasury and empties the wards is a gift.",reveal:"You levy the sin taxes and revenue and health both improve. The lobbies fight and the public grumbles at pricier vices, but consumption of the worst products begins to fall.",effects:{FI:5,EN:5,FA:-6}},right:{id:"b",label:"Spare the consumer and the lobbies.",tooltip:"A new tax on small pleasures is a small revolt.",reveal:"You hold off on the sin taxes. The lobbies and the public are spared, and so is the disease and the revenue forgone, as the wards fill and the treasury stays thin.",effects:{FA:2,FI:-6,EN:-6}}},{id:"finance-0239",location:"finance",arc:"finance-t1-a81",stage:0,speaker:"Budget Secretary",portrait:"official",tags:["fiscal-rule","debt","discipline"],prompt:"Mid-reign, the old wound is torn afresh. A fiscal-responsibility law would cap the deficit and debt by statute, binding you and every successor to discipline — a credibility prize for the lenders, and a self-imposed straitjacket that forbids the populist splurges that win elections.",left:{id:"a",label:"Enact the binding fiscal rule.",tooltip:"A state that cannot bind itself cannot be trusted.",reveal:"You pass the fiscal-responsibility law. The lenders cheer the credibility and the markets calm, and you have tied your own hands against the easy election-year splurge.",effects:{GL:5,FI:3,EN:-3}},right:{id:"b",label:"Keep your fiscal hands free.",tooltip:"A rule that forbids me to spend in a crisis is a trap.",reveal:"You decline the statutory cap. You keep the freedom to splurge when politics demands, and the lenders keep their doubt about whether the deficit will ever truly be controlled.",effects:{FI:-3,EN:2,GL:-6}}},{id:"finance-0240",location:"finance",arc:"finance-t1-a82",stage:0,speaker:"Large Taxpayer Unit Chief",portrait:"official",tags:["transfer-pricing","multinationals","evasion"],prompt:"The pressure you deferred has come due, larger now. Multinational firms shift their local profits abroad through rigged internal pricing, paying almost no tax here. The chief wants a hard transfer-pricing crackdown to capture that revenue; the firms threaten to scale back investment and lobby their embassies.",left:{id:"a",label:"Crack down on transfer-pricing abuse.",tooltip:"Profits earned here should be taxed here.",reveal:"You enforce transfer-pricing rules and claw back real revenue. The multinationals grumble and a few trim investment, but the era of booking local fortunes as foreign losses ends.",effects:{FI:6,GL:2,EN:2}},right:{id:"b",label:"Tread softly to keep the investors sweet.",tooltip:"A spooked multinational takes its factory elsewhere.",reveal:"You go easy to protect the investment climate. The firms keep shifting their profits offshore tax-free, and the revenue you could have captured stays on a balance sheet in another country.",effects:{GL:2,FI:-10}}},{id:"finance-0241",location:"finance",arc:"finance-t1-a83",stage:0,speaker:"Agriculture Finance Secretary",portrait:"people",tags:["insurance","farmers","climate"],prompt:"A later term, and the quarrel has hardened into a test. Floods, cyclones, and droughts wipe out farmers' crops and push them into ruinous debt every year. A subsidised crop-insurance scheme would cushion them against the climate — a costly, complex new system, versus the cheaper status quo of ad-hoc disaster relief.",left:{id:"a",label:"Build the subsidised crop-insurance scheme.",tooltip:"A farmer insured plants without fear.",reveal:"You stand up crop insurance for the climate-battered. The system is costly and complex to run, but a ruined harvest no longer means a ruined family, and the farmers plant with confidence.",effects:{EN:6,RE:2,FI:-10}},right:{id:"b",label:"Stick with ad-hoc disaster relief.",tooltip:"A whole insurance system is a luxury; relief is enough.",reveal:"You keep the patchy, after-the-fact relief. It is cheaper and simpler, and each disaster still sweeps another cohort of farmers from their land into the moneylender's grip.",effects:{FI:3,EN:-6}}},{id:"finance-0242",location:"finance",arc:"finance-t1-a84",stage:0,speaker:"Provident Fund Trustee",portrait:"official",tags:["pension-fund","investment","risk"],prompt:"The country has changed, but this fault line has not — only worsened. The vast public provident and pension funds sit in low-yield government paper. A reform would let them invest in markets and infrastructure for higher returns — and expose millions of workers' retirements to risk, manipulation, and the temptation to fund pet projects.",left:{id:"a",label:"Let the funds chase higher market returns.",tooltip:"Idle retirement money should work harder.",reveal:"You free the funds to invest in markets and infrastructure. Returns rise in good years, but the workers' retirements now ride the market's moods, and the temptation to steer them into pet projects is real.",effects:{FI:3,RE:2,EN:-6}},right:{id:"b",label:"Keep retirement money safe and dull.",tooltip:"A pensioner's savings are not a venture fund.",reveal:"You keep the funds in safe, dull government paper. The returns are modest, but the workers' retirements are not gambled on markets or raided for politically favoured schemes.",effects:{EN:3,FI:-3}}},{id:"finance-0243",location:"finance",arc:"finance-t1-a85",stage:0,speaker:"Stimulus Coordination Chief",portrait:"fixer",tags:["stimulus","sme","leakage"],prompt:"It returns, as these things do, with the patience gone. A huge emergency stimulus must flow fast to keep firms alive through a shock — but speed means weak controls, and the big, connected firms are already first in the queue while the small ones that need it most have no bank relationship to claim it.",left:{id:"a",label:"Push the money out fast through the banks.",tooltip:"Speed saves firms; controls can come later.",reveal:"You disburse fast through the banks, and the big connected firms hoover up the lion's share. Many are saved, but the small firms that needed it most are left out, and the leakage is enormous.",effects:{FI:3,FA:3,EN:-10}},right:{id:"b",label:"Build a fair channel to the small firms.",tooltip:"A stimulus that feeds the fed is no stimulus.",reveal:"You insist on a slower channel that reaches the genuinely small and informal. The big firms wait and grumble and a few fail in the delay, but the rescue reaches those it was meant for.",effects:{EN:6,FI:-6,FA:-6}}},{id:"finance-0244",location:"finance",arc:"finance-t1-a86",stage:0,speaker:"Securities Regulator",portrait:"shadow",tags:["ipo","market","manipulation"],prompt:"Years on, the matter is no longer private; the press is already circling. A wave of companies wants to list, and insiders are pricing the IPOs to enrich a favoured few before dumping on the retail crowd. The regulator can enforce fair, fundamentals-based pricing — slowing the listings — or let the lucrative game run.",left:{id:"a",label:"Enforce fair IPO pricing.",tooltip:"A market rigged at the listing is rotten at the root.",reveal:"You impose disciplined, fundamentals-based pricing. The listings slow and the insiders lose their easy killing, but the retail investor stops being the designated bag-holder.",effects:{GL:3,EN:5,FI:-3,FA:-3}},right:{id:"b",label:"Let the listing game run.",tooltip:"A busy market looks like a healthy one.",reveal:"You let the rigged IPOs flow. The market looks vibrant and the insiders prosper, and the small investors who buy the dumped shares learn, again, who the market is really for.",effects:{FI:3,FA:2,EN:-10}}},{id:"finance-0245",location:"finance",arc:"finance-t1-a87",stage:0,speaker:"Banking Division Secretary",portrait:"official",tags:["banks","exposure","concentration"],prompt:"The same knot, retied tighter, lands before you once more. A few giant business groups have borrowed so heavily from the banks that the failure of any one could topple the system. The secretary wants strict single-borrower limits enforced; the groups — major donors — call it a chokehold on the engines of the economy.",left:{id:"a",label:"Enforce strict single-borrower limits.",tooltip:"A bank chained to one tycoon falls with him.",reveal:"You force the concentration down. The over-leveraged groups must deleverage and protest bitterly, but the banking system stops being hostage to a handful of empires.",effects:{FI:3,GL:3,EN:3,FA:-10}},right:{id:"b",label:"Relax the limits for the big groups.",tooltip:"The great groups are the engines; do not stall them.",reveal:"You let the concentration ride. The tycoons keep borrowing freely and stay loyal, and the system's fate stays welded to a few balance sheets that are too big to fail and too connected to refuse.",effects:{FI:2,FA:3,EN:-6,GL:-6}}},{id:"finance-0246",location:"finance",arc:"finance-t1-a88",stage:0,speaker:"Banking Division Secretary",portrait:"fixer",tags:["banks","family-control","governance"],prompt:"Another monsoon, another return of an argument you cannot end. A law lets a single family hold a bank's board for years through multiple directorships — a recipe for the insider looting that has hollowed banks before. A reform would break the family grip; the banking dynasties, deeply tied to your party, will fight it.",left:{id:"a",label:"Break the family grip on bank boards.",tooltip:"A bank run as a family fief gets looted as one.",reveal:"You cap family directorships and tenure. The banking dynasties rage and lean on their party ties, but the boards open up and the insider-looting machine loses its grease.",effects:{GL:5,EN:5,FI:2,FA:-13}},right:{id:"b",label:"Preserve the family directorships.",tooltip:"The banking families are pillars of the party.",reveal:"You keep the family-control law intact. The dynasties stay grateful and entrenched, and the next hollowed-out bank is already being quietly emptied by the board that owns it.",effects:{FA:5,FI:-3,EN:-10,GL:-6}}},{id:"finance-0247",location:"finance",arc:"finance-t1-a89",stage:0,speaker:"Tariff Commission Chief",portrait:"official",tags:["dumping","tariffs","industry"],prompt:"Deep into the reign, the issue demands a final-sounding answer. A flood of cheap, possibly dumped, foreign goods is undercutting your domestic manufacturers. The chief can slap on protective anti-dumping duties to save the local industry and jobs — raising prices for consumers — or keep the market open and cheap.",left:{id:"a",label:"Impose protective anti-dumping duties.",tooltip:"A factory drowned in cheap imports is a town unemployed.",reveal:"You shield the domestic industry with duties. The local manufacturers and their workers are saved, the exporting nation protests to the trade body, and consumers pay more for the protected goods.",effects:{FI:2,EN:3,GL:-6}},right:{id:"b",label:"Keep the market open and cheap.",tooltip:"A consumer's cheap goods are a benefit too.",reveal:"You leave the market open. Consumers enjoy the cheap imports, but the domestic factories buckle and shed jobs, hollowing out the very industry you hoped to grow.",effects:{GL:2,FI:-3,EN:-6}}},{id:"finance-0248",location:"finance",arc:"finance-t1-a90",stage:0,speaker:"Budget Secretary",portrait:"official",tags:["soe","losses","transparency"],prompt:"The reckoning you postponed has matured into a crisis. The state enterprises' staggering losses are hidden off-budget, quietly funded by directed bank loans and never shown to parliament. The secretary can bring them onto the books for honest accounting — a shocking number — or keep them comfortably in the shadows.",left:{id:"a",label:"Bring the SOE losses onto the budget.",tooltip:"A loss hidden is a debt compounding in the dark.",reveal:"You consolidate the hidden losses into the open budget. The true deficit number shocks, but the lenders respect the honesty and the bleeding enterprises can finally be confronted.",effects:{GL:5,EN:2,FI:-6}},right:{id:"b",label:"Keep the losses off-budget.",tooltip:"An ugly number published is a panic invited.",reveal:"You leave the SOE losses in the shadows. The headline deficit stays flattering, and the hidden hole keeps growing, funded by banks that will one day present the bill.",effects:{FI:3,GL:-10,EN:-3}}},{id:"finance-0249",location:"finance",arc:"finance-t1-a91",stage:0,speaker:"Anti-Money-Laundering Director",portrait:"ambassador",tags:["fatf","compliance","reputation"],prompt:"A new chapter, the same antagonists, less room to manoeuvre. The global financial watchdog threatens to grey-list the country over weak money-laundering and terror-financing controls — a label that would choke correspondent banking and scare investors. Fixing it means real enforcement against laundering your own backers enjoy.",left:{id:"a",label:"Enforce hard to avoid the grey list.",tooltip:"A grey-listed nation is a nation cut off.",reveal:"You build genuine anti-laundering enforcement and dodge the listing. Correspondent banking stays open and investors calm, but your backers' laundering channels are now watched, and they are furious.",effects:{GL:6,FI:3,FA:-10}},right:{id:"b",label:"Do the minimum and risk the listing.",tooltip:"I will not strangle my friends' money to please a watchdog.",reveal:"You make cosmetic changes and your backers keep their channels. The watchdog grey-lists you, correspondent banks pull back, and the cost of every cross-border transaction climbs.",effects:{FA:3,GL:-13,FI:-10}}},{id:"finance-0250",location:"finance",arc:"finance-t1-a92",stage:0,speaker:"Land Reform Commissioner",portrait:"official",tags:["benami","property","corruption"],prompt:"The old fault line widens; this time there is no quiet option. Vast wealth hides in 'benami' property — assets held in others' names to disguise the true, often corrupt, owner. A law to pierce these veils and seize illicit holdings would be transformative, and would expose fortunes held by the very powerful.",left:{id:"a",label:"Enact and enforce the benami law.",tooltip:"A fortune in a servant's name is a confession.",reveal:"You pass the law and begin piercing the false ownership. Illicit fortunes are exposed and some seized, and the powerful who hid behind nominees are suddenly, dangerously visible.",effects:{GL:5,EN:6,FI:3,FA:-13}},right:{id:"b",label:"Leave benami holdings undisturbed.",tooltip:"Too many of those names lead back to my own.",reveal:"You let the benami fortunes lie. The powerful keep their disguised wealth, the loophole stays wide open, and the corrupt accumulation of decades goes quietly unchallenged.",effects:{FA:5,FI:-3,EN:-10,GL:-6}}},{id:"finance-0251",location:"finance",arc:"finance-t1-a93",stage:0,speaker:"Customs Commissioner",portrait:"shadow",tags:["gold","smuggling","policy"],prompt:"Time has not healed it — the conflict comes back armed. Tonnes of gold pass through the country's airports as smuggled transit, enriching syndicates with airport and police protection. The commissioner can legalise and tax gold imports to kill the smuggling's logic, or keep cracking down while the rackets thrive.",left:{id:"a",label:"Legalise and tax gold imports.",tooltip:"A trade taxed in daylight starves the smuggler.",reveal:"You open a legal, taxed gold-import channel. The smuggling syndicates lose their edge, the jewellers and the treasury gain, and a shadow trade is dragged into the light.",effects:{FI:5,GL:2,EN:2,FA:-3}},right:{id:"b",label:"Keep the ban and the crackdowns.",tooltip:"Legalising smuggling rewards the smuggler.",reveal:"You keep gold imports banned and chase the couriers. The headline seizures look tough, but the protected syndicates keep the bulk of the trade and the airport rackets stay golden.",effects:{MI:2,FI:-3,EN:-6}}},{id:"finance-0252",location:"finance",arc:"finance-t1-a94",stage:0,speaker:"Customs Commissioner",portrait:"shadow",tags:["vat-refund","drawback","fraud"],prompt:"Once again, and with the whole house holding its breath. Exporters claim duty drawbacks and VAT refunds on goods that were never made or shipped, draining the treasury through forged paperwork blessed by bribed officers. The commissioner can install a tracked, audited system, or leave the lucrative scam alone.",left:{id:"a",label:"Track and audit every refund claim.",tooltip:"A refund on a phantom export is theft with a stamp.",reveal:"You digitise and audit the refund system and the phantom claims collapse. Real exporters wait a little longer for genuine refunds, but a vast leak of public money is plugged.",effects:{FI:6,GL:2,FA:-6}},right:{id:"b",label:"Leave the refund system as it is.",tooltip:"A crackdown punishes the honest exporter too.",reveal:"You leave the refund pipeline loose. The genuine exporters get their money fast, and so do the fraudsters claiming on exports that never existed, bleeding the treasury all the while.",effects:{FI:-6,FA:2,EN:-6}}},{id:"finance-0253",location:"finance",arc:"finance-t1-a95",stage:0,speaker:"Customs Commissioner",portrait:"shadow",tags:["bonded-warehouse","duty","diversion"],prompt:"The matter resurfaces in a harder year, patience exhausted. Duty-free raw materials imported for export factories under the bonded-warehouse scheme are being diverted onto the local market, undercutting honest producers and dodging duty. The commissioner can audit the bonds hard, or protect the well-connected abusers.",left:{id:"a",label:"Audit the bonded warehouses hard.",tooltip:"A duty-free import sold at home is smuggling by license.",reveal:"You audit the bonds and catch the diverters. Honest producers stop being undercut and the duty is recovered, and the connected abusers and their patrons turn on you.",effects:{FI:5,EN:3,FA:-6}},right:{id:"b",label:"Protect the connected abusers.",tooltip:"The men running those bonds run the party's accounts.",reveal:"You leave the bonded scam alone. The diverted goods keep flooding the local market duty-free, honest producers keep losing, and the racket's patrons stay loyal and rich.",effects:{FA:3,FI:-6,EN:-6}}},{id:"finance-0254",location:"finance",arc:"finance-t1-a96",stage:0,speaker:"Revenue Board Chairman",portrait:"official",tags:["inheritance-tax","wealth","dynasty"],prompt:"A later season of rule, the stakes now openly existential. Great fortunes pass untaxed from one generation to the next, entrenching a hereditary elite. An inheritance tax would raise revenue and loosen the dynastic grip on wealth — and fall hardest on the established families, your own circle among them.",left:{id:"a",label:"Introduce an inheritance tax.",tooltip:"A fortune unearned should not pass wholly untouched.",reveal:"You levy a tax on great inheritances. Revenue rises and dynastic wealth loosens at the edges, and the established families — yours included — recoil at the precedent.",effects:{FI:5,EN:5,FA:-13}},right:{id:"b",label:"Leave inheritances untaxed.",tooltip:"I will not be the one to tax my own children's legacy.",reveal:"You spare inheritances the tax. The hereditary elite keeps its fortunes intact across generations, and the chance to broaden revenue and loosen dynastic wealth passes by.",effects:{FA:5,FI:-6,EN:-6}}},{id:"finance-0255",location:"finance",arc:"finance-t1-a97",stage:0,speaker:"Insurance Regulator",portrait:"people",tags:["microinsurance","poverty","resilience"],prompt:"It comes around again, and the margin for error is gone. A single illness, death, or flood pushes poor families into destitution. A microinsurance push — tiny premiums, simple payouts, delivered through mobile money — would cushion them, but it needs subsidy and tight regulation to keep the insurers from cheating the poor.",left:{id:"a",label:"Drive a regulated microinsurance scheme.",tooltip:"A few taka of cover stands between a family and ruin.",reveal:"You build subsidised, well-regulated microinsurance. The cost and oversight are real, but a flood or a funeral stops meaning the loss of everything for millions of poor households.",effects:{EN:6,FI:-6,GL:2}},right:{id:"b",label:"Leave the poor to informal coping.",tooltip:"A whole insurance system for tiny premiums earns nothing.",reveal:"You leave the poor to their informal safety nets of debt and charity. The budget is spared, and the next flood or illness keeps sweeping families from the edge into destitution.",effects:{FI:2,EN:-10}}},{id:"finance-0256",location:"finance",arc:"finance-t1-a98",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["islamic-finance","sukuk","savings"],prompt:"The same demand, but the reign is older and the knives sharper. A large, pious pool of savings sits outside the banks because it shuns interest. A proper Islamic-finance framework and sovereign sukuk could mobilise that money for development — but it demands real Sharia governance, not a cosmetic relabelling that invites scandal.",left:{id:"a",label:"Build genuine Islamic finance and sukuk.",tooltip:"Faith-shy savings can still build roads.",reveal:"You establish credible Islamic-finance rules and issue sukuk. A vast pool of pious savings enters the formal economy and funds development, and the framework's integrity wins trust.",effects:{FI:5,EN:3,GL:2}},right:{id:"b",label:"Slap an Islamic label on conventional products.",tooltip:"The label is what the market wants; the substance is detail.",reveal:"You relabel conventional products as Islamic without real substance. The savings trickle in, but the scholars cry foul, a mis-selling scandal brews, and trust in the whole sector frays.",effects:{FI:2,EN:-6,GL:-3}}},{id:"finance-0257",location:"finance",arc:"finance-t1-a99",stage:0,speaker:"Banking Division Secretary",portrait:"official",tags:["deposit-insurance","savers","stability"],prompt:"Years deep, the unresolved returns to be resolved for good. Small savers have almost no protection if a bank fails, and rumours of trouble trigger panicked runs. A proper deposit-insurance scheme would protect savers and calm the system — funded by a levy the banks will resist, and a public backstop in a real crisis.",left:{id:"a",label:"Establish robust deposit insurance.",tooltip:"A saver who fears for his deposit starts a run.",reveal:"You build real deposit insurance funded by a bank levy. The banks grumble at the cost, but small savers gain protection and the system gains a shock absorber against panic.",effects:{FI:3,EN:5,GL:2,FA:-3}},right:{id:"b",label:"Leave savers to take their chances.",tooltip:"A levy on the banks is a cost passed to the customer.",reveal:"You decline the scheme to spare the banks the levy. The savers stay exposed, and the next rumour about a weak bank empties its counters before the truth can catch up.",effects:{FI:2,EN:-10}}},{id:"finance-0258",location:"finance",arc:"finance-t1-a100",stage:0,speaker:"Education Finance Secretary",portrait:"people",tags:["stipend","girls","education"],prompt:"The conflict reignites, and the world is watching this time. The school stipend that keeps poor children — especially girls — in class is too small and reaches too few. Expanding it would lift enrolment and delay child marriage, a proven investment, at a steep and permanent cost to the budget.",left:{id:"a",label:"Expand the school stipend widely.",tooltip:"A stipend that keeps a girl in school changes a generation.",reveal:"You widen and raise the stipend. Enrolment climbs, child marriages slip later, and the budget takes a heavy permanent load for a payoff measured in decades.",effects:{EN:8,GL:3,FI:-13}},right:{id:"b",label:"Keep the stipend small and targeted.",tooltip:"A generous stipend is a budget line forever.",reveal:"You keep the stipend lean. The budget is protected, but the poorest children — and the girls most at risk of early marriage — keep dropping out for want of a few taka.",effects:{FI:3,EN:-6}}},{id:"finance-0259",location:"finance",arc:"finance-t1-a101",stage:0,speaker:"Women's Affairs Finance Officer",portrait:"people",tags:["maternity","allowance","poverty"],prompt:"A familiar crisis, escalated by everything you let slide. Poor pregnant and nursing women work to the day they give birth and back, harming mother and child for want of any support. A national maternity allowance would change that — a costly, permanent commitment the finance hawks call unaffordable.",left:{id:"a",label:"Fund a national maternity allowance.",tooltip:"A nation that will not support its mothers stunts its future.",reveal:"You establish the maternity allowance. Mothers rest and nurse, infant health improves, and the budget carries a new permanent burden for a quietly transformative return.",effects:{EN:8,GL:3,FI:-10}},right:{id:"b",label:"Leave maternity support to charity.",tooltip:"A new allowance is a promise the budget cannot keep.",reveal:"You decline the allowance. The treasury is spared, and poor mothers keep labouring to the last day and back, the cost paid in their health and their children's.",effects:{FI:3,EN:-10}}},{id:"finance-0260",location:"finance",arc:"finance-t1-a102",stage:0,speaker:"Education Finance Secretary",portrait:"fixer",tags:["textbooks","printing","graft"],prompt:"The fault line cracks wider; the decision can no longer wait. The annual free-textbook programme — hundreds of millions of books to every child — is a logistical marvel riddled with printing-contract graft and quality-skimping. The secretary can clean up the tenders, angering a cartel of party-linked printers, or keep the books flowing on the cheap and corrupt status quo.",left:{id:"a",label:"Clean up the textbook tenders.",tooltip:"A child's book should not be a printer's bribe.",reveal:"You open the tenders and enforce quality. The party-linked printing cartel rages and threatens delays, but the books arrive better and the graft shrinks.",effects:{EN:5,FI:2,GL:2,FA:-6}},right:{id:"b",label:"Keep the printing cartel happy.",tooltip:"The books arrive on time; do not break the machine.",reveal:"You leave the cosy contracts intact. The books arrive on schedule, flimsy and over-priced, and the printers' cartel stays a reliable, grateful funder of the party.",effects:{FA:3,FI:-3,EN:-6}}},{id:"finance-0261",location:"finance",arc:"finance-t1-a103",stage:0,speaker:"Revenue Board Chairman",portrait:"official",tags:["tax-net","informal","compliance"],prompt:"Late in the reign, the old question demands a heavier answer. Only a tiny fraction of citizens file taxes, and the chairman wants a drive to pull the vast informal middle — small traders, professionals, landlords — into the net. It would broaden revenue fairly, and it would knock on a million doors that have never paid and will resent it.",left:{id:"a",label:"Drive a broad tax-net expansion.",tooltip:"A nation where few pay is a nation few can fund.",reveal:"You launch the registration and enforcement drive. Revenue broadens onto those long outside the net, the new taxpayers grumble loudly, and the salaried at last get some company in paying.",effects:{FI:6,EN:3,FA:-6}},right:{id:"b",label:"Leave the informal economy untaxed.",tooltip:"A million new tax notices is a million new enemies.",reveal:"You hold off on the expansion. The informal middle keeps its untaxed cash, the revenue base stays narrow, and the few who do pay keep carrying the many who do not.",effects:{FA:2,FI:-6}}},{id:"finance-0262",location:"finance",arc:"finance-t1-a104",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["currency","redenomination","confidence"],prompt:"It returns once more — and this round may be the one remembered. Years of inflation have left the currency cluttered with zeros, and a vanity proposal would lop several off to 'restore dignity' to the taka. The governor warns it is costly, disruptive, and purely cosmetic — fixing none of the inflation that caused the zeros.",left:{id:"a",label:"Redenominate the currency.",tooltip:"A proud currency wears fewer zeros.",reveal:"You lop the zeros off the taka in a grand relaunch. The notes look tidier and the optics flatter, and the costly, disruptive exercise changes nothing about the inflation that bloated them.",effects:{FI:-6,GL:2,EN:-3}},right:{id:"b",label:"Reject the cosmetic redenomination.",tooltip:"Zeros are a symptom; cutting them cures nothing.",reveal:"You spike the vanity project. There is no relaunch fanfare, but the money and disruption are saved, and you focus on the inflation that actually matters.",effects:{FI:3,GL:-3}}},{id:"finance-0263",location:"finance",arc:"finance-t1-a105",stage:0,speaker:"Financial Inclusion Director",portrait:"people",tags:["agent-banking","rural","inclusion"],prompt:"The reckoning circles back, grown teeth in the waiting. Agent banking — local shopkeepers acting as bank outlets — could bring real banking to villages that have never seen a branch. The director wants an aggressive rollout; the banks fear the fraud risk and the cannibalisation of their branch business.",left:{id:"a",label:"Push aggressive agent-banking rollout.",tooltip:"A bank counter in every bazaar banks the nation.",reveal:"You drive agent banking deep into the villages. The unbanked gain savings, credit, and payments for the first time, and the banks' fraud fears prove manageable against the reach gained.",effects:{EN:6,FI:3,GL:2}},right:{id:"b",label:"Let the banks set the pace.",tooltip:"A reckless rollout invites a fraud scandal.",reveal:"You leave the pace to the cautious banks. The fraud risk stays low, and so does the reach, and the villages keep waiting for a banking system that never quite arrives.",effects:{FI:2,EN:-6}}},{id:"finance-0264",location:"finance",arc:"finance-t1-a106",stage:0,speaker:"External Finance Secretary",portrait:"ambassador",tags:["world-bank","conditions","reform"],prompt:"Another term, the same antagonist, the stakes raised again. The World Bank offers cheap budget support tied to governance reforms — procurement transparency, SOE discipline, subsidy reform. The secretary says the money is cheap and the reforms are sound; the catch is foreign conditions on domestic policy and the donors they annoy.",left:{id:"a",label:"Take the support and the reforms.",tooltip:"Cheap money and good medicine in one dose.",reveal:"You accept the budget support and enact the reforms. The cheap money helps and the governance genuinely improves, and the nationalists grumble about foreign hands on the tiller.",effects:{FI:5,GL:3,EN:2,FA:-3}},right:{id:"b",label:"Refuse the conditional support.",tooltip:"I will not let a foreign bank write my budget.",reveal:"You turn down the conditional money on principle. You keep full policy control, but you forgo cheap finance and the reforms that, conditions aside, the country actually needed.",effects:{FA:2,FI:-10,GL:-3}}},{id:"finance-0265",location:"finance",arc:"finance-t1-a107",stage:0,speaker:"Labour Finance Inspector",portrait:"people",tags:["wage-theft","workers","enforcement"],prompt:"The matter, long deferred, lands with the force of a verdict. Across the informal economy and even the factories, employers routinely withhold wages, overtime, and legal dues with near-total impunity. The inspector wants a real enforcement unit with teeth; the employers, many of them donors, call it harassment.",left:{id:"a",label:"Build a wage-enforcement unit with teeth.",tooltip:"A wage withheld is a wage stolen.",reveal:"You stand up a unit that actually recovers stolen wages and fines the thieves. Workers start getting their due, the donor-employers cry harassment, and a quiet everyday injustice meets a check.",effects:{EN:6,GL:2,FI:-3,FA:-6}},right:{id:"b",label:"Leave wage disputes to the workers.",tooltip:"An employer hounded for back-pay closes the gate.",reveal:"You decline to build the unit. The employers keep their impunity, and the workers keep chasing wages already earned and rarely paid in full.",effects:{FA:3,FI:2,EN:-10}}},{id:"finance-0266",location:"finance",arc:"finance-t1-a108",stage:0,speaker:"Budget Secretary",portrait:"fixer",tags:["recapitalisation","banks","bailout"],prompt:"Years on and unhealed, the conflict returns to claim its answer. The state banks, looted into insolvency, need recapitalising again from the budget — public money poured into holes dug by the very managers and defaulters who looted them, with no reform attached. The secretary asks whether to pay up or attach hard conditions.",left:{id:"a",label:"Recapitalise with no strings.",tooltip:"A failed state bank cannot simply be allowed to die.",reveal:"You pour public money into the looted banks again, no questions asked. They limp on, the loopers and defaulters who emptied them face nothing, and the cycle is set to repeat.",effects:{FI:-6,FA:3,EN:-10,GL:-6}},right:{id:"b",label:"Attach hard reform conditions.",tooltip:"I will not refill a bucket no one will fix.",reveal:"You make the bailout conditional on board purges, recoveries, and reform. The looters and their patrons fight it bitterly, but the public money goes in with at least a chance of staying.",effects:{GL:3,EN:3,FI:-6,FA:-10}}},{id:"finance-0267",location:"finance",arc:"finance-t1-a109",stage:0,speaker:"Revenue Board Chairman",portrait:"people",tags:["small-business","turnover-tax","simplicity"],prompt:"The same fault line, the harder hour, the narrower path. Small businesses are crushed by complex tax paperwork and the bribes that come with assessment. A simple flat turnover tax would ease their burden and pull them into the system — at the cost of some revenue from those who would have paid more honestly.",left:{id:"a",label:"Introduce the simple turnover tax.",tooltip:"A tax a shopkeeper can compute is a tax a shopkeeper pays.",reveal:"You bring in a flat, simple turnover tax for small firms. Compliance jumps as the paperwork and the bribes fall away, and the system gains millions of small, honest taxpayers.",effects:{FI:3,EN:5,FA:-3}},right:{id:"b",label:"Keep the existing complex assessment.",tooltip:"A flat tax leaves money on the table from the bigger fish.",reveal:"You keep the complex regime. The treasury squeezes more from the few who comply, and the rest stay outside, paying the assessor a bribe instead of the state a tax.",effects:{FI:2,EN:-6}}},{id:"finance-0268",location:"finance",arc:"finance-t1-a110",stage:0,speaker:"Central Bank Governor",portrait:"fixer",tags:["directed-lending","credit","distortion"],prompt:"It comes back sharpened by every season you survived. The ministry wants the central bank to order the banks to pump cheap, directed credit into politically favoured sectors and firms. The governor warns it distorts the market and breeds bad loans; the politics says the favoured firms are friends who must be fed.",left:{id:"a",label:"Order the directed lending.",tooltip:"Credit steered to friends is friendship repaid.",reveal:"You direct the cheap credit to the favoured firms. They prosper on subsidised loans, the market distorts, and a fresh crop of politically-blessed bad loans begins to sprout.",effects:{FI:2,FA:3,EN:-6,GL:-6}},right:{id:"b",label:"Let credit follow the market.",tooltip:"Lending by favour is the seed of every banking crisis.",reveal:"You refuse to direct the credit. The favoured firms grumble at being denied their subsidy, but the banks lend on merit and the next wave of bad loans is not sown by decree.",effects:{GL:3,FI:2,EN:2,FA:-6}}},{id:"finance-0269",location:"finance",arc:"finance-t1-a111",stage:0,speaker:"Central Bank Governor",portrait:"official",tags:["interest-rate","inflation","growth"],prompt:"A later year of power, the old crisis now a true test of it. Inflation is biting hard, and the textbook answer is to raise interest rates and choke it — at the cost of slowing growth, raising borrowing costs, and angering the business lobby and the public both. The governor asks whether to tighten or to keep money cheap.",left:{id:"a",label:"Raise rates to crush inflation.",tooltip:"Unchecked inflation robs every wage and saving.",reveal:"You tighten hard and inflation begins, slowly, to ease. Borrowing costs jump, growth cools, the business lobby howls, and the painful medicine works as medicine does.",effects:{FI:3,GL:3,EN:-10}},right:{id:"b",label:"Keep money cheap to protect growth.",tooltip:"A choked economy is a poorer one for everyone.",reveal:"You keep rates low to protect growth and jobs. The business lobby is pleased and the expansion continues, and inflation keeps gnawing at every wage and every saving in the country.",effects:{EN:2,FI:-6,GL:-3}}},{id:"finance-0270",location:"finance",arc:"finance-t1-a112",stage:0,speaker:"Investment Authority Chief",portrait:"ambassador",tags:["fdi","screening","sovereignty"],prompt:"The unresolved returns, and this time it will not be deferred. Foreign capital wants to buy into ports, telecoms, and banks — strategic sectors. A screening regime would protect national security and prevent a single foreign power buying influence; an open-door policy would maximise the investment you desperately need.",left:{id:"a",label:"Screen FDI in strategic sectors.",tooltip:"Some assets must not be owned from abroad.",reveal:"You set up a screening regime for strategic sectors. Some investment is deterred and the open-economy purists complain, but no single foreign power buys a chokehold on your ports or banks.",effects:{GL:2,MI:3,FI:-6}},right:{id:"b",label:"Keep an open door for all FDI.",tooltip:"Capital is capital; the country needs it.",reveal:"You keep the door wide open. The investment flows in handsomely, and with it a foreign power's quiet acquisition of stakes in the infrastructure your security depends on.",effects:{FI:5,GL:2,MI:-6}}},{id:"finance-0271",location:"finance",arc:"finance-t1-a113",stage:0,speaker:"Land Reform Commissioner",portrait:"people",tags:["land-records","digitisation","corruption"],prompt:"A term later, the same fault line tears open again. Land records are a chaos of forgeries and bribes, the single biggest source of litigation and graft in the country. Digitising them would end a century of fraud and dispossession — and gut a vast, lucrative ecosystem of clerks, touts, and forgers tied to local power.",left:{id:"a",label:"Digitise the land records.",tooltip:"A clear title is the poor man's strongest shield.",reveal:"You drive the digitisation through against fierce resistance. The forgers and touts lose their racket, land litigation eases, and the poor gain titles that can finally be defended.",effects:{EN:6,GL:3,FI:2,FA:-6}},right:{id:"b",label:"Leave the paper land records be.",tooltip:"Untangling a century of forgery is a war I cannot win.",reveal:"You leave the land-records chaos intact. The clerks and touts keep their lucrative fraud, the courts stay clogged with land disputes, and the powerful keep dispossessing the weak by forged deed.",effects:{FA:3,FI:-3,EN:-10}}},{id:"finance-0272",location:"finance",arc:"finance-t1-a114",stage:0,speaker:"Ports Finance Director",portrait:"official",tags:["port","efficiency","trade"],prompt:"Years into your rule, the matter you thought buried resurfaces — harder. The main port's chronic congestion costs the economy billions in demurrage and delay, but fixing it means automating operations and breaking the entrenched labour and handling syndicates that profit from the chaos. The director asks whether to take them on.",left:{id:"a",label:"Modernise the port, break the syndicates.",tooltip:"A clogged port is a tax on every import and export.",reveal:"You automate the port and break the handling syndicates. The demurrage bill plummets and trade speeds up, and the displaced syndicate bosses and their political patrons declare war.",effects:{FI:5,GL:3,EN:2,FA:-6}},right:{id:"b",label:"Leave the port and its syndicates be.",tooltip:"A port shutdown over reform would cripple the economy.",reveal:"You avoid the fight with the port syndicates. The congestion and demurrage grind on as a permanent drag, and the economy quietly pays the syndicates' toll on every container.",effects:{FA:2,FI:-6,GL:-3}}},{id:"finance-0273",location:"finance",arc:"finance-t1-a115",stage:0,speaker:"Digital Finance Adviser",portrait:"people",tags:["digital-payments","cash","transparency"],prompt:"A new season of power, an old problem with sharper teeth. The economy runs on untraceable cash, fuelling tax evasion and graft. A hard push toward digital payments — incentives, merchant mandates, interoperability — would widen the tax net and cut corruption, but it sidelines the cash-poor and the elderly and threatens the informal traders.",left:{id:"a",label:"Drive the shift to digital payments.",tooltip:"Cash in the dark is where taxes go to die.",reveal:"You push hard for digital payments and the tax net widens as cash retreats. Corruption gets harder to hide, and the cash-poor and elderly struggle, needing support to keep up.",effects:{FI:5,EN:2,GL:2}},right:{id:"b",label:"Let cash and digital coexist gently.",tooltip:"A nation forced cashless overnight abandons its poorest.",reveal:"You let the transition come gradually. No one is left stranded by a sudden cashless push, but the untraceable cash economy keeps shielding the evaders and the grafters.",effects:{EN:2,FI:-3}}},{id:"finance-0274",location:"finance",arc:"finance-t1-a116",stage:0,speaker:"Telecom Finance Director",portrait:"ambassador",tags:["spectrum","auction","revenue"],prompt:"The crisis returns, and this time the cabinet is watching. New mobile spectrum is up for auction. You can set a punishing reserve price to milk the operators for maximum one-time revenue, or price it to spur cheap, fast data and broad coverage that grows the digital economy for years.",left:{id:"a",label:"Maximise the auction revenue.",tooltip:"Spectrum is a one-time treasure; sell it dear.",reveal:"You squeeze the operators for a record auction haul. The treasury banks a windfall, and the operators, recouping it, keep data dear and coverage thin for years to come.",effects:{FI:6,EN:-6,RE:-3}},right:{id:"b",label:"Price spectrum for cheap, wide data.",tooltip:"Cheap data grows more than a one-time cheque.",reveal:"You price the spectrum to spur coverage and affordable data. The one-time haul is smaller, but cheap fast internet spreads, and the digital economy it feeds pays back for years.",effects:{EN:5,GL:2,FI:-6}}},{id:"finance-0275",location:"finance",arc:"finance-t1-a117",stage:0,speaker:"Aviation Finance Secretary",portrait:"fixer",tags:["airline","losses","soe"],prompt:"Once more the issue lands on your desk, the stakes higher than before. The national airline bleeds money on padded leasing deals, overstaffing, and graft, kept aloft for prestige and patronage. The secretary can force a painful restructuring or privatisation, or keep subsidising the flag in the sky.",left:{id:"a",label:"Restructure or privatise the airline.",tooltip:"A flag that flies on subsidy flies on borrowed time.",reveal:"You force the restructuring, cutting the padded leases and the overstaffing. The unions and the brokers who profited rage, but the airline stops being a bottomless drain on the treasury.",effects:{FI:6,GL:2,EN:-10,FA:-6}},right:{id:"b",label:"Keep subsidising the flag carrier.",tooltip:"A nation's airline is a nation's face.",reveal:"You keep the airline aloft on subsidy. The flag flies and the patronage flows, and the padded deals and graft keep the losses mounting flight after flight.",effects:{FA:3,FI:-10,EN:-3}}},{id:"finance-0276",location:"finance",arc:"finance-t1-a118",stage:0,speaker:"Fiscal Climate Adviser",portrait:"official",tags:["carbon-tax","climate","revenue"],prompt:"Another year survived, and the reckoning circles back. A modest carbon levy on fuels and heavy industry would raise revenue and nudge the economy greener, and play well with climate donors. It would also raise costs across the board and hit the industries and consumers already squeezed by inflation.",left:{id:"a",label:"Introduce the carbon levy.",tooltip:"The polluter should pay, and the treasury should collect.",reveal:"You bring in a carbon levy. Revenue rises, the economy nudges greener, and the climate donors approve, while industry and consumers feel one more cost in an already pinched year.",effects:{FI:3,EN:3,GL:3,RE:2}},right:{id:"b",label:"Hold off on the carbon tax.",tooltip:"A new fuel levy amid inflation is a riot ordered in advance.",reveal:"You shelve the carbon tax. Industry and consumers are spared another cost, and the revenue, the green nudge, and the donor goodwill all go uncollected.",effects:{FI:-3,EN:-3,GL:-3}}},{id:"finance-0277",location:"finance",arc:"finance-t1-a119",stage:0,speaker:"Revenue Board Chairman",portrait:"shadow",tags:["capital-gains","stock-market","elite"],prompt:"The ground has shifted; the same demand arrives with new menace. Large stock-market gains go almost entirely untaxed, a quiet gift to the wealthy and the manipulators. A capital-gains tax would be fair and raise real revenue — and the big investors and brokers, well-connected, warn it will crash the market in protest.",left:{id:"a",label:"Tax large capital gains.",tooltip:"A fortune made on the bourse should pay like any other.",reveal:"You tax the big market gains. Revenue rises and fairness with it, the small investor is spared, and the big players stage a noisy sell-off and lean on every connection they have.",effects:{FI:5,EN:3,FA:-6}},right:{id:"b",label:"Leave market gains untaxed.",tooltip:"A capital-gains tax could spook the whole bourse.",reveal:"You leave the gains untaxed to keep the market calm. The wealthy and the manipulators keep their tax-free windfalls, and the revenue and the fairness go uncollected.",effects:{FA:2,FI:-6,EN:-3}}},{id:"finance-0278",location:"finance",arc:"finance-t1-a120",stage:0,speaker:"External Finance Secretary",portrait:"ambassador",tags:["imf","transparency","data"],prompt:"History rhymes: the conflict reopens deeper than last time. The IMF's annual review will publish a candid assessment of the economy — the real reserves, the hidden debts, the bad loans. You can cooperate fully and let the unflattering truth out, or pressure for a softened report that protects the rosy official narrative.",left:{id:"a",label:"Cooperate fully with a candid review.",tooltip:"A diagnosis softened is a disease untreated.",reveal:"You let the IMF publish the unvarnished assessment. The numbers sting and the opposition feasts, but the lenders and markets reward the transparency, and the problems can finally be named.",effects:{GL:5,FI:-3,EN:-3}},right:{id:"b",label:"Pressure for a softened report.",tooltip:"An honest report is a headline against me.",reveal:"You lean on the mission for a gentler write-up. The official narrative survives intact, the markets are soothed by a number that is not quite real, and the IMF's quiet doubts deepen.",effects:{FI:2,GL:-10}}},{id:"finance-0279",location:"finance",arc:"finance-t1-a121",stage:0,speaker:"Industrial Safety Secretary",portrait:"people",tags:["garments","safety","factories"],prompt:"Mid-reign, the old wound is torn afresh. After a catastrophic factory collapse, a binding international safety accord requires costly retrofits — fire exits, structural fixes — that the buyers demand and the owners resist. The secretary asks whether to enforce the accord fully or help owners dodge it.",left:{id:"a",label:"Enforce the safety accord fully.",tooltip:"A factory that buries its workers is no asset.",reveal:"You enforce the retrofits hard, factory by factory. The owners howl at the cost and a few lines close, but the death-trap buildings are fixed and the buyers keep their orders.",effects:{EN:8,GL:5,FI:-6,FA:-6}},right:{id:"b",label:"Help owners dodge the costly retrofits.",tooltip:"Protect the owners who keep a million employed.",reveal:"You help the owners paper over the accord. The retrofits go undone, the lines stay cheap, and the next fire or collapse is already being built into a building no one fixed.",effects:{FI:3,FA:3,EN:-16,GL:-10}}},{id:"finance-0280",location:"finance",arc:"finance-t1-a122",stage:0,speaker:"Tariff Commission Chief",portrait:"official",tags:["machinery","duty","industry"],prompt:"The pressure you deferred has come due, larger now. Industrialists want all imported capital machinery to come in duty-free to spur investment and modernisation. It would genuinely help manufacturers re-tool — and it is also a famous loophole for importing finished goods disguised as 'machinery' to dodge duty entirely.",left:{id:"a",label:"Grant broad duty-free machinery imports.",tooltip:"Cheap machines build modern factories.",reveal:"You open the duty-free channel wide. Genuine manufacturers re-tool cheaply, and the disguised-import racket revives alongside, smuggling finished goods in under the machinery label.",effects:{FI:-3,EN:3,RE:2}},right:{id:"b",label:"Allow it narrowly with tight verification.",tooltip:"A loophole for machines becomes a loophole for everything.",reveal:"You permit duty-free machinery only with strict end-use verification. The honest manufacturers grumble at the paperwork, but the disguised-import loophole stays shut and the duty is protected.",effects:{FI:3,EN:2,FA:-3}}},{id:"finance-0281",location:"finance",arc:"finance-t1-a123",stage:0,speaker:"ICT Investment Director",portrait:"official",tags:["it","hi-tech-park","jobs"],prompt:"A later term, and the quarrel has hardened into a test. A flagship hi-tech park could anchor a software and electronics industry and tens of thousands of skilled jobs — if it gets real power, connectivity, and tenants. Too many such parks have become empty monuments. The director asks whether to commit fully or modestly.",left:{id:"a",label:"Commit fully to the hi-tech park.",tooltip:"The future's factories are made of code.",reveal:"You back the park with reliable power, fibre, and incentives, and court real anchor tenants. The cost is high and the bet uncertain, but a genuine tech cluster and its skilled jobs begin to form.",effects:{EN:5,FI:-10,GL:2,RE:2}},right:{id:"b",label:"Build it modestly and hope.",tooltip:"A grand park half-empty is a grand embarrassment.",reveal:"You build a modest version and hope tenants come. The cost is contained, but without serious infrastructure and incentives the park risks joining the country's collection of hollow monuments.",effects:{FI:-3,EN:2}}},{id:"finance-0282",location:"finance",arc:"finance-t1-a124",stage:0,speaker:"SME Finance Director",portrait:"people",tags:["women","entrepreneurs","credit"],prompt:"The country has changed, but this fault line has not — only worsened. Women entrepreneurs are almost entirely locked out of formal credit by collateral demands and bias. A dedicated, lightly-collateralised fund would unleash a wave of women-led small businesses — at higher default risk and the grumbling of bankers who call it charity.",left:{id:"a",label:"Launch the women-entrepreneur credit fund.",tooltip:"Half the talent locked out is half the economy lost.",reveal:"You build the dedicated fund. Default risk runs higher and the bankers grumble, but a wave of women-led businesses opens, and a vast pool of stifled enterprise finally finds capital.",effects:{EN:6,FI:-6,GL:2}},right:{id:"b",label:"Leave SME credit gender-blind.",tooltip:"Special funds breed special defaults.",reveal:"You keep credit 'neutral', which in practice means collateral-bound and male. The default risk stays low and the bankers content, and women entrepreneurs keep borrowing from family or not at all.",effects:{FI:2,EN:-6}}},{id:"finance-0283",location:"finance",arc:"finance-t1-a125",stage:0,speaker:"Planning Commission Member",portrait:"fixer",tags:["mp-fund","patronage","local"],prompt:"It returns, as these things do, with the patience gone. Each MP gets a large annual development fund to spend in their constituency — a patronage machine that builds loyalty and, often, the MP's own house and friends' contracts. The member asks whether to keep the fund or route the money through audited local government.",left:{id:"a",label:"Keep the MP development funds.",tooltip:"An MP without a chequebook is an MP without friends.",reveal:"You keep the funds flowing to the MPs. They build loyalty and the occasional genuine road, and skim and steer the rest to their own contractors and kin, audited by no one.",effects:{FA:5,MI:2,EN:-10,FI:-3}},right:{id:"b",label:"Route the money through local government.",tooltip:"Development should follow a plan, not a member's whim.",reveal:"You move the money to audited local councils. The MPs lose a treasured lever and seethe, but the development spreads by need and plan rather than by the member's favour.",effects:{EN:6,GL:3,FA:-10}}},{id:"finance-0284",location:"finance",arc:"finance-t1-a126",stage:0,speaker:"External Finance Secretary",portrait:"ambassador",tags:["rating","markets","reform"],prompt:"Years on, the matter is no longer private; the press is already circling. The credit-rating agencies will downgrade the country unless you show real fiscal reform — but the reforms (subsidy cuts, tax rises) are politically toxic. A downgrade raises every future borrowing cost; ignoring it keeps the politics easy and the future dear.",left:{id:"a",label:"Reform to protect the rating.",tooltip:"A downgrade taxes every loan for a decade.",reveal:"You enact the painful reforms and stave off the downgrade. The public feels the squeeze and grumbles, but the rating holds and the country's future borrowing stays affordable.",effects:{GL:3,FI:3,EN:-13}},right:{id:"b",label:"Ignore the agencies, keep the politics easy.",tooltip:"I will not cut subsidies to please a foreign rating.",reveal:"You spare the public the reforms and take the downgrade. The politics stay calm now, and every loan the country raises henceforth carries a higher price for the rating you let slip.",effects:{EN:3,FI:-10,GL:-6}}},{id:"finance-0285",location:"finance",arc:"finance-t1-a127",stage:0,speaker:"Budget Secretary",portrait:"fixer",tags:["allowance","veterans","spending"],prompt:"The same knot, retied tighter, lands before you once more. The freedom-fighter honour allowance is being expanded again, with the rolls swelling implausibly as the genuine veterans age and 'new' ones appear with forged certificates. The secretary can audit and clean the rolls, angering a sacred constituency, or keep paying all comers.",left:{id:"a",label:"Audit and clean the veteran rolls.",tooltip:"A forged certificate dishonours the real heroes.",reveal:"You audit the rolls and strip out the forgeries. The genuine veterans are honoured and the fraud purged, and the cleansing of a sacred list draws furious accusations of disrespect.",effects:{FI:3,GL:2,EN:2,FA:-6}},right:{id:"b",label:"Keep paying the swollen rolls.",tooltip:"I will not be the one to question a freedom-fighter's claim.",reveal:"You leave the rolls untouched. The genuine and the forged draw the honour allowance alike, the sacred constituency stays placated, and the fraud quietly bloats the budget line.",effects:{FA:5,FI:-6,EN:-3}}},{id:"finance-0286",location:"finance",arc:"finance-t1-a128",stage:0,speaker:"Transport Economy Adviser",portrait:"people",tags:["gig-economy","ride-share","workers"],prompt:"Another monsoon, another return of an argument you cannot end. Ride-share and delivery apps have created work for hundreds of thousands of young people — and stripped them of any protection, pay floor, or benefits. The adviser wants to regulate the platforms with minimum earnings and insurance; the apps and the cheap-fare public resist.",left:{id:"a",label:"Regulate the gig platforms.",tooltip:"A job with no floor is a trap with an app.",reveal:"You impose minimum earnings, insurance, and dispute rights on the platforms. Fares rise a little and the apps threaten to scale back, but a precarious workforce gains a measure of security.",effects:{EN:6,FI:-3,GL:2}},right:{id:"b",label:"Leave the gig economy unregulated.",tooltip:"Cheap rides and easy work are their own reward.",reveal:"You leave the platforms free. Fares stay low and the apps expand, and the young riders and drivers keep working without a floor, a benefit, or a safety net beneath them.",effects:{FI:2,EN:-10}}},{id:"finance-0287",location:"finance",arc:"finance-t1-a129",stage:0,speaker:"Commerce Envoy",portrait:"ambassador",tags:["fta","regional","trade"],prompt:"Deep into the reign, the issue demands a final-sounding answer. A regional free-trade agreement would open big neighbouring markets to your exports — and open your own market to a flood of their cheaper goods that could swamp domestic industry. The envoy asks whether to sign the deal or protect the home market.",left:{id:"a",label:"Sign the regional free-trade deal.",tooltip:"A market opened both ways favours the competitive.",reveal:"You sign the FTA and your exporters gain access to vast new markets. Some domestic industries, undercut by cheaper imports, buckle and shed jobs, and the adjustment is wrenching.",effects:{GL:5,FI:2,EN:-6}},right:{id:"b",label:"Protect the home market.",tooltip:"Free trade with a giant is a flood with a treaty.",reveal:"You decline the deal to shield domestic industry. The home producers are protected and the jobs held, but your exporters lose the access, and the integration the region is moving toward leaves you behind.",effects:{EN:2,FI:-3,GL:-6}}},{id:"finance-0288",location:"finance",arc:"finance-t1-a130",stage:0,speaker:"Revenue Board Chairman",portrait:"people",tags:["stamp-duty","property","informality"],prompt:"The reckoning you postponed has matured into a crisis. Property-transfer stamp duty is so high that almost everyone under-declares the sale price, fuelling black money and starving the treasury. Cutting the rate would boost honest declarations and the property market; the hawks fear the short-term revenue dip.",left:{id:"a",label:"Cut the stamp duty to boost compliance.",tooltip:"A rate too high is a rate evaded.",reveal:"You slash the stamp duty. Declarations jump toward honesty, the property market quickens, and after a brief dip the revenue actually rises as the under-declaration racket collapses.",effects:{FI:3,EN:3,GL:2}},right:{id:"b",label:"Keep the high stamp duty.",tooltip:"A rate cut is a revenue cut I cannot risk now.",reveal:"You keep the duty high. The headline rate looks lucrative, and the universal under-declaration keeps fuelling black money while the treasury collects on fictional sale prices.",effects:{FI:-3,EN:-3}}},{id:"finance-0289",location:"finance",arc:"finance-t1-a131",stage:0,speaker:"Industries Secretary",portrait:"people",tags:["sme","manufacturing","cluster"],prompt:"A new chapter, the same antagonists, less room to manoeuvre. A gritty cluster of small workshops makes the spare parts and machines that keep industry and agriculture running — undercapitalised, unregulated, and ignored. A support push of credit, training, and standards could turn it into a real manufacturing base, or you can keep chasing flashier prizes.",left:{id:"a",label:"Invest in the light-engineering cluster.",tooltip:"A nation that makes its own parts depends on no one's.",reveal:"You back the workshops with credit, training, and standards. The transformation is slow and unglamorous, but an import-substituting manufacturing base — and skilled jobs — takes root.",effects:{EN:5,FI:-6,RE:2}},right:{id:"b",label:"Chase the flashier industrial prizes.",tooltip:"Workshops do not make headlines.",reveal:"You steer support to glossier projects instead. The flagship announcements dazzle, and the unsung workshops that actually keep industry running stay starved and stuck.",effects:{GL:2,FI:-3,EN:-3}}},{id:"finance-0290",location:"finance",arc:"finance-t1-a132",stage:0,speaker:"External Finance Secretary",portrait:"ambassador",tags:["adb","loan","megaproject"],prompt:"The old fault line widens; this time there is no quiet option. A development bank offers a large soft loan for a flagship transport corridor — cheaper than markets, but with rigorous procurement and environmental conditions that will slow the build and block the cost-padding your contractors expect.",left:{id:"a",label:"Take the loan with all its conditions.",tooltip:"Cheap money and clean procurement together.",reveal:"You take the soft loan and accept the rigorous conditions. The build is slower and the contractors are denied their padding, but the corridor is cheaply financed and honestly built.",effects:{FI:3,GL:3,EN:2,FA:-6}},right:{id:"b",label:"Fund it your own way, conditions-free.",tooltip:"I will not let a bank's auditors run my project.",reveal:"You skip the conditional loan and finance it domestically. The contractors get their padding and the speed they want, and the project costs more, runs dirtier, and strains the budget.",effects:{FA:3,FI:-10,EN:-3}}},{id:"finance-0291",location:"finance",arc:"finance-t1-a133",stage:0,speaker:"Central Bank Governor",portrait:"shadow",tags:["currency","high-note","black-money"],prompt:"Time has not healed it — the conflict comes back armed. Introducing a new high-denomination note would ease the bulk of large cash transactions — convenient, and a famous enabler of hoarding, bribery, and black money. The governor asks whether to print it or hold the line on the largest note.",left:{id:"a",label:"Introduce the high-denomination note.",tooltip:"A bigger note is a smaller suitcase.",reveal:"You print the big note. Large cash deals get easier for everyone, including the hoarders, bribers, and launderers who can now move fortunes in a slim envelope.",effects:{FI:2,EN:-6,GL:-3}},right:{id:"b",label:"Hold the line on the largest note.",tooltip:"A big note is a bribe's best friend.",reveal:"You refuse the high-denomination note. Large cash deals stay bulky and a little harder to hide, a small friction against the corruption that thrives on portable wealth.",effects:{GL:2,EN:2}}},{id:"finance-0292",location:"finance",arc:"finance-t1-a134",stage:0,speaker:"Urban Economy Officer",portrait:"people",tags:["vendors","informal","licensing"],prompt:"Once again, and with the whole house holding its breath. The cities run on hundreds of thousands of street vendors who block footpaths, pay daily bribes to police and mastans, and have no legal standing. The officer can formalise them with licences and designated zones, or keep clearing them in periodic, futile drives.",left:{id:"a",label:"Formalise and license the vendors.",tooltip:"A hawker licensed is a hawker freed from the mastan.",reveal:"You license the vendors and assign them zones. The police and mastans lose their daily extortion and resent it, but the vendors gain legal standing and the footpaths get some order.",effects:{EN:6,FI:2,MI:-3,FA:-3}},right:{id:"b",label:"Keep clearing them in periodic drives.",tooltip:"The footpaths belong to the pedestrian.",reveal:"You keep mounting eviction drives that scatter the vendors for a day before they return. The bribes keep flowing to police and mastans, and nothing actually changes but the optics.",effects:{MI:2,FI:-3,EN:-10}}},{id:"finance-0293",location:"finance",arc:"finance-t1-a135",stage:0,speaker:"Railway Finance Secretary",portrait:"people",tags:["railway","losses","subsidy"],prompt:"The matter resurfaces in a harder year, patience exhausted. The state railway loses money on every ticket — cheap fares, overstaffing, ticketless travel, and graft — yet it is the lifeline of the poor. The secretary can hike fares and cut staff to stem the losses, or keep the cheap, bleeding service running.",left:{id:"a",label:"Reform fares and staffing.",tooltip:"A railway that bankrupts itself serves no one long.",reveal:"You raise fares, curb the ticketless, and trim the bloat. The losses narrow and the service steadies, but the poor who depend on cheap travel feel the pinch and the unions strike.",effects:{FI:5,EN:-10,FA:-3}},right:{id:"b",label:"Keep the cheap service bleeding.",tooltip:"The train is the poor man's only affordable distance.",reveal:"You keep fares low and the trains rolling at a loss. The poor keep their cheap lifeline, and the railway keeps draining the budget, its graft and overstaffing untouched.",effects:{EN:5,FI:-10}}},{id:"finance-0294",location:"finance",arc:"finance-t1-a136",stage:0,speaker:"Industries Secretary",portrait:"doctor",tags:["pharma","api","self-reliance"],prompt:"A later season of rule, the stakes now openly existential. The proud pharmaceutical industry imports nearly all its active ingredients, leaving it hostage to foreign supply. A dedicated API park would build self-reliance and a high-value export edge — a costly, slow industrial bet versus simply importing as before.",left:{id:"a",label:"Build the pharmaceutical API park.",tooltip:"An industry that imports its core imports its fate.",reveal:"You commit to the API park. The investment is heavy and the payoff years away, but the pharma industry begins to make its own ingredients and an export edge sharpens.",effects:{FI:-6,EN:3,GL:2,RE:2}},right:{id:"b",label:"Keep importing the active ingredients.",tooltip:"Why build what I can buy?",reveal:"You keep relying on imported ingredients. The capital is saved, and the industry stays one foreign supply-shock away from a shortage of the medicines the country and its exports depend on.",effects:{FI:2,EN:-3,GL:-3}}},{id:"finance-0295",location:"finance",arc:"finance-t1-a137",stage:0,speaker:"Revenue Board Chairman",portrait:"people",tags:["sim-tax","internet","access"],prompt:"It comes around again, and the margin for error is gone. Taxes on SIM cards, handsets, and data are an easy, lucrative revenue stream — and a regressive tax on the very connectivity that drives the digital economy and reaches the rural poor. The chairman asks whether to raise these taxes or cut them.",left:{id:"a",label:"Raise the SIM and data taxes.",tooltip:"A connected nation can spare a few taka per gigabyte.",reveal:"You raise the connectivity taxes and the revenue flows easily. Data and phones get dearer, the rural poor and the digital economy both feel it, and a regressive levy deepens.",effects:{FI:5,EN:-10}},right:{id:"b",label:"Cut the regressive connectivity taxes.",tooltip:"A tax on data is a tax on the future.",reveal:"You cut the SIM and data taxes. The easy revenue is forgone, but cheaper connectivity spreads to the rural poor and feeds the digital economy that pays back many times over.",effects:{EN:5,GL:2,FI:-6}}},{id:"finance-0296",location:"finance",arc:"finance-t1-a138",stage:0,speaker:"Cottage Industry Director",portrait:"people",tags:["handloom","heritage","artisans"],prompt:"The same demand, but the reign is older and the knives sharper. The famed handloom weavers and artisans — keepers of a heritage craft — are being wiped out by cheap power-loom imitations and debt. A revival of credit, design support, and a protected 'heritage' label could save them, or you can let the market take its course.",left:{id:"a",label:"Fund the handloom revival.",tooltip:"A craft lost is a heritage no money rebuilds.",reveal:"You back the weavers with credit, design, and a protected heritage label. The cost is modest and the market still hard, but a dying craft and the communities who keep it get a fighting chance.",effects:{EN:5,GL:2,FI:-6}},right:{id:"b",label:"Let the market take its course.",tooltip:"Nostalgia cannot outcompete a power loom.",reveal:"You let the handloom communities fend for themselves. The cheaper power-loom goods win, the looms fall silent one village at a time, and a centuries-old craft fades toward memory.",effects:{FI:2,EN:-6}}},{id:"finance-0297",location:"finance",arc:"finance-t1-a139",stage:0,speaker:"Export Zone Authority Chief",portrait:"people",tags:["epz","wages","investment"],prompt:"Years deep, the unresolved returns to be resolved for good. The export-processing zones, your showcase for foreign investors, run on a wage floor lower than the national minimum and a ban on unions. Raising the EPZ wage and allowing unions would be just — and might spook the investors the zones were built to attract.",left:{id:"a",label:"Raise EPZ wages and allow unions.",tooltip:"A showcase built on suppressed wages shames the show.",reveal:"You lift the EPZ wage and permit unions. Some investors grumble and threaten to look elsewhere, but the zone workers gain dignity and pay, and the showcase stops being a sweatshop with landscaping.",effects:{EN:6,GL:3,FI:-6,FA:-3}},right:{id:"b",label:"Keep the EPZ wages low and unions banned.",tooltip:"The investors came for the cheap, calm labour.",reveal:"You keep the zones cheap and union-free. The investors stay content and the FDI flows, and the zone workers keep earning below the national floor with no voice to change it.",effects:{FI:5,FA:2,EN:-13,GL:-3}}},{id:"finance-0298",location:"finance",arc:"finance-t1-a140",stage:0,speaker:"Revenue Board Chairman",portrait:"people",tags:["advance-tax","compliance","burden"],prompt:"The conflict reignites, and the world is watching this time. The web of advance and source taxes deducted on imports, utilities, and transactions has become a hidden, regressive burden — easy to collect, but falling on businesses and consumers regardless of actual profit, and impossible for the small to reclaim. The chairman asks whether to rationalise it.",left:{id:"a",label:"Rationalise the advance-tax web.",tooltip:"A tax collected before profit is a tax on existence.",reveal:"You prune the tangle of advance taxes. Collection gets a little harder and revenue dips short-term, but the hidden burden on the small and the consumer eases and the system grows fairer.",effects:{EN:5,GL:2,FI:-6}},right:{id:"b",label:"Keep the easy advance-tax collection.",tooltip:"A tax collected at source is a tax that does not escape.",reveal:"You keep the advance-tax web intact. Collection stays easy and leak-proof, and the hidden, regressive burden goes on falling hardest on those least able to reclaim it.",effects:{FI:3,EN:-6}}},{id:"finance-0299",location:"finance",arc:"finance-t1-a141",stage:0,speaker:"Budget Secretary",portrait:"fixer",tags:["budget","deficit","populism"],prompt:"A familiar crisis, escalated by everything you let slide. Election year, and the cabinet wants the largest budget in history — a blizzard of new schemes, subsidies, and giveaways — funded by optimistic revenue forecasts and borrowing. The secretary warns the numbers do not add up; the politics says they do not have to.",left:{id:"a",label:"Unveil the record populist budget.",tooltip:"A budget is a promise, and promises win votes.",reveal:"You unveil the record-shattering budget to fanfare. The schemes dazzle and the votes warm, and the fantastical revenue forecasts collapse within months, forcing painful cuts you will own.",effects:{EN:5,FI:-13,GL:-6}},right:{id:"b",label:"Present a sober, credible budget.",tooltip:"A budget built on fantasy is a crisis with a launch date.",reveal:"You table a realistic budget the numbers actually support. The cabinet grumbles that it lacks fireworks for the campaign, but the lenders trust it and no mid-year reckoning lies in wait.",effects:{GL:5,FI:3,EN:-3}}},{id:"finance-0300",location:"finance",arc:"finance-t1-a141",stage:1,speaker:"Budget Secretary",portrait:"fixer",tags:["budget","deficit","populism"],prompt:"The fault line cracks wider; the decision can no longer wait. The budget is passed, and now the chronic gap between the grand announcements and the money actually disbursed yawns wide — schemes launched with fanfare sit unfunded and half-built. The secretary asks whether to chase headline announcements or quietly fund what was already promised.",left:{id:"a",label:"Announce yet more new schemes.",tooltip:"A ribbon cut is worth more than a road finished.",reveal:"You keep launching glittering new schemes over the unfinished ones. The headlines flow, the backlog of half-built promises grows, and the public learns that an announcement here rarely becomes a thing.",effects:{FA:2,EN:-10,FI:-3}},right:{id:"b",label:"Fund and finish what was promised.",tooltip:"A promise kept quietly beats ten announced loudly.",reveal:"You stop the announcement treadmill and fund the existing commitments to completion. There are fewer ribbons to cut, but the schools, roads, and clinics already promised actually get built.",effects:{EN:6,GL:2,FI:-6}}}];export{e as f};
